-- =========================================================================
-- GLOBAL DEBUG LOG FUNCTIONS (DYNAMIC PATHS - WORKS FOR ANY USER)
-- =========================================================================
-- Get script directory dynamically
local SCRIPT_DIR = debug.getinfo(1, "S").source:match("@(.*)[\\/]") or "."
local DEBUG_DIR = SCRIPT_DIR .. "/Carpie Diem/Debug"
local DEBUG_LOG_PATH = DEBUG_DIR .. "/DEBUG LOG.txt"

local function casino_debug_log(msg)
    local timestamp = os.date("%Y-%m-%d %H:%M:%S")
    local formatted = timestamp .. " [CASINO] " .. tostring(msg) .. "\n"
    pcall(function()
        local dir_cmd = 'if not exist "' .. DEBUG_DIR:gsub("/", "\\") .. '" mkdir "' .. DEBUG_DIR:gsub("/", "\\") .. '"'
        os.execute(dir_cmd)
    end)
    pcall(function()
        local f = io.open(DEBUG_LOG_PATH, "a")
        if f then f:write(formatted) f:flush() f:close() end
    end)
end

local function money_debug_log(msg)
    local timestamp = os.date("%Y-%m-%d %H:%M:%S")
    local formatted = timestamp .. " [MONEY] " .. tostring(msg) .. "\n"
    pcall(function()
        local dir_cmd = 'if not exist "' .. DEBUG_DIR:gsub("/", "\\") .. '" mkdir "' .. DEBUG_DIR:gsub("/", "\\") .. '"'
        os.execute(dir_cmd)
    end)
    pcall(function()
        local f = io.open(DEBUG_LOG_PATH, "a")
        if f then f:write(formatted) f:flush() f:close() end
    end)
end

