	 ["GET_PED_BONE_COORDS"] = function( ped,  boneId,  offsetX,  offsetY,  offsetZ)
		local result = invoker.call(0x17C07FC640E86B4E, ped, boneId, 1.0*offsetX, 1.0*offsetY, 1.0*offsetZ)
		-- Try multiple accessor patterns for Vector3 return type
		if result.vec3 then
			return result.vec3.x, result.vec3.y, result.vec3.z
		elseif result.scr_vec3 then
			return result.scr_vec3.x, result.scr_vec3.y, result.scr_vec3.z
		else
			-- Return nil to indicate failure (ESP code will detect and abort)
			return nil, nil, nil
		end
	 end, 
