function entities.networkise(entity)
    if not ENTITY.DOES_ENTITY_EXIST(entity) then return end
    if NETWORK.NETWORK_IS_SESSION_STARTED() then
        if not NETWORK.NETWORK_GET_ENTITY_IS_NETWORKED(entity) then
            NETWORK.NETWORK_REGISTER_ENTITY_AS_NETWORKED(entity)
            local start = util.get_tick_count()
            while not NETWORK.NETWORK_GET_ENTITY_IS_NETWORKED(entity) do
                if util.get_tick_count() - start > 1000 then break end
                util.yield()
            end
        end
        local netId = NETWORK.NETWORK_GET_NETWORK_ID_FROM_ENTITY(entity)
        if netId ~= 0 then
            NETWORK.SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES(netId, true)
            NETWORK.SET_NETWORK_ID_ALWAYS_EXISTS_FOR_PLAYER(netId, PLAYER.PLAYER_ID(), true)
            NETWORK.SET_NETWORK_ID_CAN_MIGRATE(netId, false)
        end
    end
end
function entities.create_ped(type, hash, pos, heading)
    if not request.model(hash) then return 0 end
    local ped = PED.CREATE_PED(type, hash, pos.x, pos.y, pos.z, heading, true, true)
    STREAMING.SET_MODEL_AS_NO_LONGER_NEEDED(hash)
    entities.networkise(ped)
    return ped
end
function entities.create_vehicle(hash, pos, heading)
    if not request.model(hash) then return 0 end
    local veh = VEHICLE.CREATE_VEHICLE(hash, pos.x, pos.y, pos.z, heading, true, true, false)
    STREAMING.SET_MODEL_AS_NO_LONGER_NEEDED(hash)
    entities.networkise(veh)
    return veh
end
function entities.create_object(hash, pos)
    if not request.model(hash) then return 0 end
    local obj = OBJECT.CREATE_OBJECT(hash, pos.x, pos.y, pos.z, true, true, false)
    STREAMING.SET_MODEL_AS_NO_LONGER_NEEDED(hash)
    entities.networkise(obj)
    return obj
end
function entities.delete(handle)
    if not handle or handle == 0 then return end
    if not ENTITY.DOES_ENTITY_EXIST(handle) then return end
    if NETWORK.NETWORK_IS_SESSION_STARTED() and NETWORK.NETWORK_GET_ENTITY_IS_NETWORKED(handle) then
        local netId = NETWORK.NETWORK_GET_NETWORK_ID_FROM_ENTITY(handle)
        if netId ~= 0 then
            NETWORK.SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES(netId, false)
            NETWORK.SET_NETWORK_ID_ALWAYS_EXISTS_FOR_PLAYER(netId, PLAYER.PLAYER_ID(), false)
            NETWORK.SET_NETWORK_ID_CAN_MIGRATE(netId, true)
        end
    end
    local attempts = 0
    while not NETWORK.NETWORK_HAS_CONTROL_OF_ENTITY(handle) and attempts < 10 do
        NETWORK.NETWORK_REQUEST_CONTROL_OF_ENTITY(handle)
        attempts = attempts + 1
        util.yield(0)
    end
    if ENTITY.IS_ENTITY_ATTACHED(handle) then
        ENTITY.DETACH_ENTITY(handle, true, true)
    end
    ENTITY.SET_ENTITY_AS_MISSION_ENTITY(handle, false, true)
    if pointer_int then
        local ptr = pointer_int()
        ptr.value = handle
        ENTITY.DELETE_ENTITY(ptr)
        ptr:free()
    else
        ENTITY.DELETE_ENTITY(handle)
    end
end
function entities.get_user_vehicle_as_handle()
    local ped = players.me().ped
    return PED.GET_VEHICLE_PED_IS_IN(ped, false)
end
local function spawn_squad(name, model_str, weapon_hash, count)
    util.create_job(function()
        local target = get_target()
        if not target then return end
        if not request.model(joaat(model_str)) then return end
        notify.push("Test", "Sending " .. name .. " squad...")
        for i = 1, count do
            local angle = (360 / count) * i
            local rad = math.rad(angle)
            local pos = {
                x = target.coords.x + (math.cos(rad) * 5.0),
                y = target.coords.y + (math.sin(rad) * 5.0),
                z = target.coords.z
            }
            local ped = entities.create_ped(28, hash, pos, 0.0)
            PED.SET_PED_DEFAULT_COMPONENT_VARIATION(ped)
            PED.SET_PED_COMBAT_ATTRIBUTES(ped, 46, true)
            PED.SET_PED_COMBAT_ATTRIBUTES(ped, 5, true)
            PED.SET_PED_FLEE_ATTRIBUTES(ped, 0, false)
            PED.SET_PED_COMBAT_ABILITY(ped, 2)
            if weapon_hash then
                WEAPON.GIVE_WEAPON_TO_PED(ped, weapon_hash, 999, false, true)
            end
            TASK.TASK_COMBAT_PED(ped, target.ped, 0, 16)
            util.yield(100)
        end
    end)
end
local function attach_to_vehicle_bone(target_veh, entity, bone_name, offset, rot)
    if not ENTITY.DOES_ENTITY_EXIST(target_veh) or not ENTITY.DOES_ENTITY_EXIST(entity) then return end
    local bone_idx = 0
    if bone_name then
        bone_idx = ENTITY.GET_ENTITY_BONE_INDEX_BY_NAME(target_veh, bone_name)
        if bone_idx == -1 then bone_idx = 0 end
    end
    NETWORK.NETWORK_REQUEST_CONTROL_OF_ENTITY(entity)
    ENTITY.ATTACH_ENTITY_TO_ENTITY(
        entity, target_veh, bone_idx,
        offset.x, offset.y, offset.z,
        rot.x, rot.y, rot.z,
        true, false, false, false, 2, true, 0
    )
end
local function apply_yeet_force_once(entity, target_pos, multiplier)
    if not ENTITY.DOES_ENTITY_EXIST(entity) then return end
    local ent_pos = get_coords(entity)
    local dist = ent_pos:distance3d(target_pos)
    if dist < 4.0 or dist > 100.0 then return end
    local dx = target_pos.x - ent_pos.x
    local dy = target_pos.y - ent_pos.y
    local dz = target_pos.z - ent_pos.z
    NETWORK.NETWORK_REQUEST_CONTROL_OF_ENTITY(entity)
    ENTITY.APPLY_FORCE_TO_ENTITY_CENTER_OF_MASS(entity, 1, dx * multiplier, dy * multiplier, dz * multiplier, true, false, true, true)
end

