        [0x4A] = "J", [0x4B] = "K", [0x4C] = "L", [0x5A] = "Z", [0x58] = "X", [0x43] = "C",
        [0x56] = "V", [0x42] = "B", [0x4E] = "N", [0x4D] = "M",
        [0x2D] = "INSERT", [0x2E] = "DELETE", [0x24] = "HOME", [0x23] = "END",
        [0x21] = "PAGE UP", [0x22] = "PAGE DOWN", [0x09] = "TAB", [0x14] = "CAPS LOCK",
        [0x20] = "SPACE", [0x0D] = "ENTER", [0x08] = "BACKSPACE", [0x1B] = "ESC",
        [0xBB] = "=", [0xBD] = "-", [0xDB] = "[", [0xDD] = "]",
        [0xBA] = ";", [0xDE] = "'", [0xBC] = ",", [0xBE] = ".", [0xBF] = "/", [0xDC] = "\\"
    }
}

