    -- =========================================================================
    -- NATIVES (Using Lexis invoker)
    -- Lexis natives use vec3() for coordinate parameters
    -- =========================================================================
    local N = {}

    -- Cache native functions
    local function init_natives()
        if invoker and invoker.call then
            -- Entity natives (Lexis uses vec3 for coordinates, not separate x,y,z)
            N.SET_ENTITY_COORDS_NO_OFFSET = function(entity, x, y, z, keepTasks, keepIK, doWarp)
                -- Native expects: EntityIndex, VecNewCoors (vec3), KeepTasks, KeepIK, DoWarp
                local coords = vec3(x, y, z)
                invoker.call(0x239a3351ac1da385, entity, coords, keepTasks or false, keepIK or false, doWarp or false)
            end
            
            -- Camera natives for spectating
            N.SET_GAMEPLAY_CAM_IGNORE_OBJECTS_UPDATE = function(toggle)
                invoker.call(0x0293FA0B18022CBD8, toggle)
            end
            N.SET_GAMEPLAY_CAM_RELATIVE_HEADING = function(toggle)
                invoker.call(0xFBE4D1B401B65B614, toggle)
            end
            N.FREEZE_ENTITY_POSITION = function(entity, toggle)
                invoker.call(0x428ca6dbd1094446, entity, toggle)
            end
            N.SET_ENTITY_HEALTH = function(entity, health, instigator)
                invoker.call(0x6b76dc1f3ae6e6a3, entity, health, instigator or 0)
            end
            N.APPLY_FORCE_TO_ENTITY = function(entity, forceType, x, y, z, offX, offY, offZ, boneIndex, isDirectionRel, ignoreUpVec, isForceRel, p12, p13)
                local force = vec3(x, y, z)
                local offset = vec3(offX, offY, offZ)
                invoker.call(0xc5f68be9613e2d18, entity, forceType, force, offset, boneIndex or 0, isDirectionRel, ignoreUpVec, isForceRel, p12, p13)
            end

            -- Network natives
            N.NETWORK_SET_IN_SPECTATOR_MODE = function(toggle, playerIndex)
                -- Native expects: InSpectatorMode (bool), playerIndex (integer - player ID, not ped)
                invoker.call(0x423de3854bb50894, toggle, playerIndex)
            end

            -- Fire natives (also uses vec3 for coordinates)
            N.ADD_EXPLOSION = function(x, y, z, explosionType, damageScale, isAudible, isInvisible, cameraShake, noDamage)
                -- Native expects: VecExplosionPos (vec3), ExplosionTag, SizeScale, bMakeSound, bNoFx, CamShakeMultiplier, NoDamage
                local pos = vec3(x, y, z)
                invoker.call(0xe3ad2bdbaee269ac, pos, explosionType, damageScale, isAudible, not isInvisible, cameraShake, noDamage)
            end
            N.START_SCRIPT_FIRE = function(x, y, z, maxChildren, isGasFire)
                local pos = vec3(x, y, z)
                local result = invoker.call(0x6b83617e04503888, pos, maxChildren, isGasFire)
                return result and result.int or 0
            end

            -- Weapon natives
            N.GIVE_WEAPON_TO_PED = function(ped, weaponHash, ammoCount, isHidden, bForceInHand)
                -- Native expects: PedIndex, TypeOfWeapon (hash), AmountOfAmmo, bForceIntoHand, bEquip
                invoker.call(0xbf0fd6e56c964fcb, ped, weaponHash, ammoCount, isHidden, bForceInHand)
            end
            N.REMOVE_ALL_PED_WEAPONS = function(ped)
                invoker.call(0xB282DC6EBD803C75, ped)
            end
            N.GET_HASH_KEY = function(str)
                local result = invoker.call(0xD24D37CC275948CC, str)
                return result and result.int or 0
            end
            
            -- Weapon natives
            N.GET_CURRENT_PED_WEAPON = function(ped)
                local result = invoker.call(0x0A6DB27619D9C6F46, ped)
                return result and result.int or 0
            end
            N.SET_PED_AMMO = function(ped, weaponHash, ammo)
                invoker.call(0x5E3FDBF74A97653D, ped, weaponHash, ammo)
            end
            N.DISABLE_WEAPON_RELOAD = function(ped, toggle)
                invoker.call(0x4D7B416BC2D0366B, ped, toggle)
            end
            N.SET_PLAYER_WEAPON_RECOIL_MULTIPLIER = function(player, multiplier)
                invoker.call(0x4A7B48FDE25E3700, player, multiplier)
            end
            N.SET_WEAPON_FIRING_RATE = function(ped, weaponHash, rate)
                invoker.call(0x5FC292984E0A2FBE, ped, weaponHash, rate)
            end
            N.SET_AMMO_IN_CLIP = function(ped, weaponHash, ammo)
                invoker.call(0x015A522136D7EB956, ped, weaponHash, ammo)
            end

            -- Ped natives
            N.SET_PED_ARMOUR = function(ped, amount)
                invoker.call(0xcea04d83135264cc, ped, amount)
            end

            -- Time/Weather natives
            N.SET_CLOCK_TIME = function(hour, minute, second)
                invoker.call(0x47C3B5848C3E45D8, hour, minute, second) -- SET_CLOCK_TIME
            end
            N.SET_TIME_SCALE = function(timeScale)
                invoker.call(0x1D408577D440E81E, timeScale) -- SET_TIME_SCALE
            end
            N.SET_WEATHER_TYPE_NOW_PERSIST = function(weatherType)
                invoker.call(0xED712CA327900C8A, weatherType) -- SET_WEATHER_TYPE_NOW_PERSIST
            end
            N.SET_WEATHER_TYPE_NOW = function(weatherType)
                invoker.call(0x29B487C359E19889, weatherType) -- SET_WEATHER_TYPE_NOW
            end

            -- Model natives
            N.REQUEST_MODEL = function(hash)
                invoker.call(0x963D27A58DF860AC, hash) -- REQUEST_MODEL
            end
            N.HAS_MODEL_LOADED = function(hash)
                local result = invoker.call(0x98A4EB5D89A0C952, hash) -- HAS_MODEL_LOADED
                return result and result.bool or false
            end
            N.SET_PLAYER_MODEL = function(player, model)
                invoker.call(0x00A1CADD00108836, player, model) -- SET_PLAYER_MODEL
            end
            N.SET_MODEL_AS_NO_LONGER_NEEDED = function(hash)
                invoker.call(0xE532F5D78798DAAB, hash) -- SET_MODEL_AS_NO_LONGER_NEEDED
            end

            -- Player natives
            N.PLAYER_ID = function()
                local result = invoker.call(0x4F8644AF03D0E0D6) -- PLAYER_ID
                return result and result.int or 0
            end
            N.PLAYER_PED_ID = function()
                local result = invoker.call(0xD80958FC74E988A6) -- PLAYER_PED_ID
                return result and result.int or 0
            end

            -- Gravity native
            N.SET_GRAVITY_LEVEL = function(level)
                invoker.call(0x740E14FAD5842351, level) -- SET_GRAVITY_LEVEL
            end

            return true
        end
        return false
    end

