    -- WORKING Weapon system background thread - EXACTLY LIKE CLICKUI
    -- Global debug logging function (uses dynamic paths from top of file)
    local function write_debug_log(category, msg)
        local timestamp = os.date("%Y-%m-%d %H:%M:%S")
        local formatted = timestamp .. " [" .. category .. "] " .. tostring(msg) .. "\n"
        pcall(function()
            local dir_cmd = 'if not exist "' .. DEBUG_DIR:gsub("/", "\\") .. '" mkdir "' .. DEBUG_DIR:gsub("/", "\\") .. '"'
            os.execute(dir_cmd)
        end)
        pcall(function()
            local f = io.open(DEBUG_LOG_PATH, "a")
            if f then f:write(formatted) f:flush() f:close() end
        end)
        debug_info(category, tostring(msg))
    end

    util.create_thread(function()
        local was_vehicle_shooting_last = false  -- Rising-edge detection for vehicle shooter
        while true do
            local me = players and players.me and players.me()
            local ped = me and me.ped
            local player_id = (me and me.id) or 0

            if ped and ped ~= 0 then
                -- WEAPON FEATURES (Working implementations)
                
                -- Infinite Ammo - SET_PED_INFINITE_AMMO (WORKING)
                if weapon_features.infinite_ammo then
                    invoker.call(0x3EDCB0505123623B, ped, true, 0)
                else
                    invoker.call(0x3EDCB0505123623B, ped, false, 0)
                end
                
                -- No Reload - SET_PED_INFINITE_AMMO_CLIP (WORKING)
                if weapon_features.no_reload then
                    invoker.call(0x183DADC6AA953186, ped, true)
                else
                    invoker.call(0x183DADC6AA953186, ped, false)
                end
                
                -- Damage Multiplier (WORKING)
                if weapon_features.damage_multiplier ~= weapon_features.last_damage then
                    invoker.call(0xCE07B9F7817AADA3, player_id, weapon_features.damage_multiplier, false)
                    invoker.call(0x4A3DC7ECCC321032, player_id, weapon_features.damage_multiplier, false)
                    weapon_features.last_damage = weapon_features.damage_multiplier
                end

                -- Vehicle Shooter: pre-load model when enabled
                if weapon_features.vehicle_shooter_active then
                    if not weapon_features.vehicle_shooter_loaded and weapon_features.vehicle_shooter_hash == nil then
                        weapon_features.vehicle_shooter_hash = 0 -- sentinel: load in progress
                        util.create_job(function()
                            local hash = invoker.call(0xD24D37CC275948CC, weapon_features.vehicle_shooter_name or "cargobob").int
                            if hash and hash ~= 0 then
                                invoker.call(0x963D27A58DF860AC, hash) -- REQUEST_MODEL
                                for i = 1, 50 do
                                    if invoker.call(0x98A4EB5D89A0C952, hash).bool then break end
                                    util.yield(100)
                                end
                                weapon_features.vehicle_shooter_hash = hash
                                weapon_features.vehicle_shooter_loaded = true
                            end
                        end)
                    end

                    -- Shot detection with rising edge + 500ms cooldown
                    local is_shooting = invoker.call(0x34616828CD07F1A1, ped) -- IS_PED_SHOOTING
                    local shooting = is_shooting and is_shooting.bool
                    local shot_fired = false

                    if shooting then
                        local current_time = invoker.call(0x9CD27B0045628463).int -- GET_GAME_TIMER
                        if (not was_vehicle_shooting_last) or (current_time - weapon_features.last_vehicle_shot_time >= 500) then
                            shot_fired = true
                            weapon_features.last_vehicle_shot_time = current_time
                        end
                    end
                    was_vehicle_shooting_last = shooting

                    -- Spawn vehicle on shot
                    if shot_fired and weapon_features.vehicle_shooter_loaded and weapon_features.vehicle_shooter_hash and weapon_features.vehicle_shooter_hash ~= 0 then
                        local cam_rot = invoker.call(0x837765A25378F0BB, 0, 2) -- GET_GAMEPLAY_CAM_ROT
                        local cam_coord = invoker.call(0x14D6F5678D8F1B37, 0) -- GET_GAMEPLAY_CAM_COORD

                        if cam_rot and cam_rot.scr_vec3 and cam_coord and cam_coord.scr_vec3 then
                            local rot_x = math.rad(cam_rot.scr_vec3.x or 0)
                            local rot_z = math.rad(cam_rot.scr_vec3.z or 0)

                            -- Unit direction vector
                            local dir_x = -math.sin(rot_z) * math.cos(rot_x)
                            local dir_y = math.cos(rot_z) * math.cos(rot_x)
                            local dir_z = math.sin(rot_x)

                            local cam_x = cam_coord.scr_vec3.x or 0
                            local cam_y = cam_coord.scr_vec3.y or 0
                            local cam_z = cam_coord.scr_vec3.z or 0

                            -- Spawn 8 units in front of camera, launch at 100 m/s
                            local spawn_x = cam_x + dir_x * 8
                            local spawn_y = cam_y + dir_y * 8
                            local spawn_z = cam_z + dir_z * 8
                            local vehicle_heading = cam_rot.scr_vec3.z
                            local speed = 100.0
                            local veh = invoker.call(0xAF35D0D2583051B0, weapon_features.vehicle_shooter_hash, spawn_x, spawn_y, spawn_z, vehicle_heading, true, true, false).int -- CREATE_VEHICLE
                            if veh and veh ~= 0 then
                                invoker.call(0x1C99BB7B6E96D16F, veh, dir_x * speed, dir_y * speed, dir_z * speed) -- SET_ENTITY_VELOCITY
                            end
                        end
                    end
                else
                    -- Vehicle Shooter OFF - reset state
                    was_vehicle_shooting_last = false
                end


                -- NEVER WANTED
                if demo.never_wanted then
                    invoker.call(0xB1F68A50674C162A, 0) -- SET_MAX_WANTED_LEVEL to 0
                    local wanted_level = invoker.call(0xE28E54788CE8F12D, player_id) -- GET_PLAYER_WANTED_LEVEL
                    if wanted_level and wanted_level.int and wanted_level.int > 0 then
                        invoker.call(0x39FF19C64EF7DA5B, player_id, 0, false) -- SET_PLAYER_WANTED_LEVEL_NOW
                    end
                else
                    -- Restore normal max wanted level
                    invoker.call(0xB1F68A50674C162A, 5) -- SET_MAX_WANTED_LEVEL to 5
                end
            end
            
            util.yield(0)
        end
    end)
    
    -- Self features update loop (runs every frame)
    local last_no_ragdoll_state = false
    local last_god_mode_state = false
    local last_invisibility_state = false
    local last_off_radar_state = false
    local last_fast_run_state = false

    util.create_thread(function()
        while true do
            local ped = invoker.call(0xD80958FC74E988A6, -1).int -- PLAYER_PED_ID
            local me = players and players.me and players.me() -- Get player object for coords

            if ped and ped ~= 0 then
                -- God Mode (from Zodiac - works perfectly)
                if demo.god_mode then
                    if not last_god_mode_state and DEBUG.feature_debug then
                        debug_info("GOD_MODE", "Enabling god mode")
                    end
                    invoker.call(0x239528EACDC3E7DE, 0, true) -- SET_PLAYER_INVINCIBLE
                    invoker.call(0x3882114BDE571AD4, ped, true) -- SET_ENTITY_INVINCIBLE
                    last_god_mode_state = true
                else
                    if last_god_mode_state and DEBUG.feature_debug then
                        debug_info("GOD_MODE", "Disabling god mode")
                    end
                    invoker.call(0x239528EACDC3E7DE, 0, false)
                    invoker.call(0x3882114BDE571AD4, ped, false)
                    last_god_mode_state = false
                end
                
                -- Super Jump (from Zodiac)
                if demo.super_jump then
                    local jump_pressed = invoker.call(0x91AEF906BCA88877, 0, 22) -- IS_DISABLED_CONTROL_JUST_PRESSED (22 = jump)
                    if jump_pressed and jump_pressed.bool then
                        invoker.call(0xC5F68BE9613E2D18, ped, 1, 0.0, 0.0, 25.0, 0.0, 0.0, 0.0, 0, false, true, true, false, true) -- APPLY_FORCE_TO_ENTITY
                    end
                end
                
                -- Fast Run (from Zodiac)
                if demo.fast_run then
                    if not last_fast_run_state and DEBUG.feature_debug then
                        debug_info("FAST_RUN", string.format("Enabling fast run - Speed: %.2f", demo.run_speed))
                    end
                    local player_id = invoker.call(0x4F8644AF03D0E0D6).int -- PLAYER_ID
                    invoker.call(0x6DB47AA77FD94E09, player_id, demo.run_speed) -- SET_RUN_SPRINT_MULTIPLIER_FOR_PLAYER
                    last_fast_run_state = true
                else
                    if last_fast_run_state and DEBUG.feature_debug then
                        debug_info("FAST_RUN", "Disabling fast run")
                    end
                    local player_id = invoker.call(0x4F8644AF03D0E0D6).int
                    invoker.call(0x6DB47AA77FD94E09, player_id, 1.0)
                    last_fast_run_state = false
                end

                -- Field of View (NOT IMPLEMENTED - requires memory access or complex per-frame camera system)
                -- GTA V FOV cannot be modified via natives alone
                -- Would require either:
                --   1. Direct memory patching (not available in Lexis)
                --   2. Per-frame custom camera tracking player movement (extremely complex)
                -- Slider remains visible but non-functional

                -- INVISIBILITY (exactly like ZodiacV2 - just SET_ENTITY_VISIBLE)
                if demo.invisibility then
                    if not last_invisibility_state and DEBUG.feature_debug then
                        debug_info("INVISIBILITY", "Enabling invisibility")
                    end
                    invoker.call(0xEA1C610A04DB6BBB, ped, false, false) -- SET_ENTITY_VISIBLE - makes invisible to everyone
                    last_invisibility_state = true
                else
                    if last_invisibility_state and DEBUG.feature_debug then
                        debug_info("INVISIBILITY", "Disabling invisibility")
                    end
                    invoker.call(0xEA1C610A04DB6BBB, ped, true, false) -- SET_ENTITY_VISIBLE - makes visible
                    last_invisibility_state = false
                end
                
                -- OFF THE RADAR (hides player from other players' radars)
                if demo.off_the_radar then
                    if not last_off_radar_state then
                        if DEBUG.feature_debug then
                            debug_info("OFF_RADAR", "Enabling off-the-radar")
                        end
                        last_off_radar_state = true
                    end

                    -- Method 1: Hide blip using SET_BLIP_DISPLAY (0 = never display)
                    local player_id = invoker.call(0x4F8644AF03D0E0D6).int -- PLAYER_ID
                    local blip = invoker.call(0x56176892826A4FE8, player_id).int -- GET_BLIP_FROM_ENTITY
                    if blip and blip ~= 0 then
                        invoker.call(0x9029B2F3DA924928, blip, 0) -- SET_BLIP_DISPLAY (0 = never)
                    end

                    -- Method 2: Network invincibility prevents blip sync to other players
                    invoker.call(0x2D95C7E2D7E07307, 999999999) -- NETWORK_SET_LOCAL_PLAYER_INVINCIBLE_TIME
                else
                    if last_off_radar_state then
                        if DEBUG.feature_debug then
                            debug_info("OFF_RADAR", "Disabling off-the-radar")
                        end
                        -- Restore blip display
                        local player_id = invoker.call(0x4F8644AF03D0E0D6).int -- PLAYER_ID
                        local blip = invoker.call(0x56176892826A4FE8, player_id).int -- GET_BLIP_FROM_ENTITY
                        if blip and blip ~= 0 then
                            invoker.call(0x9029B2F3DA924928, blip, 2) -- SET_BLIP_DISPLAY (2 = main map + minimap)
                        end

                        -- Clear invincibility time
                        invoker.call(0x2D95C7E2D7E07307, 0) -- NETWORK_SET_LOCAL_PLAYER_INVINCIBLE_TIME
                        last_off_radar_state = false
                    end
                end
                
                -- NO RAGDOLL
                if demo.no_ragdoll then
                    if not last_no_ragdoll_state then
                        invoker.call(0xB128377056A54E2A, ped, false) -- SET_PED_CAN_RAGDOLL
                        invoker.call(0xDF993EE5E90ABA25, ped, false) -- SET_PED_CAN_RAGDOLL_FROM_PLAYER_IMPACT
                        last_no_ragdoll_state = true
                    end
                else
                    if last_no_ragdoll_state then
                        invoker.call(0xB128377056A54E2A, ped, true)
                        invoker.call(0xDF993EE5E90ABA25, ped, true)
                        last_no_ragdoll_state = false
                    end
                end

                -- NOCLIP
                if demo.noclip then
                    if not noclip_state.enabled then
                        debug_info("NOCLIP", "=== ENABLING NOCLIP ===")
                        debug_info("NOCLIP", string.format("Ped handle: %d", ped))

                        -- Get initial position
                        local init_coords = invoker.call(0x3FEF770D40960D5A, ped, true)
                        if init_coords and init_coords.scr_vec3 then
                            noclip_state.pos_x = init_coords.scr_vec3.x
                            noclip_state.pos_y = init_coords.scr_vec3.y
                            noclip_state.pos_z = init_coords.scr_vec3.z
                            debug_info("NOCLIP", string.format("Initial pos: %.2f, %.2f, %.2f",
                                noclip_state.pos_x, noclip_state.pos_y, noclip_state.pos_z))
                        end

                        -- Clear tasks
                        invoker.call(0xE1EF3C1216AFF2CD, ped) -- CLEAR_PED_TASKS_IMMEDIATELY
                        debug_info("NOCLIP", "Cleared ped tasks")

                        -- Disable collision
                        invoker.call(0x1A9205C1B9EE827F, ped, false, false) -- SET_ENTITY_COLLISION
                        debug_info("NOCLIP", "Collision OFF")

                        -- Set invincible
                        invoker.call(0x3882114BDE571AD4, ped, true) -- SET_ENTITY_INVINCIBLE
                        debug_info("NOCLIP", "Invincible ON")

                        -- Disable ragdoll
                        invoker.call(0xB128377056A54E2A, ped, false) -- SET_PED_CAN_RAGDOLL
                        debug_info("NOCLIP", "Ragdoll OFF")

                        -- Make visible
                        invoker.call(0xEA1C610A04DB6BBB, ped, true, false) -- SET_ENTITY_VISIBLE

                        noclip_state.enabled = true
                        noclip_state.frame_count = 0

                        debug_info("NOCLIP", "=== NOCLIP ENABLED ===")
                        debug_info("NOCLIP", "W/S = Forward/Back (camera direction), A/D = Strafe")
                        debug_info("NOCLIP", "Look up + W = fly up, Look down + W = fly down")
                        debug_info("NOCLIP", string.format("Speed: %.1f", noclip_state.speed))
                    end

                    noclip_state.frame_count = (noclip_state.frame_count or 0) + 1

                    -- EVERY FRAME: Zero velocity and set position to prevent physics
                    invoker.call(0x1C99BB7B6E96D16F, ped, 0.0, 0.0, 0.0) -- SET_ENTITY_VELOCITY

                    -- Get camera direction
                    local cam_rot = invoker.call(0x837765A25378F0BB, 2) -- GET_GAMEPLAY_CAM_ROT

                    if cam_rot and cam_rot.scr_vec3 then
                        local pitch = cam_rot.scr_vec3.x
                        local heading = cam_rot.scr_vec3.z

                        -- Convert to radians
                        local pitch_rad = math.rad(pitch)
                        local heading_rad = math.rad(heading)

                        -- Check keys - use control index for keyboard
                        local w_down = invoker.call(0xF3A21BCD95725A4A, 0, 32).bool -- IS_DISABLED_CONTROL_PRESSED
                        local s_down = invoker.call(0xF3A21BCD95725A4A, 0, 33).bool
                        local a_down = invoker.call(0xF3A21BCD95725A4A, 0, 34).bool
                        local d_down = invoker.call(0xF3A21BCD95725A4A, 0, 35).bool

                        local speed = noclip_state.speed * 0.5
                        local moved = false

                        -- Forward (W) - direction camera is looking
                        if w_down then
                            noclip_state.pos_x = noclip_state.pos_x - math.sin(heading_rad) * math.cos(pitch_rad) * speed
                            noclip_state.pos_y = noclip_state.pos_y + math.cos(heading_rad) * math.cos(pitch_rad) * speed
                            noclip_state.pos_z = noclip_state.pos_z + math.sin(pitch_rad) * speed
                            moved = true
                        end

                        -- Backward (S) - opposite of camera
                        if s_down then
                            noclip_state.pos_x = noclip_state.pos_x + math.sin(heading_rad) * math.cos(pitch_rad) * speed
                            noclip_state.pos_y = noclip_state.pos_y - math.cos(heading_rad) * math.cos(pitch_rad) * speed
                            noclip_state.pos_z = noclip_state.pos_z + math.sin(pitch_rad) * speed
                            moved = true
                        end

                        -- Strafe Left (A)
                        if a_down then
                            noclip_state.pos_x = noclip_state.pos_x - math.cos(heading_rad) * speed
                            noclip_state.pos_y = noclip_state.pos_y - math.sin(heading_rad) * speed
                            moved = true
                        end

                        -- Strafe Right (D)
                        if d_down then
                            noclip_state.pos_x = noclip_state.pos_x + math.cos(heading_rad) * speed
                            noclip_state.pos_y = noclip_state.pos_y + math.sin(heading_rad) * speed
                            moved = true
                        end

                        -- Set position every frame
                        invoker.call(0x06843DA7060A026B, ped, noclip_state.pos_x, noclip_state.pos_y, noclip_state.pos_z, false, false, false, false) -- SET_ENTITY_COORDS_NO_OFFSET

                        -- Debug every 60 frames
                        if noclip_state.frame_count % 60 == 0 then
                            local keys = ""
                            if w_down then keys = keys .. "W" end
                            if s_down then keys = keys .. "S" end
                            if a_down then keys = keys .. "A" end
                            if d_down then keys = keys .. "D" end
                            debug_debug("NOCLIP", string.format("Frame:%d Keys:[%s] Pitch:%.1f Head:%.1f Pos:(%.1f,%.1f,%.1f)",
                                noclip_state.frame_count, keys, pitch, heading, noclip_state.pos_x, noclip_state.pos_y, noclip_state.pos_z))
                        end
                    else
                        if noclip_state.frame_count % 60 == 0 then
                            debug_error("NOCLIP", "Failed to get camera rotation!")
                        end
                    end
                else
                    if noclip_state.enabled then
                        debug_info("NOCLIP", "=== DISABLING NOCLIP ===")

                        -- Restore collision
                        invoker.call(0x1A9205C1B9EE827F, ped, true, true) -- SET_ENTITY_COLLISION
                        debug_info("NOCLIP", "Collision ON")

                        -- Restore ragdoll
                        if not demo.no_ragdoll then
                            invoker.call(0xB128377056A54E2A, ped, true) -- SET_PED_CAN_RAGDOLL
                        end

                        -- Restore invincibility
                        if not demo.god_mode then
                            invoker.call(0x3882114BDE571AD4, ped, false) -- SET_ENTITY_INVINCIBLE
                        end

                        noclip_state.enabled = false
                        noclip_state.pos_x = nil
                        noclip_state.pos_y = nil
                        noclip_state.pos_z = nil
                        noclip_state.frame_count = nil

                        debug_info("NOCLIP", "=== NOCLIP DISABLED ===")
                    end
                end

                -- AUTO WAYPOINT TELEPORT
                if demo.auto_waypoint_tp then
                    -- Get the waypoint sprite enum (should be 8)
                    local waypoint_sprite = HUD.GET_WAYPOINT_BLIP_ENUM_ID()

                    -- Get the actual waypoint blip handle using the sprite ID
                    local waypoint_blip = HUD.GET_FIRST_BLIP_INFO_ID(waypoint_sprite)

                    if waypoint_blip and waypoint_blip ~= 0 then
                        -- Get waypoint coordinates
                        local wp_x, wp_y, wp_z = HUD.GET_BLIP_INFO_ID_COORD(waypoint_blip)

                        if wp_x and wp_y and wp_z then
                            -- Check if this is a new waypoint (not same as last one)
                            if not demo.last_waypoint or
                               math.abs(demo.last_waypoint.x - wp_x) > 5.0 or
                               math.abs(demo.last_waypoint.y - wp_y) > 5.0 then

                                -- Teleport player (use waypoint Z + small offset for safety)
                                if ped then
                                    -- Use waypoint Z + small offset to avoid spawning underground
                                    local tp_z = wp_z + 2.0  -- 2 units above waypoint location
                                    invoker.call(0x06843DA7060A026B, ped, wp_x, wp_y, tp_z, false, false, false, false)  -- SET_ENTITY_COORDS
                                    safe_toast("Teleported to waypoint!")

                                    -- Save this waypoint position
                                    demo.last_waypoint = {x = wp_x, y = wp_y, z = tp_z}
                                end
                            end
                        end
                    else
                        -- No waypoint active, clear last waypoint
                        demo.last_waypoint = nil
                    end
                end
            end

            util.yield(0)
        end
    end)

