    local ESP_DEBUG_DIR = "C:/Users/lmao2/Lexis/Grand Theft Auto V/scripts/Carpie Diem/Debug ESP"
    local ESP_LOG_PATH = ESP_DEBUG_DIR .. "/esp_debug.log"

