                            end
                        end
                    end

                    -- Render player list in side panel
                    if esp_state.draw_player_list and esp_state.name_data and #esp_state.name_data > 0 then
                        -- Sort by distance (closest first)
                        table.sort(esp_state.name_data, function(a, b) return a.distance < b.distance end)

                        local panel_x = 30
                        local panel_y = 200
                        local line_height = 24  -- Increased for bigger text

                        for i, ndata in ipairs(esp_state.name_data) do
                            if i > 10 then break end  -- Show max 10 players

                            local y_pos = panel_y + ((i - 1) * line_height)

                            if gui and gui.text then
                                local display_text = string.format("%s [%.0fm]", ndata.name, ndata.distance)

                                -- Determine color based on mode
                                local text_color
                                if esp_state.player_list_color_mode == 1 then
                                    -- Distance-based coloring
                                    if ndata.distance > 400 then
                                        text_color = color(255, 0, 0, 255)  -- Red for far
                                    elseif ndata.distance > 200 then
                                        text_color = color(255, 255, 0, 255)  -- Yellow for medium
                                    else
                                        text_color = color(0, 255, 0, 255)  -- Green for close
                                    end
                                elseif esp_state.player_list_color_mode == 2 then
                                    -- Rainbow - cycle through colors based on time and index
                                    local time = os.clock()
                                    local hue = ((time * 100) + (i * 30)) % 360
                                    local r, g, b = 0, 0, 0
                                    local h = hue / 60
                                    local x = (1 - math.abs(h % 2 - 1))
                                    if h < 1 then r, g, b = 1, x, 0
                                    elseif h < 2 then r, g, b = x, 1, 0
                                    elseif h < 3 then r, g, b = 0, 1, x
                                    elseif h < 4 then r, g, b = 0, x, 1
                                    elseif h < 5 then r, g, b = x, 0, 1
                                    else r, g, b = 1, 0, x
                                    end
                                    text_color = color(math.floor(r * 255), math.floor(g * 255), math.floor(b * 255), 255)
                                elseif esp_state.player_list_color_mode == 3 then
