                                    text_color = color(255, 255, 255, 255)
                                elseif esp_state.player_list_color_mode == 4 then
                                    -- Cyan
                                    text_color = color(0, 255, 255, 255)
                                elseif esp_state.player_list_color_mode == 5 then
