                if esp_was_enabled then
                    esp_log(">>> ESP DISABLED <<<")
                    esp_log("========================================")
                    esp_logging_active = false  -- Stop logging when ESP is turned off
                    esp_was_enabled = false
                end

                if esp_state.gamer_tags and next(esp_state.gamer_tags) then
                    for ped, tag_id in pairs(esp_state.gamer_tags) do
