                        invoker.call(0x31698AA80E0223F8, tag_id)
                    end
                    esp_state.gamer_tags = {}
                end
            end

            -- Render custom screen message at top of screen (works independently of ESP)
            if esp_state.custom_message_enabled and esp_state.custom_message_text and esp_state.custom_message_text ~= "" then
