    -- =========================================================================
    -- DRAWING FUNCTIONS (Exact ClickUI pattern)
    -- =========================================================================

    local function draw_rect(x, y, w, h, col, rounding)
        if w <= 0 or h <= 0 then return end
        local r = gui.rect(vec2(x, y), vec2(w, h))
        r:filled()
        -- Apply menu transparency
        if UI.menu_transparency and UI.menu_transparency < 100 then
            local transparency_factor = UI.menu_transparency / 100
            -- Create new color with modified alpha
            local new_col = color(col.r or 255, col.g or 255, col.b or 255, math.floor((col.a or 255) * transparency_factor))
            r:color(new_col)
        else
            r:color(col)
        end
        if rounding and rounding > 0 then
            r:rounding(rounding)
        end
        r:draw()
    end

    local function draw_text(str, x, y, size, col)
        local t = gui.text(tostring(str))
        if not t then return end
        t:position(vec2(x, y))
        t:scale(size)
        t:color(col)
        t:draw()
    end

    local function draw_text_centered(str, x, y, w, h, size, col)
        local t = gui.text(tostring(str))
        if not t then return end
        -- Center horizontally
        local tx = x + w / 2
        t:position(vec2(tx, y + (h - size) / 2))
        t:scale(size)
        t:color(col)
        if gui.justify then
            t:justify(gui.justify.center)
        end
        t:draw()
    end

    local function is_mouse_in(x, y, w, h)
        return MOUSE.x >= x and MOUSE.x <= x + w and MOUSE.y >= y and MOUSE.y <= y + h
    end

    -- =========================================================================
    -- INPUT UPDATE
    -- =========================================================================

    -- Native for checking scroll wheel (control 241 = scroll up, 242 = scroll down)
    local N_IS_DISABLED_CONTROL_JUST_PRESSED = nil
    if invoker and invoker.call then
        N_IS_DISABLED_CONTROL_JUST_PRESSED = function(inputGroup, control)
            local result = invoker.call(0xe2587f8cbbd87b1d, inputGroup, control)
            return result and result.bool or false
        end
    end

    local function update_input()
        -- Mouse position
        if input.mouse_position then
            local mp = input.mouse_position()
            if mp then
                MOUSE.x = mp.x or 0
                MOUSE.y = mp.y or 0
            end
        end

        -- Mouse buttons
        local was_pressed = MOUSE.pressed
        if input.mouse then
            local ms = input.mouse(1)
            if ms then
                MOUSE.pressed = ms.pressed or false
                MOUSE.just_pressed = ms.just_pressed or false
            end
        end

        -- Mouse wheel scroll (using GTA V control codes 241=up, 242=down)
        MOUSE.scroll_up = false
        MOUSE.scroll_down = false
        if N_IS_DISABLED_CONTROL_JUST_PRESSED then
            MOUSE.scroll_up = N_IS_DISABLED_CONTROL_JUST_PRESSED(0, 241)
            MOUSE.scroll_down = N_IS_DISABLED_CONTROL_JUST_PRESSED(0, 242)
        end
    end

    -- =========================================================================
    -- WIDGET SYSTEM
    -- =========================================================================

    local widget_y = 0
    local content_x = 0
    local content_w = 0

    local function begin_content(x, y, w)
        content_x = x
        widget_y = y
        content_w = w
    end

    local function button(label)
        local s = UI.scale
        local pad = math.floor(10 * s)
        local x = content_x + pad
        local y = widget_y
        local w = content_w - pad * 2
        local h = math.floor(36 * s)  -- Taller for better clickability
        local hover = is_mouse_in(x, y, w, h)
        local pressed = hover and MOUSE.pressed
        local clicked = hover and MOUSE.just_pressed

        if clicked then
            debug_debug("UI", string.format("Button clicked: '%s'", label))
        end

        -- Button background with states
        local bg_col = C.widget_bg
        local text_offset = 0
        if pressed then
            -- Active/pressed state: darker (widget_bg is 40,40,46 so pressed is ~80%)
            bg_col = color(32, 32, 37, 255)
            text_offset = math.floor(1 * s)
        elseif hover then
            -- Hover state: lighter
            bg_col = C.widget_hover
        end

        draw_rect(x, y, w, h, bg_col, math.floor((UI.widget_rounding or 5) * s))  -- More rounding

        -- Accent bar on top (shows on hover)
        if hover then
            draw_rect(x, y, w, math.floor(3 * s), C.accent, math.floor(6 * s))
        end

        -- Subtle glow on hover
        if hover and not pressed then
            -- Draw thin border for glow effect (default accent is 114,137,218)
            draw_rect(x - 1, y - 1, w + 2, h + 2, color(114, 137, 218, 60), math.floor(6 * s))
        end

        -- Button text (offset when pressed)
        draw_text_centered(label, x, y + text_offset, w, h, UI.font_widget, C.text)

        widget_y = widget_y + h + math.floor(8 * s)  -- More spacing
        return clicked
    end

