    function Speedometer:GetTheme() return self.themes[self.currentTheme] or self.themes.neon_purple end
    function Speedometer:SetTheme(name) if self.themes[name] then self.currentTheme = name end end
    function Speedometer:GetThemeNames()
        local names = {}
        for _, key in ipairs(self.themeOrder) do names[#names+1] = self.themes[key].name end
        return names
    end
    function Speedometer:GetThemeKeyByIndex(index) return self.themeOrder[index] or "neon_purple" end
    function Speedometer:GetThemeIndexByKey(key)
        for i, k in ipairs(self.themeOrder) do if k == key then return i end end
        return 1
    end
    function Speedometer:SetDisplayMode(mode)
        for _, key in ipairs(self.displayModeOrder) do
            if key == mode then self.displayMode = mode return end
        end
    end
    function Speedometer:GetDisplayModeNames()
        local names = {}
        for _, key in ipairs(self.displayModeOrder) do names[#names+1] = self.displayModeNames[key] or key end
        return names
    end
    function Speedometer:GetDisplayModeKeyByIndex(index) return self.displayModeOrder[index] or "gauge" end
    function Speedometer:GetDisplayModeIndexByKey(key)
        for i, k in ipairs(self.displayModeOrder) do if k == key then return i end end
        return 1
    end

    function Speedometer:Update()
        if not self.enabled then return end
        local now = os.clock()
        self.deltaTime = now - self.lastTime
        self.lastTime = now
        if self.deltaTime > 0.1 then self.deltaTime = 0.016 end

        local currentVeh = 0
        if players and players.me then
            local me = players.me()
            if me and me.in_vehicle then currentVeh = me.vehicle or 0 else currentVeh = 0 end
        end
        if (not currentVeh) or currentVeh == 0 then
            self.speed,self.speedSmooth,self.lastSpeed,self.accel,self.brake = 0,0,0,0,0
            return false
        end

        local speedRes = invoker.call(0xD5037BA82E12416F, currentVeh)
        local speedMs = (speedRes and speedRes.float) or nil
        if not speedMs then
            self.speed,self.speedSmooth,self.lastSpeed,self.accel,self.brake = 0,0,0,0,0
            return false
        end
        self.speed = speedMs * 3.6

        local smooth = clamp(self.deltaTime * 6, 0, 1)
        self.speedSmooth = lerp(self.speedSmooth or self.speed, self.speed, smooth)

        local delta = self.speed - (self.lastSpeed or self.speed)
        self.lastSpeed = self.speed
        local accelRaw = clamp(delta / 6, 0, 1)
        local brakeRaw = clamp((-delta) / 8, 0, 1)
        local smoothAb = clamp(self.deltaTime * 8, 0, 1)
        self.accel = lerp(self.accel or 0, accelRaw, smoothAb)
        self.brake = lerp(self.brake or 0, brakeRaw, smoothAb)
        return true
    end

    function Speedometer:Init()
        self.speedSmooth,self.speed,self.lastSpeed,self.accel,self.brake = 0,0,0,0,0
        self.lastTime,self.deltaTime,self.posSet = os.clock(),0.016,false
    end

    -- Simplified Render for integration (full version would be too large)
    function Speedometer:Render()
        if not self.enabled or not game or not game.resolution then return end
        local inVeh = self:Update()
        if not inVeh then return end

        local res = game.resolution()
        local sc,radius,margin = self.scale, self.radius * self.scale, math.floor(30 * self.scale)
        if not self.posSet then self.pos = vec2(res.x - radius - margin, res.y - radius - margin) end
        local center,theme = self.pos, self:GetTheme()
        local speed = clamp(self.speedSmooth or self.speed, 0, self.maxSpeed)

        -- Text mode
        if self.displayMode == "text" then
            local value = tostring(math.floor(speed + 0.5))
            local cfg = self.textConfig
            local base = vec2(center.x + (cfg.offsetX or 0), center.y + (cfg.offsetY or 0))
            if gui and gui.text then
                local textScale = clamp(cfg.scale or 28, 10, 64)
                local speedColor = cfg.useThemeColor and theme.textCol or cfg.speedColor
                gui.text(value)
                    :position(base)
                    :scale(textScale)
                    :color(color(speedColor.r, speedColor.g, speedColor.b, speedColor.a or 255))
                    :draw()
                if cfg.showUnit then
                    gui.text("km/h")
                        :position(vec2(base.x + 50, base.y))
                        :scale(textScale)
                        :color(color((cfg.unitColor or cfg.speedColor).r, (cfg.unitColor or cfg.speedColor).g, (cfg.unitColor or cfg.speedColor).b, 200))
                        :draw()
                end
            end
            return
        end

        -- Gauge mode (simplified from full version)
        local r = radius
        while r > 0 do gui.circle(center, r, color(theme.bg.r, theme.bg.g, theme.bg.b, theme.bg.a)) r = r - math.max(2, math.floor(3 * sc)) end
        local t = self.maxSpeed > 0 and (speed / self.maxSpeed) or 0
        local angle = math.rad(self.sweepStart + (self.sweepEnd - self.sweepStart) * t)
        local needleLen = radius - (22 * sc)
        local needleEnd = vec2(center.x + math.cos(angle) * needleLen, center.y + math.sin(angle) * needleLen)
        if gui and gui.line then gui.line(center, needleEnd, math.max(1, math.floor(self.needleThickness * sc)), color(theme.needle.r, theme.needle.g, theme.needle.b, theme.needle.a)) end
        gui.circle(center, math.max(2, math.floor(6 * sc)), color(theme.hub.r, theme.hub.g, theme.hub.b, theme.hub.a))
        if gui and gui.text then
            local speedText = tostring(math.floor(speed + 0.5))
            gui.text(speedText):position(vec2(center.x - 20, center.y)):scale(22):color(color(theme.textCol.r, theme.textCol.g, theme.textCol.b, theme.textCol.a)):draw()
            gui.text("KM/H"):position(vec2(center.x - 15, center.y - 20)):scale(12):color(color(theme.textDim.r, theme.textDim.g, theme.textDim.b, theme.textDim.a)):draw()
        end
    end


    local function checkbox(label, value)
        local s = UI.scale
        local pad = math.floor(10 * s)
        local x = content_x + pad
        local y = widget_y
        local w = content_w - pad * 2
        local h = math.floor(32 * s)  -- Taller for modern toggle
        local hover = is_mouse_in(x, y, w, h)

        local old_value = value
        if hover and MOUSE.just_pressed then
            value = not value
            -- Log toggle
            if value ~= old_value then
                debug_debug("UI", string.format("'%s' toggled: %s", label, value and "ON" or "OFF"))
            end
        end

        -- Background with hover glow
        local bg_col = hover and C.widget_hover or C.widget_bg
        draw_rect(x, y, w, h, bg_col, math.floor((UI.widget_rounding or 5) * s))

        -- Modern toggle switch (pill shape)
        local toggle_w = math.floor(48 * s)
        local toggle_h = math.floor(24 * s)
        local toggle_x = x + w - toggle_w - math.floor(10 * s)
        local toggle_y = y + (h - toggle_h) / 2

        -- Toggle track (background)
        local track_col = value and C.accent or C.checkbox_off
        draw_rect(toggle_x, toggle_y, toggle_w, toggle_h, track_col, math.floor(12 * s))  -- High rounding for pill shape

        -- Toggle knob (circle that slides)
        local knob_size = math.floor(20 * s)
        local knob_padding = math.floor(2 * s)
        local knob_x = value and (toggle_x + toggle_w - knob_size - knob_padding) or (toggle_x + knob_padding)
        local knob_y = toggle_y + knob_padding
        draw_rect(knob_x, knob_y, knob_size, knob_size, color(255, 255, 255, 255), math.floor(10 * s))  -- White circle

        -- Label on left
        draw_text(label, x + math.floor(10 * s), y + (h - UI.font_widget) / 2, UI.font_widget, C.text)

        widget_y = widget_y + h + math.floor(6 * s)  -- More spacing
        return value
    end

    local function slider(label, value, min, max)
        local s = UI.scale
        local pad = math.floor(10 * s)
        local x = content_x + pad
        local y = widget_y
        local w = content_w - pad * 2
        local h = math.floor(50 * s)  -- Slightly taller for better spacing

        -- Bigger hitbox for track (extends above/below)
        local track_x = x + math.floor(8 * s)
        local track_y = y + math.floor(30 * s)
        local track_w = w - math.floor(16 * s)
        local track_h = math.floor(10 * s)  -- Slightly taller track
        local track_hitbox_h = math.floor(24 * s)  -- Bigger hitbox
        local track_hitbox_y = track_y - (track_hitbox_h - track_h) / 2

        local hover = is_mouse_in(x, y, w, h)
        local track_hover = is_mouse_in(track_x, track_hitbox_y, track_w, track_hitbox_h)

        -- Background with glow on hover
        local bg_col = track_hover and C.widget_hover or (hover and C.widget_hover or C.widget_bg)
        draw_rect(x, y, w, h, bg_col, math.floor((UI.widget_rounding or 5) * s))

        -- Label and value
        draw_text(string.format("%s: %.2f", label, value), x + math.floor(8 * s), y + math.floor(6 * s), UI.font_widget, C.text)

        -- Min/Max labels
        draw_text(tostring(min), track_x, track_y + track_h + math.floor(4 * s), UI.font_small - 2, C.text_dim)
        local max_text = tostring(max)
        draw_text(max_text, track_x + track_w - math.floor(12 * s), track_y + track_h + math.floor(4 * s), UI.font_small - 2, C.text_dim)

        -- Track background
        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor((UI.widget_rounding or 5) * s))

        -- Fill with gradient effect (darker at start)
        local pct = (value - min) / (max - min)
        if pct > 0 then
            draw_rect(track_x, track_y, track_w * pct, track_h, C.accent, math.floor((UI.widget_rounding or 5) * s))
        end

        -- Handle/thumb indicator
        local thumb_x = track_x + (track_w * pct) - math.floor(4 * s)
        local thumb_y = track_y - math.floor(3 * s)
        local thumb_w = math.floor(8 * s)
        local thumb_h = track_h + math.floor(6 * s)
        draw_rect(thumb_x, thumb_y, thumb_w, thumb_h, color(255, 255, 255, 255), math.floor(3 * s))

        -- Drag interaction
        if track_hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
            value = min + (max - min) * mouse_pct

            -- Value tooltip while dragging
            local tooltip_x = MOUSE.x - math.floor(20 * s)
            local tooltip_y = MOUSE.y - math.floor(30 * s)
            local tooltip_w = math.floor(45 * s)
            local tooltip_h = math.floor(22 * s)
            draw_rect(tooltip_x, tooltip_y, tooltip_w, tooltip_h, color(0, 0, 0, 230), math.floor(4 * s))
            draw_text(string.format("%.1f", value), tooltip_x + math.floor(6 * s), tooltip_y + math.floor(4 * s), UI.font_small, color(255, 255, 255, 255))
        end

        widget_y = widget_y + h + math.floor(6 * s)  -- More spacing after
        return value
    end

    local function group_header(title)
        local s = UI.scale
        local pad = math.floor(10 * s)
        local x = content_x + pad
        local y = widget_y
        local w = content_w - pad * 2
        local h = math.floor(28 * s)

        draw_rect(x, y, w, h, C.group_header, math.floor((UI.widget_rounding or 5) * s))
        draw_text(title, x + math.floor(10 * s), y + (h - UI.font_widget) / 2, UI.font_widget, C.text)

        widget_y = widget_y + h + math.floor(5 * s)
    end

    local function text_label(str)
        local s = UI.scale
        draw_text(str, content_x + math.floor(15 * s), widget_y, UI.font_widget, C.text_dim)
        widget_y = widget_y + math.floor(22 * s)
    end

    local function separator()
        local s = UI.scale
        local pad = math.floor(10 * s)
        draw_rect(content_x + pad, widget_y + math.floor(3 * s), content_w - pad * 2, 1, C.text_dim)
        widget_y = widget_y + math.floor(10 * s)
    end

    -- =========================================================================
    -- PLAYER LIST FUNCTIONS
    -- =========================================================================

    local function update_player_list()
        local now = os.clock()
        if now < player_state.update_timer then return end
        player_state.update_timer = now + 2.0  -- Update every 2 seconds (reduced from 0.5 to prevent flashing)

        player_state.player_list = {}

        -- Get my ID
        if players and players.me then
            local me = players.me()
            if me then player_state.my_id = me.id or -1 end
        end

        -- Get hosts
        if script and script.host then
            local sh = script.host("freemode")
            if sh then player_state.script_host_id = sh.id or -1 end
        end
        if game and game.host then
            local gh = game.host()
            if gh then player_state.session_host_id = gh.id or -1 end
        end

        -- Get player list
        local first_non_host = -1
        if players and players.list then
            for _, p in ipairs(players.list()) do
                if p and p.connected ~= false then
                    local pid = p.id or 0

                    -- Track next host candidate
                    if first_non_host == -1 and pid ~= player_state.session_host_id then
                        first_non_host = pid
                    end

                    -- Get ped handle from player ID using GET_PLAYER_PED (0x43A66C31C68491C0)
                    local ped_handle = p.ped
                    if not ped_handle or ped_handle == 0 then
                        local ped_result = invoker.call(0x43A66C31C68491C0, pid)
                        if ped_result and ped_result.int then
                            ped_handle = ped_result.int
                        end
                    end

                    local entry = {
                        id = pid,
                        name = p.name or "Unknown",
                        ped = ped_handle,
                        coords = p.coords,
                        friend = p.friend or false,
                        modder = p.modder or false,
                        alive = p.alive ~= false,
                        in_vehicle = p.in_vehicle or false,
                        vehicle = p.vehicle,
                        god = p.god or false,
                        rank = p.rank or 0,
                        rockstar_id = p.rockstar_id or 0,
                        money = p.money or 0,
                        bank = p.bank or 0,
                        wanted = p.wanted or 0,
                        health = p.health or 0,
                        max_health = p.max_health or 100,
                        armor = p.armor or 0,
                        in_interior = false,  -- Will check with native below
                        boss = p.boss or false,
                        in_ceo = p.in_ceo or false,
                        controller = p.controller or false,
                        kd = p.kd or 0,
                        heading = p.heading or 0,
                        ip = p.ip or "N/A",
                        tags = {},
                    }

                    -- Check if player is in an interior using GET_INTERIOR_FROM_ENTITY (0x2107BA504071A6BB)
                    if entry.ped then
                        local interior_id = invoker.call(0x2107BA504071A6BB, entry.ped)
                        if interior_id and interior_id.int and interior_id.int ~= 0 then
                            entry.in_interior = true
                        end
                    end

                    -- Build tags (order matters - important ones first, matching original ClickUI)
                    if entry.id == player_state.my_id then
                        table.insert(entry.tags, {text = "ME", col = C.tag_me})
                    end
                    if entry.friend then
                        table.insert(entry.tags, {text = "Friend", col = C.tag_friend})
                    end
                    if entry.modder then
                        table.insert(entry.tags, {text = "Modder", col = C.tag_modder})
                    end
                    if player_state.spectating_id == entry.id then
                        table.insert(entry.tags, {text = "Spectating", col = C.tag_spectating})
                    end
                    if entry.id == player_state.script_host_id then
                        table.insert(entry.tags, {text = "Script Host", col = C.tag_script_host})
                    end
                    if entry.id == player_state.session_host_id then
                        table.insert(entry.tags, {text = "Session Host", col = C.tag_session_host})
                    end
                    if entry.boss or entry.in_ceo then
                        table.insert(entry.tags, {text = "CEO", col = C.tag_ceo})
                    end
                    if entry.in_interior then
                        table.insert(entry.tags, {text = "Interior", col = C.tag_interior})
                    end
                    if not entry.alive then
                        table.insert(entry.tags, {text = "Dead", col = C.tag_dead})
                    elseif entry.in_vehicle then
                        table.insert(entry.tags, {text = "Vehicle", col = C.tag_vehicle})
                    end
                    if entry.god then
                        table.insert(entry.tags, {text = "God", col = C.tag_god})
                    end
                    -- Check for modded stats
                    if entry.rank >= 1000 or entry.money > 500000000 or entry.bank > 500000000 then
                        table.insert(entry.tags, {text = "Modded", col = C.tag_modded})
                    end
                    if entry.controller then
                        table.insert(entry.tags, {text = "Controller", col = C.tag_controller})
                    end

                    table.insert(player_state.player_list, entry)
                end
            end
        end

        player_state.next_host_id = first_non_host

        -- Sort by ID
        table.sort(player_state.player_list, function(a, b) return a.id < b.id end)

        -- Add Next Host tag after sorting
        for _, p in ipairs(player_state.player_list) do
            if p.id == player_state.next_host_id and p.id ~= player_state.session_host_id then
                table.insert(p.tags, {text = "Next Host", col = C.tag_next_host})
            end
        end
    end

    local function get_selected_player()
        if not player_state.selected_id then return nil end
        for _, p in ipairs(player_state.player_list) do
            if p.id == player_state.selected_id then return p end
        end
        return nil
    end

    -- =========================================================================
    -- NETWORK CRASH HELPERS (Research-Based)
    -- =========================================================================

    -- Get FRESH coordinates for a specific player ID (not from cached list)
    local function get_fresh_player_coords(player_id)
        if not invoker.call(0xB8DFD30D6973E135, player_id).bool then -- NETWORK_IS_PLAYER_ACTIVE
            return nil
        end
        local ped = invoker.call(0x43A66C31C68491C0, player_id).int -- GET_PLAYER_PED
        if not ped or ped == 0 then return nil end
        if not invoker.call(0x7239B21A38F536BA, ped).bool then return nil end -- DOES_ENTITY_EXIST

        local coords = invoker.call(0x3FEF770D40960D5A, ped, false).scr_vec3 -- GET_ENTITY_COORDS
        return {x = coords.x, y = coords.y, z = coords.z}
    end

    local function properly_network_entity(entity)
        if not invoker.call(0x7239B21A38F536BA, entity).bool then return false end -- DOES_ENTITY_EXIST
        if not invoker.call(0x9DE624D2FC4B603F).bool then return false end -- NETWORK_IS_SESSION_STARTED

        -- Register entity as networked
        if not invoker.call(0xC7827959479DCC78, entity).bool then -- NETWORK_GET_ENTITY_IS_NETWORKED
            invoker.call(0x06FAACD625D80CAA, entity) -- NETWORK_REGISTER_ENTITY_AS_NETWORKED

            -- CRITICAL: Wait for registration to complete
            local start = util.get_tick_count()
            while not invoker.call(0xC7827959479DCC78, entity).bool do -- NETWORK_GET_ENTITY_IS_NETWORKED
                if util.get_tick_count() - start > 2000 then
                    return false  -- Increased timeout to 2 seconds
                end
                util.yield()
            end
        end

        -- Get network ID
        local netId = invoker.call(0xA11700682F3AD45C, entity).int -- NETWORK_GET_NETWORK_ID_FROM_ENTITY
        if netId == 0 then return false end

        -- Set ALL critical network flags
        invoker.call(0xE05E81A888FA63C8, netId, true) -- SET_NETWORK_ID_EXISTS_ON_ALL_MACHINES
        invoker.call(0xA8A024587329F36A, netId, invoker.call(0x4F8644AF03D0E0D6).int, true) -- SET_NETWORK_ID_ALWAYS_EXISTS_FOR_PLAYER with PLAYER_ID
        invoker.call(0x299EEB23175895FC, netId, false) -- SET_NETWORK_ID_CAN_MIGRATE

        return true
    end

    local function request_model_with_timeout(hash)
        if not invoker.call(0x35B9E0803292B641, hash).bool or not invoker.call(0xC0296A2EDF545E92, hash).bool then -- IS_MODEL_IN_CDIMAGE, IS_MODEL_VALID
            return false
        end

        invoker.call(0xFA28FE3A6246FC30, hash) -- REQUEST_MODEL
        local start = util.get_tick_count()
        while not invoker.call(0x98A4EB5D89A0C952, hash).bool do -- HAS_MODEL_LOADED
            if util.get_tick_count() - start > 3000 then
                return false  -- Increased timeout to 3 seconds for model loading
            end
            util.yield()
        end
        return true
    end

    -- =========================================================================
    -- PLAYER TAB WIDGETS
    -- =========================================================================

    local function draw_tag(text, x, y, col)
        local s = UI.scale
        local padding = math.floor(4 * s)
        local font_size = math.floor(10 * s)
        local text_w = #text * (font_size * 0.6)  -- Approximate width
        local tag_w = text_w + padding * 2
        local tag_h = math.floor(16 * s)

        draw_rect(x, y, tag_w, tag_h, col, math.floor(3 * s))
        draw_text(text, x + padding, y + math.floor(2 * s), font_size, C.bg)

        return tag_w + math.floor(3 * s)  -- Return width for next tag
    end

    local function selectable(label, is_selected, tags, x, y, w, h)
        local s = UI.scale
        local hover = is_mouse_in(x, y, w, h)
        local clicked = hover and MOUSE.just_pressed

        -- Background
        local bg_col = is_selected and C.selectable_active or (hover and C.selectable_hover or C.selectable_bg)
        draw_rect(x, y, w, h, bg_col, math.floor((UI.widget_rounding or 5) * s))

        -- Selection indicator
        if is_selected then
            draw_rect(x, y, math.floor(3 * s), h, C.accent)
        end

        -- Label
        local font_size = math.floor(12 * s)
        draw_text(label, x + math.floor(10 * s), y + (h - font_size) / 2, font_size, C.text)

        -- Tags (on right side)
        if tags and #tags > 0 then
            local tag_x = x + w - math.floor(10 * s)
            local tag_h = math.floor(16 * s)
            for i = #tags, 1, -1 do
                local tag = tags[i]
                local tw = #tag.text * (math.floor(10 * s) * 0.6) + math.floor(8 * s)
                tag_x = tag_x - tw - math.floor(3 * s)
                draw_tag(tag.text, tag_x, y + (h - tag_h) / 2, tag.col)
            end
        end

        return clicked
    end

    local function sub_tab_bar(tabs, active, x, y, w)
        local s = UI.scale
        local tab_gap = math.floor(8 * s)
        local total_gap = tab_gap * (#tabs - 1)
        local tab_w = (w - total_gap) / #tabs
        local h = UI.subtab_h

        draw_rect(x, y, w, h, C.subtab_bg, math.floor((UI.widget_rounding or 5) * s))

        local new_active = active
        for i, name in ipairs(tabs) do
            local tx = x + (i - 1) * (tab_w + tab_gap)
            local hover = is_mouse_in(tx, y, tab_w, h)
            local is_active = (i == active)

            local inner_pad = math.floor(2 * s)
            if is_active then
                draw_rect(tx + inner_pad, y + inner_pad, tab_w - inner_pad * 2, h - inner_pad * 2, C.subtab_active, math.floor((UI.widget_rounding or 5) * s))
            elseif hover then
                draw_rect(tx + inner_pad, y + inner_pad, tab_w - inner_pad * 2, h - inner_pad * 2, C.subtab_hover, math.floor((UI.widget_rounding or 5) * s))
            end

            draw_text_centered(name, tx, y, tab_w, h, UI.font_small, is_active and C.subtab_text_active or C.subtab_text)

            if hover and MOUSE.just_pressed then
                new_active = i
            end
        end

        return new_active, h + math.floor(6 * s)
    end

    -- Small button for rows
    local function small_button(label, x, y, w, h)
        local s = UI.scale
        local hover = is_mouse_in(x, y, w, h)
        local pressed = hover and MOUSE.pressed
        local clicked = hover and MOUSE.just_pressed

        -- Button background with states
        local bg_col = C.widget_bg
        local text_offset = 0
        if pressed then
            -- Pressed state: darker (widget_bg is 40,40,46 so pressed is ~80%)
            bg_col = color(32, 32, 37, 255)
            text_offset = math.floor(1 * s)
        elseif hover then
            -- Hover state
            bg_col = C.widget_hover
        end

        draw_rect(x, y, w, h, bg_col, math.floor((UI.widget_rounding or 5) * s))

        -- Accent highlight on top when hovering
        if hover then
            draw_rect(x, y, w, math.floor(2 * s), C.accent, math.floor(5 * s))
        end

        -- Text with offset when pressed
        draw_text_centered(label, x, y + text_offset, w, h, UI.font_small, C.text)

        return clicked
    end

    -- Modern inline toggle switch (replaces all inline checkboxes)
    local function inline_toggle(label, value, x, y, w, h)
        local s = UI.scale
        local hover = is_mouse_in(x, y, w, h)

        -- Background with hover
        draw_rect(x, y, w, h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))

        -- Label on left
        draw_text(label, x + math.floor(10 * s), y + (h - UI.font_small) / 2, UI.font_small, C.text)

        -- Toggle switch on right (pill shape)
        local toggle_w = math.floor(40 * s)
        local toggle_h = math.floor(20 * s)
        local toggle_x = x + w - toggle_w - math.floor(8 * s)
        local toggle_y = y + (h - toggle_h) / 2

        -- Toggle track
        local track_col = value and C.accent or C.checkbox_off
        draw_rect(toggle_x, toggle_y, toggle_w, toggle_h, track_col, math.floor(10 * s))

        -- Toggle knob
        local knob_size = math.floor(16 * s)
        local knob_pad = math.floor(2 * s)
        local knob_x = value and (toggle_x + toggle_w - knob_size - knob_pad) or (toggle_x + knob_pad)
        local knob_y = toggle_y + knob_pad
        draw_rect(knob_x, knob_y, knob_size, knob_size, color(255, 255, 255, 255), math.floor(8 * s))

        -- Click handler
        if hover and MOUSE.just_pressed then
            value = not value
        end

        return value
    end

    -- Improved RGB/Value slider with tooltip and better visuals
    local function improved_slider(label, value, min, max, x, y, w, h, color_fill)
        local s = UI.scale
        local hover = is_mouse_in(x, y, w, h)

        -- Track
        local track_y = y + math.floor(h * 0.6)
        local track_h = math.floor(h * 0.4)
        draw_rect(x, track_y, w, track_h, C.widget_bg, math.floor((UI.widget_rounding or 5) * s))

        -- Fill
        local pct = (value - min) / (max - min)
        if pct > 0 then
            draw_rect(x, track_y, w * pct, track_h, color_fill or C.accent, math.floor((UI.widget_rounding or 5) * s))
        end

        -- Thumb indicator
        local thumb_x = x + (w * pct) - math.floor(3 * s)
        local thumb_w = math.floor(6 * s)
        draw_rect(thumb_x, track_y - math.floor(2 * s), thumb_w, track_h + math.floor(4 * s), color(255, 255, 255, 255), math.floor(3 * s))

        -- Min/Max labels
        draw_text(tostring(min), x, track_y + track_h + math.floor(2 * s), UI.font_small - 2, C.text_dim)
        draw_text(tostring(max), x + w - math.floor(16 * s), track_y + track_h + math.floor(2 * s), UI.font_small - 2, C.text_dim)

        -- Drag
        if hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - x) / w))
            value = math.floor(min + (max - min) * mouse_pct)

            -- Tooltip while dragging
            local tooltip_x = MOUSE.x - math.floor(18 * s)
            local tooltip_y = MOUSE.y - math.floor(28 * s)
            local tooltip_w = math.floor(36 * s)
            local tooltip_h = math.floor(20 * s)
            draw_rect(tooltip_x, tooltip_y, tooltip_w, tooltip_h, color(0, 0, 0, 240), math.floor(4 * s))
            draw_text(tostring(value), tooltip_x + math.floor(8 * s), tooltip_y + math.floor(3 * s), UI.font_small, color(255, 255, 255, 255))
        end

        return value
    end

    -- Recovery slider (for Self > Recovery tab)
    local function recovery_slider(label, value, min, max, x, y, w, s, suffix)
        local slider_h = math.floor(40 * s)
        local track_h = math.floor(8 * s)
        local thumb_size = math.floor(16 * s)

        -- Label
        draw_text(label, x, y, UI.font_small, C.text_dim)

        -- Value display (in accent color)
        local value_text = string.format("%.0f%s", value, suffix or "")
        local value_w = #value_text * UI.font_small * 0.6
        draw_text(value_text, x + w - value_w, y, UI.font_small, C.accent)

        -- Track background
        local track_y = y + math.floor(18 * s)
        draw_rect(x, track_y, w, track_h, C.checkbox_off, math.floor((UI.widget_rounding or 5) * s))

        -- Fill on track
        local percent = (value - min) / (max - min)
        if percent > 0 then
            draw_rect(x, track_y, w * percent, track_h, C.accent, math.floor((UI.widget_rounding or 5) * s))
        end

        -- Min/Max labels
        draw_text(tostring(min), x, track_y + track_h + math.floor(3 * s), UI.font_small - 2, C.text_dim)
        local max_label = tostring(max) .. (suffix or "")
        draw_text(max_label, x + w - math.floor(#max_label * 7), track_y + track_h + math.floor(3 * s), UI.font_small - 2, C.text_dim)

        -- Thumb
        local thumb_x = x + math.floor(percent * (w - thumb_size))
        local thumb_y = track_y - (thumb_size - track_h) / 2

        local hover = is_mouse_in(x, track_y - thumb_size/2, w, thumb_size + math.floor(6 * s))
        draw_rect(thumb_x, thumb_y, thumb_size, thumb_size, hover and color(255, 255, 255, 255) or C.accent, math.floor(thumb_size / 2))

        -- Dragging with tooltip
        if hover and MOUSE.pressed then
            local mouse_percent = math.max(0, math.min(1, (MOUSE.x - x) / w))
            value = min + mouse_percent * (max - min)
            value = math.floor(value + 0.5)

            -- Tooltip while dragging
            local tooltip_x = MOUSE.x - math.floor(22 * s)
            local tooltip_y = MOUSE.y - math.floor(30 * s)
            local tooltip_w = math.floor(48 * s)
            local tooltip_h = math.floor(20 * s)
            draw_rect(tooltip_x, tooltip_y, tooltip_w, tooltip_h, color(0, 0, 0, 240), math.floor(4 * s))
            draw_text(string.format("%.0f%s", value, suffix or ""), tooltip_x + math.floor(6 * s), tooltip_y + math.floor(3 * s), UI.font_small, color(255, 255, 255, 255))
        end

        return value, slider_h
    end

    -- Text input widget with keyboard support (like Spawn tab)
    local function text_input_box(label, text_state, is_focused, x, y, w, h)
        local s = UI.scale
        local hover = is_mouse_in(x, y, w, h)
        local clicked = hover and MOUSE.just_pressed

        -- Handle keyboard input when focused (EXACTLY like Spawn tab)
        if is_focused and input and input.key then
            -- Backspace
            if input.key(0x08).just_pressed then
                if #text_state > 0 then
                    text_state = text_state:sub(1, -2)
                end
            end

            -- Numbers 0-9
            for code = 0x30, 0x39 do
                if input.key(code).just_pressed then
                    text_state = text_state .. string.char(code)
                end
            end

            -- Letters A-Z (with shift support for capitals)
            local shift_pressed = input.key(0x10).pressed  -- VK_SHIFT
            for code = 0x41, 0x5A do
                if input.key(code).just_pressed then
                    if shift_pressed then
                        text_state = text_state .. string.char(code)  -- Uppercase
                    else
                        text_state = text_state .. string.char(code):lower()  -- Lowercase
                    end
                end
            end

            -- Space
            if input.key(0x20).just_pressed then
                text_state = text_state .. " "
            end

            -- Special characters
            if input.key(0xBD).just_pressed then text_state = text_state .. "-" end  -- Minus/Dash
            if input.key(0xBB).just_pressed then text_state = text_state .. "=" end  -- Equals
            if input.key(0xBA).just_pressed then text_state = text_state .. ":" end  -- Semicolon
            if input.key(0xDE).just_pressed then text_state = text_state .. "'" end  -- Quote
            if input.key(0xBC).just_pressed then text_state = text_state .. "," end  -- Comma
            if input.key(0xBE).just_pressed then text_state = text_state .. "." end  -- Period
            if input.key(0xBF).just_pressed then text_state = text_state .. "/" end  -- Slash
            if input.key(0xDB).just_pressed then text_state = text_state .. "[" end  -- Left bracket
            if input.key(0xDD).just_pressed then text_state = text_state .. "]" end  -- Right bracket
            if input.key(0xDC).just_pressed then text_state = text_state .. "\\" end  -- Backslash
            if input.key(0x31).just_pressed then text_state = text_state .. "!" end  -- Exclamation (Shift+1)
        end

        -- Background
        local bg_col = is_focused and C.accent or (hover and C.widget_hover or C.widget_bg)
        draw_rect(x, y, w, h, bg_col, math.floor((UI.widget_rounding or 5) * s))

        -- Label
        local label_x = x + math.floor(8 * s)
        draw_text(label .. ":", label_x, y + math.floor(4 * s), math.floor(10 * s), is_focused and C.bg or C.text_dim)

        -- Text content
        local text_y = y + math.floor(18 * s)
        local display_text = text_state
        if is_focused then
            display_text = display_text .. "_"  -- Cursor
        end
        draw_text(display_text, label_x, text_y, UI.font_small, is_focused and C.bg or C.text)

        -- Click to focus/unfocus
        if clicked then
            is_focused = not is_focused
            if is_focused then
                safe_toast("Type your message - Click again to finish")
            else
                safe_toast("Message set!")
            end
        end

        return text_state, is_focused, clicked
    end

