    -- Get rainbow color based on time
    local function get_rainbow_color(speed)
        local time = os.clock() * speed
        local r = math.floor((math.sin(time) + 1) * 127.5)
        local g = math.floor((math.sin(time + 2.094) + 1) * 127.5)
        local b = math.floor((math.sin(time + 4.188) + 1) * 127.5)
        return r, g, b
    end

    -- Get color by mode
    local function get_color_by_mode(mode, rainbow_speed)
        if mode == 1 then return 255, 255, 255  -- White
        elseif mode == 2 then return get_rainbow_color(rainbow_speed or 1.0)  -- Rainbow
        elseif mode == 3 then return 255, 0, 0  -- Red
        elseif mode == 4 then return 0, 255, 0  -- Green
        elseif mode == 5 then return 0, 0, 255  -- Blue
        elseif mode == 6 then return 255, 255, 0  -- Yellow
        elseif mode == 7 then return 0, 255, 255  -- Cyan
        elseif mode == 8 then return 255, 0, 255  -- Pink
        end
        return 255, 255, 255
    end

