                    -- Make invisible first
                    invoker.call(0xE3B6097CC25AA69E, self_state.preview_ped, false, false) -- SET_ENTITY_VISIBLE
                    -- Teleport clone far underground (safer than DELETE_ENTITY, prevents crashes)
                    invoker.call(0x06843DA7060A026B, self_state.preview_ped, 0.0, 0.0, -1000.0, false, false, false, false) -- SET_ENTITY_COORDS
                end
            end)
            self_state.preview_ped = nil
