    -- =========================================================================
    -- AIMBOT V2 - Based on working GL Prediction approach
    -- =========================================================================
    -- Uses SET_FIRST_PERSON_SHOOTER_CAMERA_HEADING/PITCH (proven working natives)
    -- Calculates heading from CAMERA POSITION to target (not rotation-based)
    -- Heading is relative to ENTITY heading (same method as reference script)
    -- =========================================================================

    util.create_thread(function()
        while true do
            if self_state.aimbot_enabled then
                pcall(function()
                    -- Get local player
                    local me = players.me()
                    if not me or not me.ped or not me.coords then return end

                    -- No recoil and perfect accuracy when aimbot enabled
                    invoker.call(0x4A7B48FDE25E3700, me.id, 0.0)       -- SET_PLAYER_WEAPON_RECOIL_MULTIPLIER (0 = no recoil)
                    invoker.call(0x7AEFB85C1D49DEB6, me.ped, 100)      -- SET_PED_ACCURACY (100 = max accuracy, min spread)
                    invoker.call(0x0EF93E9F3D08C178, true)              -- STOP_GAMEPLAY_CAM_SHAKING
                    invoker.call(0xA87E00932DB4D85D, 0.0)               -- SET_GAMEPLAY_CAM_SHAKE_AMPLITUDE (0 = no shake)

                    -- Check if aiming OR shooting (keep lock active while firing)
                    local is_aiming = invoker.call(0xF3A21BCD95725A4A, 0, 25) -- IS_CONTROL_PRESSED (right mouse)
                    local is_shooting = invoker.call(0x34616828CD07F1A1, me.ped) -- IS_PED_SHOOTING

                    if (not is_aiming or not is_aiming.bool) and (not is_shooting or not is_shooting.bool) then
                        self_state.aimbot_locked_target = nil
                        return
                    end

                    -- Get camera position (NOT rotation - this is key)
                    local cam_coord_result = invoker.call(0x14D6F5678D8F1B37) -- GET_GAMEPLAY_CAM_COORD
                    if not cam_coord_result then return end
                    local cam_coords = cam_coord_result.scr_vec3 or cam_coord_result.vec3
                    if not cam_coords then return end

                    -- Get entity heading (our player's heading)
                    local self_heading = invoker.call(0xE83D4F9BA2A38914, me.ped).float -- GET_ENTITY_HEADING
                    if not self_heading then return end

                    -- Find closest player to crosshair
                    local best_target = nil
                    local best_distance = math.huge

                    for _, player in ipairs(players.list()) do
                        if player and player.ped and player.ped ~= me.ped and player.coords and player.connected and player.alive then

                            -- Distance check
                            local dx = player.coords.x - me.coords.x
                            local dy = player.coords.y - me.coords.y
                            local dz = player.coords.z - me.coords.z
                            local distance_3d = math.sqrt(dx*dx + dy*dy + dz*dz)

                            if distance_3d > self_state.aimbot_max_range then
                                goto next_player
                            end

                            -- Wall check (line of sight)
                            if self_state.aimbot_wall_check then
                                local los_check = invoker.call(0xFCDFF7B72D23A1AC, me.ped, player.ped, 17) -- HAS_ENTITY_CLEAR_LOS_TO_ENTITY
                                if not los_check or not los_check.bool then
                                    goto next_player
                                end
                            end

                            -- Get target bone coords
                            local bone_id = 31086 -- Head
                            if self_state.aimbot_bone_target == 2 then bone_id = 39317 -- Neck
                            elseif self_state.aimbot_bone_target == 3 then bone_id = 24818 end -- Chest

                            local bone_x, bone_y, bone_z = PED.GET_PED_BONE_COORDS(player.ped, bone_id, 0.0, 0.0, 0.0)
                            if not bone_x then goto next_player end

                            -- Calculate heading from CAMERA to target (same as reference script)
                            local target_vec_x = bone_x - cam_coords.x
                            local target_vec_y = bone_y - cam_coords.y
                            local target_vec_z = bone_z - cam_coords.z

                            local camera_heading = math.atan2(target_vec_x, target_vec_y) * (180.0 / math.pi)

                            -- Normalize heading same way as reference
                            if camera_heading >= 0.0 and camera_heading <= 180.0 then
                                camera_heading = 360.0 - camera_heading
                            elseif camera_heading <= 0.0 and camera_heading >= -180.0 then
                                camera_heading = -camera_heading
                            end

                            -- Heading difference relative to entity heading
                            local heading_diff = camera_heading - self_heading

                            -- Calculate pitch angle
                            local horiz_dist = math.sqrt(target_vec_x * target_vec_x + target_vec_y * target_vec_y)
                            local pitch_angle = math.atan2(target_vec_z, horiz_dist) * (180.0 / math.pi)

                            -- Check if within FOV (use heading_diff as angular distance)
                            local fov_limit_degrees = self_state.aimbot_fov / 13.33
                            local angular_dist = math.abs(heading_diff)
                            if angular_dist > 180 then angular_dist = 360 - angular_dist end

                            if angular_dist <= fov_limit_degrees and distance_3d < best_distance then
                                best_distance = distance_3d
                                best_target = {
                                    ped = player.ped,
                                    name = player.name,
                                    heading_diff = heading_diff,
                                    pitch_angle = pitch_angle
                                }
                            end

                            ::next_player::
                        end
                    end

                    -- Lock onto target
                    self_state.aimbot_locked_target = best_target

                    if best_target then
                        -- RECALCULATE target angles fresh every time to account for any movement
                        -- Get fresh bone coords
                        local bone_id = 31086 -- Head
                        if self_state.aimbot_bone_target == 2 then bone_id = 39317 -- Neck
                        elseif self_state.aimbot_bone_target == 3 then bone_id = 24818 end -- Chest

                        local bone_x, bone_y, bone_z = PED.GET_PED_BONE_COORDS(best_target.ped, bone_id, 0.0, 0.0, 0.0)

                        if bone_x and cam_coords and self_heading then
                            -- Fresh calculation of angles to target
                            local target_vec_x = bone_x - cam_coords.x
                            local target_vec_y = bone_y - cam_coords.y
                            local target_vec_z = bone_z - cam_coords.z

                            local camera_heading = math.atan2(target_vec_x, target_vec_y) * (180.0 / math.pi)

                            -- Normalize heading
                            if camera_heading >= 0.0 and camera_heading <= 180.0 then
                                camera_heading = 360.0 - camera_heading
                            elseif camera_heading <= 0.0 and camera_heading >= -180.0 then
                                camera_heading = -camera_heading
                            end

                            local heading_diff = camera_heading - self_heading
                            local horiz_dist = math.sqrt(target_vec_x * target_vec_x + target_vec_y * target_vec_y)
                            local pitch_angle = math.atan2(target_vec_z, horiz_dist) * (180.0 / math.pi)

                            -- Apply camera lock multiple times per frame with FRESH angles
                            for i = 1, 5 do
                                invoker.call(0xB4EC2312F4E5B1F1, 1.0 * heading_diff)         -- SET_GAMEPLAY_CAM_RELATIVE_HEADING
                                invoker.call(0x6D0858B8EDFD2B7D, 1.0 * pitch_angle, 1.0)     -- SET_GAMEPLAY_CAM_RELATIVE_PITCH
                                invoker.call(0x103991D4A307D472, 1.0 * heading_diff)          -- SET_FIRST_PERSON_SHOOTER_CAMERA_HEADING
                                invoker.call(0x759E13EBC1C15C5A, 1.0 * pitch_angle)           -- SET_FIRST_PERSON_SHOOTER_CAMERA_PITCH
                            end
                        end
                    end
                end)
                util.yield(0)
            else
                -- Reset recoil and accuracy when aimbot disabled
                pcall(function()
                    local me = players.me()
                    if me and me.id and me.ped then
                        invoker.call(0x4A7B48FDE25E3700, me.id, 1.0)      -- SET_PLAYER_WEAPON_RECOIL_MULTIPLIER (1.0 = normal)
                        invoker.call(0x7AEFB85C1D49DEB6, me.ped, 50)     -- SET_PED_ACCURACY (50 = default)
                    end
                end)
                self_state.aimbot_locked_target = nil
                util.yield(250)
            end
        end
    end)

    -- FOV Circle Renderer
    util.create_thread(function()
        while true do
            if self_state.aimbot_enabled and self_state.aimbot_show_fov then
                pcall(function()
                    local res = game.resolution()
                    local cx = res.x / 2
                    local cy = res.y / 2
                    local radius = self_state.aimbot_fov

                    -- Red when locked, white when scanning
                    local circle_color = self_state.aimbot_locked_target and color(255, 50, 50, 255) or color(255, 255, 255, 180)

                    -- Draw circle
                    local segments = 64
                    for i = 0, segments - 1 do
                        local a1 = (i / segments) * math.pi * 2
                        local a2 = ((i + 1) / segments) * math.pi * 2

                        local x1 = cx + math.cos(a1) * radius
                        local y1 = cy + math.sin(a1) * radius
                        local x2 = cx + math.cos(a2) * radius
                        local y2 = cy + math.sin(a2) * radius

                        gui.line(vec2(x1, y1), vec2(x2, y2), 2.0, circle_color)
                    end
                end)
                util.yield(0)
            else
                util.yield(250)
            end
        end
    end)

    -- Clothing Persistence Thread - Prevents game from removing clothing items
    util.create_thread(function()
        while true do
            if me and me.ped then
                pcall(function()
                    local ped = me.ped

                    -- Component mapping: {component_id, style_var, tex_var}
                    local components = {
                        {1, "mask_style", "mask_tex"},
                        {2, "hair_style", "hair_tex"},
                        {3, "torso_style", "torso_tex"},
                        {4, "pants_style", "pants_tex"},
                        {5, "bag_style", "bag_tex"},           -- Bags & Parachutes - needs persistence
                        {6, "shoes_style", "shoes_tex"},
                        {7, "accessories_style", "accessories_tex"},
                        {8, "undershirt_style", "undershirt_tex"},
                        {9, "armor_style", "armor_tex"},
                        {10, "decals_style", "decals_tex"},
                        {11, "tops_style", "tops_tex"}
                    }

                    -- Check and restore components
                    for _, comp in ipairs(components) do
                        local comp_id = comp[1]
                        local style_var = comp[2]
                        local tex_var = comp[3]
                        local saved_style = math.floor(self_state[style_var])
                        local saved_tex = math.floor(self_state[tex_var])

                        -- Get current values from game
                        local current_style = invoker.call(0x67F3780DD425D4FC, ped, comp_id)
                        local current_tex = invoker.call(0x04A355E041E004E6, ped, comp_id)

                        if current_style and current_tex then
                            current_style = current_style.int or 0
                            current_tex = current_tex.int or 0

                            -- If game changed it, restore saved value
                            if current_style ~= saved_style or current_tex ~= saved_tex then
                                invoker.call(0x262B14F48D29DE80, ped, comp_id, saved_style, saved_tex, 0)
                            end
                        end
                    end

                    -- Prop mapping: {prop_id, style_var, tex_var}
                    local props = {
                        {0, "hat_style", "hat_tex"},           -- Hats/Helmets - needs persistence
                        {1, "glasses_style", "glasses_tex"},
                        {2, "ears_style", "ears_tex"},
                        {6, "watches_style", "watches_tex"},
                        {7, "bracelets_style", "bracelets_tex"}
                    }

                    -- Check and restore props (FIXED: Never remove props if saved state is -1)
                    for _, prop in ipairs(props) do
                        local prop_id = prop[1]
                        local style_var = prop[2]
                        local tex_var = prop[3]
                        local saved_style = math.floor(self_state[style_var])
                        local saved_tex = math.floor(self_state[tex_var])

                        -- SKIP if saved state is -1 (don't enforce "no prop" - let user wear whatever)
                        if saved_style >= 0 then
                            -- Get current values from game
                            local current_style = invoker.call(0x898CC20EA75BACD8, ped, prop_id)

                            if current_style then
                                current_style = current_style.int or -1

                                -- Only restore if we have a saved prop (>= 0)
                                if current_style ~= saved_style then
                                    -- Restore prop
                                    invoker.call(0x93376B65A266EB5F, ped, prop_id, saved_style, saved_tex, true, 0)
                                else
                                    -- Style matches but check texture too
                                    local current_tex = invoker.call(0xE131A28626F81AB2, ped, prop_id)
                                    current_tex = (current_tex and current_tex.int) or 0

                                    if current_tex ~= saved_tex then
                                        invoker.call(0x93376B65A266EB5F, ped, prop_id, saved_style, saved_tex, true, 0)
                                    end
                                end
                            end
                        end
                        -- If saved_style == -1, do nothing (don't clear, don't restore)
                    end
                end)
            end
            util.yield(100) -- Check every 100ms (10 times per second)
        end
    end)

    -- Money Loop - MULTIPLE METHODS FOR TESTING
    util.create_thread(function()
        money_debug_log("Money loop thread started")

        while true do
            if self_state.money_loop_active then
                -- Track start time when loop is first activated
                if self_state.money_loop_start_time == 0 then
                    self_state.money_loop_start_time = os.time()
                    money_debug_log("Money loop activated - METHOD: game.basket_transaction")
                end

                -- Calculate elapsed time in seconds
                local elapsed = os.time() - self_state.money_loop_start_time
                local interval = 5000  -- Default: 5 seconds

                -- After 15 minutes (900 seconds), switch to 10 second intervals
                if elapsed >= 900 then
                    interval = 10000  -- 10 seconds
                end

                -- Check current balance
                local wallet_before = 0
                local bank_before = 0
                pcall(function()
                    if account and account.stats then
                        wallet_before = account.stats("MPPLY_WALLET_BALANCE").int64 or 0
                        bank_before = account.stats("BANK_BALANCE").int64 or 0
                        money_debug_log(string.format("Before: Wallet=$%d, Bank=$%d", wallet_before, bank_before))
                    end
                end)

                -- Choose method based on selection
                if self_state.money_loop_method == 1 then
                    -- METHOD: Script Globals (from money (1).lua)
                    local success, err = pcall(function()
                        money_debug_log("Using Script Globals method (Enhanced Global 1970025)")

                        if script and script.globals then
                            local enhanced_global = script.globals(1970025)
                            if enhanced_global then
                                enhanced_global.int32 = 1
                                money_debug_log("Set enhanced_global(1970025) to 1 - triggers $500K")
                                util.yield(500)
                            else
                                money_debug_log("ERROR: Could not access script globals")
                            end
                        else
                            money_debug_log("ERROR: script.globals not available")
                        end
                    end)

                    if not success then
                        money_debug_log("Script Globals method FAILED: " .. tostring(err))
                    else
                        money_debug_log("Script Globals method executed")
                    end
                else
                    -- METHOD: Basket Transaction (Default)
                    local success, err = pcall(function()
                    money_debug_log("METHOD 1: Trying game.basket_transaction with CORRECT format")

                    -- Check if transaction busy
                    if game and game.is_transaction_busy and game.is_transaction_busy() then
                        money_debug_log("Transaction is busy, skipping")
                        return
                    end

                    local category = 1474183246
                    local action = 1445302971
                    local destination = 1  -- transactions.json says target=1 (wallet)

                    -- CRITICAL: Items must be POSITIONAL ARRAY not named fields!
                    -- Format: { id, extra_inventory_id, price, stat, quantity }
                    -- From transactions.json: id=-1027218631, inventory=-1, price=180000, stat=0, count=1
                    local items = {
                        { -1027218631, -1, 180000, 0, 1 }
                    }

                    if game and game.basket_transaction then
                        money_debug_log(string.format("Calling basket_transaction: cat=%d, act=%d, dest=%d, item=[%d, %d, %d, %d, %d]",
                            category, action, destination, items[1][1], items[1][2], items[1][3], items[1][4], items[1][5]))
                        game.basket_transaction(category, action, destination, items)
                        money_debug_log("basket_transaction executed")

                        -- Wait a bit for transaction to process
                        util.yield(500)

                        -- Check balance after
                        local wallet_after = 0
                        local bank_after = 0
                        pcall(function()
                            if account and account.stats then
                                wallet_after = account.stats("MPPLY_WALLET_BALANCE").int64 or 0
                                bank_after = account.stats("BANK_BALANCE").int64 or 0
                                money_debug_log(string.format("After: Wallet=$%d (+%d), Bank=$%d (+%d)",
                                    wallet_after, wallet_after - wallet_before,
                                    bank_after, bank_after - bank_before))
                            end
                        end)
                    else
                        money_debug_log("ERROR: game.basket_transaction not available")
                    end
                end)

                if not success then
                    money_debug_log("METHOD 1 FAILED: " .. tostring(err))

                    -- METHOD 2: Native transaction calls (fallback)
                    local success2, err2 = pcall(function()
                        money_debug_log("METHOD 2: Trying native transaction calls")

                        local transaction_id = -1027218631
                        local category = 1474183246
                        local action = 1445302971
                        local amount = 180000

                        invoker.call(0x279F08B1A4B29B7E, transaction_id, category, action, 1)
                        money_debug_log("Called NET_GAMESERVER_BASKET_START")

                        invoker.call(0x3C5FD37B5499582E, transaction_id, category, transaction_id, action, amount, 1)
                        money_debug_log("Called NET_GAMESERVER_BEGIN_SERVICE")

                        invoker.call(0xE2A99A9B524BEFFF, transaction_id)
                        money_debug_log("Called NET_GAMESERVER_END_SERVICE")

                        invoker.call(0x39BE7CEA8D9CC8E6, transaction_id)
                        money_debug_log("Called NET_GAMESERVER_CHECKOUT_START")
                    end)

                    if not success2 then
                        money_debug_log("METHOD 2 FAILED: " .. tostring(err2))

                        -- METHOD 3: Direct stat modification (last resort)
                        local success3, err3 = pcall(function()
                            money_debug_log("METHOD 3: Trying direct stat modification")

                            local bank_stat = account.stats("BANK_BALANCE")
                            local current_bank = bank_stat.int64
                            money_debug_log("Current bank: " .. tostring(current_bank))

                            bank_stat.int64 = current_bank + 180000
                            money_debug_log("Set bank to: " .. tostring(current_bank + 180000))
                        end)

                        if not success3 then
                            money_debug_log("METHOD 3 FAILED: " .. tostring(err3))
                        else
                            money_debug_log("METHOD 3 SUCCESS")
                        end
                    else
                        money_debug_log("METHOD 2 SUCCESS")
                    end
                    else
                        money_debug_log("METHOD 1 SUCCESS")
                    end
                end

                util.yield(interval)
            else
                -- Reset start time when loop is stopped
                if self_state.money_loop_start_time ~= 0 then
                    money_debug_log("Money loop deactivated")
                    self_state.money_loop_start_time = 0
                end
                util.yield(1000)
            end
        end
    end)

