    -- Visual Effect Auras Background Thread (WORKING EFFECTS ONLY)
    util.create_thread(function()
        local light_angle = 0

        while true do
            local me = players and players.me and players.me()
            if me and me.ped then
                pcall(function()
                    local pos = invoker.call(0x3FEF770D40960D5A, me.ped, false).scr_vec3

                    -- Rainbow Lights Circle (NETWORKED - Other players can see!)
                    if esp_state.aura_rainbow_lights then
                        light_angle = (light_angle + 5) % 360

                        -- Local lights for you (bright and clear)
                        for i = 0, 3 do
                            local angle = math.rad(light_angle + (i * 90))
                            local dist = 3.0
                            local lx = pos.x + math.cos(angle) * dist
                            local ly = pos.y + math.sin(angle) * dist
                            local lz = pos.z + 1.0

                            -- Calculate rainbow color
                            local hue = (light_angle + (i * 90)) % 360
                            local r, g, b = 255, 0, 0
                            if hue < 60 then
                                r, g, b = 255, hue * 4.25, 0
                            elseif hue < 120 then
                                r, g, b = 255 - ((hue - 60) * 4.25), 255, 0
                            elseif hue < 180 then
                                r, g, b = 0, 255, (hue - 120) * 4.25
                            elseif hue < 240 then
                                r, g, b = 0, 255 - ((hue - 180) * 4.25), 255
                            elseif hue < 300 then
                                r, g, b = (hue - 240) * 4.25, 0, 255
                            else
                                r, g, b = 255, 0, 255 - ((hue - 300) * 4.25)
                            end

                            -- DRAW_LIGHT_WITH_RANGE (for you)
                            invoker.call(0xF49E9A9716A04595, lx, ly, lz, r, g, b, 5.0, 1.0)
                        end

                        -- Networked sparkle particles (for other players) - spawn every 15 degrees
                        if light_angle % 15 == 0 then
                            invoker.call(0x6C38AF3693A69A91, "scr_indep_fireworks")  -- REQUEST_NAMED_PTFX_ASSET
                            if invoker.call(0x8702416E512EC454, "scr_indep_fireworks").bool then
                                invoker.call(0x0D53A3B8DA0809D2, "scr_indep_fireworks", 1.0)  -- USE_PARTICLE_FX_ASSET

                                for i = 0, 3 do
                                    local angle = math.rad(light_angle + (i * 90))
                                    local dist = 3.0
                                    local px = pos.x + math.cos(angle) * dist
                                    local py = pos.y + math.sin(angle) * dist
                                    local pz = pos.z + 1.0

                                    -- START_NETWORKED_PARTICLE_FX_NON_LOOPED_AT_COORD (synced to other players!)
                                    invoker.call(0xF56B8137DF10135D, "scr_indep_firework_sparkle_spawn", px, py, pz, 0.0, 0.0, 0.0, 1.5, false, false, false)
                                end
                            end
                        end
                    end

                    -- Spotlight From Above (MUST be drawn every frame)
                    if esp_state.aura_spotlight then
                        -- DRAW_SPOT_LIGHT (x, y, z, dirX, dirY, dirZ, r, g, b, distance, brightness, hardness, radius, falloff)
                        invoker.call(0xD0F64B265C8C8B33, pos.x, pos.y, pos.z + 10.0, 0.0, 0.0, -1.0, 255, 255, 255, 20.0, 10.0, 0.0, 5.0, 1.0)
                    end

                    -- Pulsing Light (single light that pulses in size and intensity)
                    if esp_state.aura_pulsing then
                        local pulse = math.abs(math.sin(light_angle * 0.05)) * 10.0 + 5.0
                        local intensity = math.abs(math.sin(light_angle * 0.05)) * 0.5 + 0.5
                        -- Cyan pulsing light
                        invoker.call(0xF49E9A9716A04595, pos.x, pos.y, pos.z + 2.0, 0, 255, 255, pulse, intensity)
                    end

                    -- Ground Ring (circle of lights on the ground)
                    if esp_state.aura_ground_ring then
                        for i = 0, 11 do
                            local angle = math.rad((light_angle + (i * 30)) % 360)
                            local dist = 2.5
                            local lx = pos.x + math.cos(angle) * dist
                            local ly = pos.y + math.sin(angle) * dist
                            local lz = pos.z - 0.9  -- On the ground
                            -- White ground lights
                            invoker.call(0xF49E9A9716A04595, lx, ly, lz, 255, 255, 255, 3.0, 1.0)
                        end
                    end

                    -- Light Pillars (vertical beams around the player)
                    if esp_state.aura_pillars then
                        for i = 0, 3 do
                            local angle = math.rad(i * 90)
                            local dist = 3.0
                            local lx = pos.x + math.cos(angle) * dist
                            local ly = pos.y + math.sin(angle) * dist
                            -- Draw multiple lights vertically to create pillar effect
                            for h = 0, 4 do
                                local lz = pos.z + (h * 1.5) - 1.0
                                -- Blue pillars
                                invoker.call(0xF49E9A9716A04595, lx, ly, lz, 100, 150, 255, 4.0, 0.8)
                            end
                        end
                    end

                    -- Color Wave (wave pattern with colors)
                    if esp_state.aura_color_wave then
                        for i = 0, 7 do
                            local angle = math.rad((light_angle * 2 + (i * 45)) % 360)
                            local dist = 2.0 + math.sin(light_angle * 0.1 + i) * 0.5
                            local lx = pos.x + math.cos(angle) * dist
                            local ly = pos.y + math.sin(angle) * dist
                            local lz = pos.z + 0.5

                            -- Each light has a different color phase
                            local hue = ((light_angle * 3) + (i * 45)) % 360
                            local r, g, b = 255, 0, 0
                            if hue < 60 then
                                r, g, b = 255, hue * 4.25, 0
                            elseif hue < 120 then
                                r, g, b = 255 - ((hue - 60) * 4.25), 255, 0
                            elseif hue < 180 then
                                r, g, b = 0, 255, (hue - 120) * 4.25
                            elseif hue < 240 then
                                r, g, b = 0, 255 - ((hue - 180) * 4.25), 255
                            elseif hue < 300 then
                                r, g, b = (hue - 240) * 4.25, 0, 255
                            else
                                r, g, b = 255, 0, 255 - ((hue - 300) * 4.25)
                            end

                            invoker.call(0xF49E9A9716A04595, lx, ly, lz, r, g, b, 4.0, 0.7)
                        end
                    end

                    -- Timecycle Screen Effects
                    if esp_state.timecycle_enabled and esp_state.timecycle_modifier and esp_state.timecycle_modifier ~= "None" then
                        pcall(function()
                            invoker.call(0x2C933ABF17A1DF41, esp_state.timecycle_modifier)  -- SET_TIMECYCLE_MODIFIER
                            if esp_state.timecycle_strength then
                                invoker.call(0x82E7FFCD5B2326B3, esp_state.timecycle_strength)  -- SET_TIMECYCLE_MODIFIER_STRENGTH
                            end
                        end)
                    else
                        -- Clear timecycle when disabled or set to "None"
                        pcall(function()
                            invoker.call(0x0F07E7745A236711)  -- CLEAR_TIMECYCLE_MODIFIER
                        end)
                    end
                end)
            end
            util.yield(0)  -- Run every frame for lights
        end
    end)

    -- ========== OUTFIT SAVE/LOAD SYSTEM (JSON FILES) ==========
    -- Helper: Save current outfit to JSON file
    local function save_current_outfit(name)
        if not name or name == "" then
            safe_toast("Please enter an outfit name")
            return
        end

        -- Get player ped (EXACTLY like vehicle save)
        local ped = invoker.call(0x43A66C31C68491C0, -1).int  -- PLAYER_PED_ID
        if not ped or ped == 0 then
            safe_toast("Failed to get player")
            return
        end

        -- Collect all outfit data
        local outfit_data = {
            name = name,
            created = os.date("%Y-%m-%d %H:%M:%S"),
            components = {},
            props = {}
        }

        -- Save all 12 components (0-11)
        for comp_id = 0, 11 do
            local drawable = invoker.call(0x67F3780DD425D4FC, ped, comp_id)  -- GET_PED_DRAWABLE_VARIATION
            local texture = invoker.call(0x04A355E041E004E6, ped, comp_id)   -- GET_PED_TEXTURE_VARIATION
            if drawable and texture then
                outfit_data.components[comp_id] = {
                    drawable = drawable.int or 0,
                    texture = texture.int or 0
                }
            end
        end

        -- Save all 8 props (0,1,2,6,7 are used)
        for prop_id = 0, 7 do
            local prop_idx = invoker.call(0x898CC20EA75BACD8, ped, prop_id)  -- GET_PED_PROP_INDEX
            local prop_tex = invoker.call(0xE131A28626F81AB2, ped, prop_id)  -- GET_PED_PROP_TEXTURE_INDEX
            if prop_idx then
                outfit_data.props[prop_id] = {
                    index = prop_idx.int or -1,
                    texture = (prop_tex and prop_tex.int) or 0
                }
            end
        end

        -- Save to disk (same pattern as vehicles)
        local base = (paths and paths.script) or SCRIPT_DIR or ".\\"
        if not base:match("[\\/]$") then base = base .. "\\" end
        local save_dir = base .. "Carpie Diem\\outfits\\"
        local save_path = save_dir .. name .. ".json"

        safe_toast("DEBUG: Saving to " .. save_path)

        -- Ensure directory exists
        if dirs and dirs.create then
            local ok1 = pcall(dirs.create, base .. "Carpie Diem\\")
            local ok2 = pcall(dirs.create, save_dir)
            safe_toast("DEBUG: Dir created - " .. tostring(ok1) .. ", " .. tostring(ok2))
        else
            safe_toast("DEBUG: dirs.create not available")
        end

        if file and file.open then
            safe_toast("DEBUG: file.open available")
            local ok, err = pcall(function()
                -- Helper to convert table to JSON string
                local function table_to_json(t, indent)
                    indent = indent or "  "
                    local json = "{\n"
                    local first = true
                    for k, v in pairs(t) do
                        if not first then json = json .. ",\n" end
                        first = false
                        json = json .. indent .. '  "' .. tostring(k) .. '": '
                        if type(v) == "table" then
                            json = json .. table_to_json(v, indent .. "  ")
                        elseif type(v) == "boolean" then
                            json = json .. (v and "true" or "false")
                        elseif type(v) == "number" then
                            json = json .. tostring(v)
                        else
                            json = json .. '"' .. tostring(v) .. '"'
                        end
                    end
                    json = json .. "\n" .. indent .. "}"
                    return json
                end

                local json_str = table_to_json(outfit_data, "")
                safe_toast("DEBUG: JSON length = " .. #json_str)

                -- Write to file (EXACTLY like vehicle save)
                local f = file.open(save_path, {create_if_not_exists=true, append=false})
                safe_toast("DEBUG: file.open returned - f=" .. tostring(f) .. ", valid=" .. tostring(f and f.valid))

                if f and f.valid then
                    f.text = json_str
                    safe_toast("DEBUG: Set f.text")

                    if f.close then
                        pcall(f.close, f)
                        safe_toast("DEBUG: Closed with f.close")
                    elseif f.Close then
                        pcall(f.Close, f)
                        safe_toast("DEBUG: Closed with f.Close")
                    end
                    safe_toast("Outfit saved: " .. name)
                else
                    safe_toast("Failed to save outfit - f=" .. tostring(f))
                end
            end)

            if not ok then
                safe_toast("Save error: " .. tostring(err))
            end
        else
            safe_toast("File API not available")
        end
    end

    -- Helper: Load outfit from data
    local function load_outfit(outfit_data)
        if not outfit_data then
            safe_toast("Invalid outfit data")
            return
        end

        -- Get player ped (EXACTLY like vehicle save)
        local ped = invoker.call(0x43A66C31C68491C0, -1).int  -- PLAYER_PED_ID
        if not ped or ped == 0 then
            safe_toast("Failed to get player")
            return
        end

        local loaded_count = 0

        pcall(function()
            -- Load components
            if outfit_data.components then
                for comp_id = 0, 11 do
                    local comp = outfit_data.components[tostring(comp_id)]
                    if comp and comp.drawable then
                        invoker.call(0x262B14F48D29DE80, ped, comp_id, comp.drawable, comp.texture or 0, 0)  -- SET_PED_COMPONENT_VARIATION
                        loaded_count = loaded_count + 1
                    end
                end
            end

            -- Load props (FIXED: Don't clear if -1, just skip to keep current helmet/props)
            if outfit_data.props then
                for prop_id = 0, 7 do
                    local prop = outfit_data.props[tostring(prop_id)]
                    if prop and prop.index and prop.index >= 0 then
                        -- Only apply props that were actually saved (index >= 0)
                        -- Skip -1 values to keep current helmets/props on
                        invoker.call(0x93376B65A266EB5F, ped, prop_id, prop.index, prop.texture or 0, true, 0)  -- SET_PED_PROP_INDEX
                        loaded_count = loaded_count + 1
                    end
                end
            end

            safe_toast("Outfit loaded: " .. (outfit_data.name or "Unknown") .. " (" .. loaded_count .. " items)")
        end)
    end

    -- Helper: Load saved outfits from disk on startup (EXACTLY like vehicle load)
    local function load_outfits_from_disk()
        self_state.saved_outfits = {}

        -- Check APIs (like vehicle load)
        if not dirs or not dirs.list then
            return
        end

        -- Build list of paths to try
        local paths_to_try = {}

        -- Try paths.script first
        local base = (paths and paths.script) or nil
        if base then
            if not base:match("[\\/]$") then base = base .. "\\" end
            table.insert(paths_to_try, base .. "Carpie Diem\\outfits\\")
        end

        -- Add fallback path using SCRIPT_DIR
        local fallback_base = SCRIPT_DIR or ".\\"
        if not fallback_base:match("[\\/]$") then fallback_base = fallback_base .. "\\" end
        local fallback = fallback_base .. "Carpie Diem\\outfits\\"
        table.insert(paths_to_try, fallback)

        local json_files = nil
        local used_path = nil

        -- Try each path until we find files (EXACTLY like vehicle load)
        for _, outfit_dir in ipairs(paths_to_try) do
            local ok_list, files = pcall(dirs.list, outfit_dir, "json")  -- TWO parameters!
            if ok_list and files and #files > 0 then
                json_files = files
                used_path = outfit_dir
                break
            end
        end

        if not json_files or #json_files == 0 then
            return
        end

        -- Load each JSON file (dirs.list returns FULL PATHS, not just filenames)
        for _, filepath in ipairs(json_files) do
            -- Extract just the filename from the full path for display
            local display_name = filepath:match("[\\/]([^\\/]+)$") or filepath
            display_name = display_name:gsub("%.json$", "")

            -- Just store name and path (load full data when needed)
            table.insert(self_state.saved_outfits, {
                name = display_name,
                path = filepath  -- filepath is already the full path
            })
        end

        if #self_state.saved_outfits > 0 then
            safe_toast("Loaded " .. #self_state.saved_outfits .. " saved outfits")
        end
    end

    -- Helper: Load outfit from file path
    local function load_outfit_from_file(filepath)
        -- Debug: show filepath
        safe_toast("Loading: " .. (filepath or "nil"))

        -- Check filepath exists
        if not filepath or filepath == "" then
            safe_toast("ERROR: No filepath provided")
            return
        end

        -- Read file EXACTLY like vehicle load does
        local ok_open, f = pcall(file.open, filepath, {create_if_not_exists=false, append=false})

        -- Debug: check what happened
        if not ok_open then
            safe_toast("ERROR: file.open threw error")
            return
        end

        if not f then
            safe_toast("ERROR: file.open returned nil")
            return
        end

        if not f.valid then
            safe_toast("ERROR: file not valid")
            return
        end

        local content = f.text

        -- Debug: check content
        if not content or content == "" then
            safe_toast("ERROR: File content empty")
            if f.close then pcall(f.close, f) elseif f.Close then pcall(f.Close, f) end
            return
        end

        -- Close file like vehicle load does
        if f.close then
            pcall(f.close, f)
        elseif f.Close then
            pcall(f.Close, f)
        end

        -- Very simple JSON parser for outfit data
        local outfit_data = {
            components = {},
            props = {}
        }

        -- Parse name
        outfit_data.name = content:match('"name"%s*:%s*"([^"]+)"') or "Unknown"

        -- Parse components (0-11)
        for i = 0, 11 do
            local comp_str = content:match('"' .. i .. '"%s*:%s*{([^}]+)}')
            if comp_str then
                local drawable = comp_str:match('"drawable"%s*:%s*(%d+)')
                local texture = comp_str:match('"texture"%s*:%s*(%d+)')
                if drawable then
                    outfit_data.components[tostring(i)] = {
                        drawable = tonumber(drawable) or 0,
                        texture = tonumber(texture) or 0
                    }
                end
            end
        end

        -- Parse props (0-7)
        for i = 0, 7 do
            local prop_str = content:match('"' .. i .. '"%s*:%s*{([^}]+)}')
            if prop_str then
                local index = prop_str:match('"index"%s*:%s*(-?%d+)')
                local texture = prop_str:match('"texture"%s*:%s*(%d+)')
                if index then
                    outfit_data.props[tostring(i)] = {
                        index = tonumber(index) or -1,
                        texture = tonumber(texture) or 0
                    }
                end
            end
        end

        load_outfit(outfit_data)
    end

    -- Helper: Delete saved outfit
    local function delete_outfit(index)
        if not self_state.saved_outfits or not self_state.saved_outfits[index] then
            return
        end

        local outfit = self_state.saved_outfits[index]

        -- Delete file
        if outfit.path then
            pcall(os.remove, outfit.path)
        end

        -- Remove from list
        table.remove(self_state.saved_outfits, index)

        if self_state.selected_outfit == index then
            self_state.selected_outfit = nil
        elseif self_state.selected_outfit and self_state.selected_outfit > index then
            self_state.selected_outfit = self_state.selected_outfit - 1
        end

        safe_toast("Outfit deleted: " .. (outfit.name or "Unknown"))
    end

    local function draw_self_tab()
        local s = UI.scale
        local base_x = content_x
        local base_y = widget_y
        local total_w = content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- TWO columns: category list (left) + content panel (right)
        local gap = math.floor(10 * s)
        local list_w = math.floor(140 * s)
        local panel_w = total_w - list_w - gap - math.floor(10 * s)

        -- LEFT: Category List
        local list_x = base_x + math.floor(5 * s)
        local list_y = base_y
        local header_h = math.floor(24 * s)

        draw_rect(list_x, list_y, list_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Categories", list_x + math.floor(8 * s), list_y + math.floor(5 * s), UI.font_small, C.text)
        list_y = list_y + header_h + 2

        draw_rect(list_x, list_y, list_w, total_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local item_h = math.floor(36 * s)
        local py = list_y + math.floor(5 * s)

        for i, cat in ipairs(SELF_CATEGORIES) do
            local is_selected = (self_state.selected_category == i)
            local label = cat.icon .. " " .. cat.name
            if selectable(label, is_selected, nil, list_x + 2, py, list_w - 4, item_h - 4) then
                self_state.selected_category = i
                self_state.scroll_offset = 0
            end
            py = py + item_h
        end

        -- RIGHT: Content Panel
        local panel_x = list_x + list_w + gap
        local panel_y = base_y

        draw_rect(panel_x, panel_y, panel_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        local selected_cat = SELF_CATEGORIES[self_state.selected_category]
        draw_text(selected_cat.name, panel_x + math.floor(8 * s), panel_y + math.floor(5 * s), UI.font_small, C.text)
        panel_y = panel_y + header_h + 2

        local panel_h = total_h - header_h - 2
        draw_rect(panel_x, panel_y, panel_w, panel_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Draw category content
        local btn_h = math.floor(28 * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)
        local ly = panel_y + math.floor(8 * s)
        local usable_w = panel_w - side_pad * 2

        -- Shared slider variables (reused to reduce local count)
        local new_val, h

        -- ========== PROTECTION ==========
        if self_state.selected_category == 1 then

            -- God Mode
            demo.god_mode = inline_toggle("God Mode", demo.god_mode, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- No Ragdoll
            demo.no_ragdoll = inline_toggle("No Ragdoll", demo.no_ragdoll, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- Never Wanted
            demo.never_wanted = inline_toggle("Never Wanted", demo.never_wanted, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- Auto Script Host
            local old_script_host = demo.auto_script_host
            demo.auto_script_host = inline_toggle("Auto Script Host", demo.auto_script_host, panel_x + side_pad, ly, usable_w, btn_h)
            if demo.auto_script_host and not old_script_host then
                -- Just enabled, force host immediately
                if script and script.force_host then
                    script.force_host("freemode")
                    safe_toast("Auto Script Host: ON - Taking freemode host...")
                else
                    safe_toast("Script API not available!")
                end
            elseif not demo.auto_script_host and old_script_host then
                safe_toast("Auto Script Host: OFF")
            end
            ly = ly + btn_h + btn_gap

            -- Ghost Organization (permanent off-radar)
            local old_ghost = self_state.ghost_org
            self_state.ghost_org = inline_toggle("Ghost Organization", self_state.ghost_org, panel_x + side_pad, ly, usable_w, btn_h)
            if self_state.ghost_org and not old_ghost then
                -- Start loop
                local sid = {}
                self_state.ghost_org_sid = sid
                util.create_thread(function()
                    while self_state.ghost_org and self_state.ghost_org_sid == sid do
                        -- SET_LOCAL_PLAYER_AS_GHOST (0x5FFE9B4144F9712F)
                        invoker.call(0x5FFE9B4144F9712F, true, false)
                        util.yield(1000)  -- Reapply every 1 second
                    end
                    -- Turn off ghost when disabled
                    invoker.call(0x5FFE9B4144F9712F, false, false)
                    self_state.ghost_org = false
                end)
                safe_toast("Ghost Organization: ON (Permanent Off-Radar)")
            elseif not self_state.ghost_org and old_ghost then
                self_state.ghost_org_sid = nil
                safe_toast("Ghost Organization: OFF")
            end
            ly = ly + btn_h + btn_gap

            ly = ly + math.floor(10 * s)

            -- Replenish Health Button
            if small_button("Replenish Health & Armor", panel_x + side_pad, ly, usable_w, btn_h) then
                local me = players and players.me and players.me()
                if me and me.ped then
                    invoker.call(0x6B76DC1F3AE6E6A3, me.ped, 328, 0) -- SET_ENTITY_HEALTH
                    invoker.call(0xCEA04D83135264CC, me.ped, 100) -- SET_PED_ARMOUR
                    safe_toast("Health & Armor Restored!")
                end
            end

        -- ========== MOVEMENT ==========
        elseif self_state.selected_category == 2 then

            -- Super Jump
            demo.super_jump = inline_toggle("Super Jump", demo.super_jump, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- Fast Run
            demo.fast_run = inline_toggle("Fast Run", demo.fast_run, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- Run Speed Slider (if fast run enabled)
            if demo.fast_run then
                local slider_h = math.floor(36 * s)
                local new_speed, h = recovery_slider("Run Speed", demo.run_speed, 1.0, 1.49, panel_x + side_pad, ly, usable_w, s, "")
