                local new_speed, h = recovery_slider("Noclip Speed", noclip_state.speed, 0.1, 5.0, panel_x + side_pad, ly, usable_w, s, "")
                noclip_state.speed = new_speed
                ly = ly + slider_h + btn_gap
            end

            -- Auto TP to Waypoint
            demo.auto_waypoint_tp = inline_toggle("Auto TP to Waypoint", demo.auto_waypoint_tp, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- FOV Slider (NOT IMPLEMENTED - technical limitation)
            -- Commented out since it doesn't work
            -- ly = ly + math.floor(10 * s)
            -- local slider_h = math.floor(36 * s)
            -- local new_fov, h = recovery_slider("Field of View (BROKEN)", self_state.fov, 10.0, 120.0, panel_x + side_pad, ly, usable_w, s, "°")
            -- self_state.fov = new_fov
            -- ly = ly + slider_h + btn_gap

        -- ========== VISIBILITY ==========
        elseif self_state.selected_category == 3 then

            -- Invisibility
            demo.invisibility = inline_toggle("Invisibility", demo.invisibility, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

            -- Off The Radar
            demo.off_the_radar = inline_toggle("Off The Radar", demo.off_the_radar, panel_x + side_pad, ly, usable_w, btn_h)
            ly = ly + btn_h + btn_gap

        -- ========== RECOVERY (ADVANCED STATS EDITOR) ==========
        elseif self_state.selected_category == 4 then
            -- Recovery sub-categories
            if not self_state.recovery_subcategory then
                self_state.recovery_subcategory = 1
            end

            local sub_categories = {"K/D Editor", "Rank Editor", "Money", "Skills", "Combat Stats", "Reports", "Modded Accounts"}
            local sub_tab_w = math.floor(usable_w / #sub_categories)
            local sub_tab_h = math.floor(28 * s)

            -- Draw sub-category tabs
            for i, name in ipairs(sub_categories) do
                local tab_x = panel_x + side_pad + (i - 1) * sub_tab_w
                local is_active = (self_state.recovery_subcategory == i)
                local hover = is_mouse_in(tab_x, ly, sub_tab_w - math.floor(2 * s), sub_tab_h)

                draw_rect(tab_x, ly, sub_tab_w - math.floor(2 * s), sub_tab_h,
                    is_active and C.accent or (hover and C.widget_hover or C.widget_bg), math.floor(4 * s))
                draw_text(name, tab_x + math.floor(8 * s), ly + (sub_tab_h - UI.font_small) / 2, UI.font_small,
                    is_active and C.background or C.text)

                if hover and MOUSE.just_pressed then
                    self_state.recovery_subcategory = i
                end
            end
            ly = ly + sub_tab_h + math.floor(10 * s)

            -- Helper function to set stat for both characters
            local function set_stat_both_chars(stat_name, value, type_accessor)
                if not account or not account.stats then
                    safe_toast("Stats API not available!")
                    return false
                end

                for i = 0, 1 do
                    local prefix = "MP" .. i .. "_"
                    account.stats(prefix .. stat_name)[type_accessor] = value
                end
                return true
            end

            -- Helper function to render text input box
            local function text_input(x, y, w, h, buffer, is_focused, placeholder)
                local hover = is_mouse_in(x, y, w, h)
                local bg = is_focused and C.accent or (hover and C.widget_hover or C.widget_bg)
                draw_rect(x, y, w, h, bg, math.floor((UI.widget_rounding or 5) * s))

                local display = buffer or ""
                if is_focused then
                    display = display .. "_"  -- Cursor
                end

                if display == "" or display == "_" then
                    draw_text(placeholder, x + math.floor(8 * s), y + math.floor(6 * s), UI.font_tiny, C.text_dim)
                else
                    draw_text(display, x + math.floor(8 * s), y + math.floor(6 * s), UI.font_tiny, is_focused and C.bg or C.text)
                end

                return hover
            end

            -- Helper function to handle keyboard input for text boxes
            local function handle_text_input(buffer)
                -- Backspace
                if input.key(0x08).just_pressed and buffer and #buffer > 0 then
                    return buffer:sub(1, -2)
                end
                -- Numbers 0-9
                for i = 0x30, 0x39 do
                    if input.key(i).just_pressed then
                        return (buffer or "") .. string.char(i)
                    end
                end
                -- Decimal point
                if input.key(0xBE).just_pressed or input.key(0x6E).just_pressed then
                    return (buffer or "") .. "."
                end
                return buffer
            end

            -- ==================== SUB-CATEGORY 1: K/D EDITOR ====================
            if self_state.recovery_subcategory == 1 then
                draw_text("K/D Editor", panel_x + side_pad, ly, UI.font_small, C.accent)
                draw_text("Uses MPPLY global stats for accurate K/D display", panel_x + side_pad, ly + math.floor(12 * s), UI.font_tiny, C.text_dim)
                ly = ly + math.floor(32 * s)

