                    self_state.kd_input = handle_text_input(self_state.kd_input)
                end
                ly = ly + input_h + math.floor(4 * s)

                if small_button("Apply Custom K/D", panel_x + side_pad, ly, usable_w, btn_h) then
                    local kd = tonumber(self_state.kd_input)
                    if kd and kd >= 0 and account and account.stats then
                        local base = 100000
                        local kills = math.floor(kd * base)
                        local deaths = base
                        account.stats("MPPLY_KILLS_PLAYERS").int32 = kills
                        account.stats("MPPLY_DEATHS_PLAYER").int32 = deaths
                        safe_toast(string.format("K/D set to %.2f!", kd))
                    else
                        safe_toast("Invalid K/D value!")
                    end
