                ly = ly + btn_h + math.floor(15 * s)

                -- Custom Kills Input
                draw_text("Custom Kills", panel_x + side_pad, ly, UI.font_small, C.text)
                ly = ly + math.floor(18 * s)

                local kills_hover = text_input(panel_x + side_pad, ly, usable_w, input_h, self_state.kills_input, self_state.kills_input_focused, "Enter kills (e.g. 50000)")

                if kills_hover and MOUSE.just_pressed then
                    self_state.kills_input_focused = true
                    self_state.kd_input_focused = false
                    self_state.deaths_input_focused = false
                    self_state.rank_input_focused = false
                    self_state.custom_stat_focused = false
                end

                if self_state.kills_input_focused then
                    self_state.kills_input = handle_text_input(self_state.kills_input)
                end
                ly = ly + input_h + math.floor(4 * s)

                if small_button("Apply Kills", panel_x + side_pad, ly, usable_w, btn_h) then
