                if deaths_hover and MOUSE.just_pressed then
                    self_state.deaths_input_focused = true
                    self_state.kd_input_focused = false
                    self_state.kills_input_focused = false
                    self_state.rank_input_focused = false
                    self_state.custom_stat_focused = false
                end

