                draw_text("Change session after setting for rank to update", panel_x + side_pad, ly + math.floor(12 * s), UI.font_tiny, C.text_dim)
                ly = ly + math.floor(32 * s)

                -- RP Calculation function
                local function get_rp_for_rank(rank)
                    if rank < 1 then return 0 end
                    if rank <= 100 then
                        local rp_table = {
                            0, 800, 2100, 3800, 6100, 9500, 12500, 16000, 19800, 24000,
                            28500, 33400, 38700, 44200, 50200, 56400, 63000, 69900, 77100, 84700,
                            92500, 100700, 109200, 118000, 127100, 136500, 146200, 156200, 166500, 177100,
                            188000, 199200, 210700, 222400, 234500, 246800, 259400, 272300, 285500, 299000,
                            312700, 326800, 341000, 355600, 370500, 385600, 401000, 416600, 432600, 448800,
                            465200, 482000, 499000, 516300, 533800, 551600, 569600, 588000, 606500, 625400,
                            644500, 663800, 683400, 703300, 723400, 743800, 764500, 785400, 806500, 827900,
                            849600, 871500, 893600, 916000, 938700, 961600, 984700, 1008100, 1031800, 1055700,
                            1079800, 1104200, 1128800, 1153700, 1178800, 1204200, 1229800, 1255600, 1281700, 1308100,
                            1334600, 1361400, 1388500, 1415800, 1443300, 1471100, 1499100, 1527300
                        }
                        if rank <= #rp_table then return rp_table[rank] end
                    end
                    return math.floor(25 * (rank ^ 2) + 23575 * rank - 1023150)
                end

                -- Custom Rank Input
                draw_text("Custom Rank (1-8000)", panel_x + side_pad, ly, UI.font_small, C.text)
                ly = ly + math.floor(18 * s)

                local input_h = math.floor(28 * s)
                local rank_hover = text_input(panel_x + side_pad, ly, usable_w, input_h, self_state.rank_input, self_state.rank_input_focused, "Enter rank (e.g. 250)")

                if rank_hover and MOUSE.just_pressed then
                    self_state.rank_input_focused = true
                    self_state.kd_input_focused = false
                    self_state.kills_input_focused = false
                    self_state.deaths_input_focused = false
                    self_state.custom_stat_focused = false
                end

                if self_state.rank_input_focused then
                    self_state.rank_input = handle_text_input(self_state.rank_input)
                end
                ly = ly + input_h + math.floor(4 * s)

                if small_button("Apply Custom Rank", panel_x + side_pad, ly, usable_w, btn_h) then
                    local rank = tonumber(self_state.rank_input)
                    if rank and rank >= 1 and rank <= 8000 then
                        local rp = get_rp_for_rank(rank)
                        if set_stat_both_chars("CHAR_XP_FM", rp, "int32") then
                            safe_toast(string.format("Rank set to %d! Change session", math.floor(rank)))
                        end
                    else
                        safe_toast("Invalid rank! Must be 1-8000")
                    end
                end
                ly = ly + btn_h + math.floor(4 * s)

            -- ==================== SUB-CATEGORY 3: MONEY ====================
            elseif self_state.recovery_subcategory == 3 then
                draw_text("Money Loop", panel_x + side_pad, ly, UI.font_small, C.accent)
                draw_text("Direct stat modification - adds to bank balance", panel_x + side_pad, ly + math.floor(12 * s), UI.font_tiny, C.text_dim)
                ly = ly + math.floor(32 * s)

                -- Money Loop Method Selector
                draw_text("Money Loop Method", panel_x + side_pad, ly, UI.font_small, C.text)
                ly = ly + math.floor(18 * s)

                local method_options = {"$180K", "$500K"}
                local method_btn_w = (usable_w - math.floor(10 * s)) / 2

                for i = 1, 2 do
                    local bx = panel_x + side_pad + (i - 1) * (method_btn_w + math.floor(10 * s))
                    local is_selected = (self_state.money_loop_method == (i - 1))
                    local hover = is_mouse_in(bx, ly, method_btn_w, btn_h)
                    local btn_col = is_selected and C.accent or (hover and C.widget_hover or C.widget_bg)
                    local txt_col = is_selected and C.text or C.text_dim

                    -- Draw button
                    draw_rect(bx, ly, method_btn_w, btn_h, btn_col, math.floor((UI.widget_rounding or 5) * s))
                    draw_text_centered(method_options[i], bx, ly, method_btn_w, btn_h, UI.font_small, txt_col)

                    -- Check click AFTER drawing
                    if hover and MOUSE.just_pressed then
                        self_state.money_loop_method = i - 1
                        safe_toast("Method: " .. method_options[i])
                    end
                end
                ly = ly + btn_h + math.floor(15 * s)

                -- Money Loop Toggle
                draw_text("Bank Money Loop", panel_x + side_pad, ly, UI.font_small, C.text)
                ly = ly + math.floor(18 * s)

                -- Calculate current status text
                local status_text = "Money Loop: OFF"
                if self_state.money_loop_active then
                    local elapsed = os.time() - self_state.money_loop_start_time
                    local amount = (self_state.money_loop_method == 1) and "$500K" or "$180K"
                    if elapsed >= 900 then
                        status_text = "Money Loop: ON (" .. amount .. "/10s)"
                    else
                        status_text = "Money Loop: ON (" .. amount .. "/5s)"
                    end
                end

                local old_loop = self_state.money_loop_active
                self_state.money_loop_active = inline_toggle(status_text, self_state.money_loop_active, panel_x + side_pad, ly, usable_w, btn_h)
                if self_state.money_loop_active ~= old_loop then
                    if self_state.money_loop_active then
                        safe_toast("Money loop started!")
                    else
                        safe_toast("Money loop stopped!")
                    end
                end
                ly = ly + btn_h + math.floor(15 * s)

                -- Info section
                draw_text("Loop Information", panel_x + side_pad, ly, UI.font_small, C.text)
                ly = ly + math.floor(18 * s)

                if self_state.money_loop_method == 1 then
                    -- $500K method info
