local STAT_SET_BLOCK_SAVES = 0xF434A10BA01C37D0
local STAT_SAVE = 0xE07BCA305B82D2FD  -- Forces stat save/commit

-- Logging setup
local log_lines = {}
local function log(msg)
    table.insert(log_lines, os.date("[%Y-%m-%d %H:%M:%S] ") .. msg)
end
local function write_log()
    pcall(function()
        local log_str = table.concat(log_lines, "\n") .. "\n"
        local f = file.open("log.txt", { create_if_not_exists = true, append = true })
        if f and f.valid then
            f.text = log_str
        end
    end)
end

