-- Helper to set stat - NO PCALL (faster, shows errors)
local stat_count = 0
local function sset(stat_name, value, type_str)
    if type_str == "int" or type_str == "int32" then
        account.stats(stat_name).int32 = value
    elseif type_str == "int64" then
        account.stats(stat_name).int64 = value
    elseif type_str == "bool" then
        account.stats(stat_name).bool = value
    elseif type_str == "float" then
        account.stats(stat_name).float = value
    elseif type_str == "uint32" then
        account.stats(stat_name).uint32 = value
    end
    stat_count = stat_count + 1
    -- Progress update every 100 stats
    if stat_count % 100 == 0 then
        safe_toast("V3.10: " .. stat_count .. " stats set...")
    end
end

