            -- Reset ly for this category (CRITICAL: prevents crash from stale ly value)
            ly = panel_y + math.floor(8 * s)

            local me = players and players.me and players.me()

            -- Create 3D preview ped when entering clothing tab (simple clone in front of player)
            if me and me.ped and not self_state.preview_active then
                pcall(function()
                    -- Get player position and heading
                    local player_pos = invoker.call(0x3FEF770D40960D5A, me.ped, true)
                    local heading = invoker.call(0xE83A169C1F547683, me.ped)
                    if player_pos and player_pos.scr_vec3 then
                        local px, py, pz = player_pos.scr_vec3.x, player_pos.scr_vec3.y, player_pos.scr_vec3.z
                        local h = (heading and heading.float) or 0.0

                        -- Use CLONE_PED to create exact duplicate with all clothing
                        local cloned = invoker.call(0xEF29A16337FACADB, me.ped, 0.0, false, false)

                        if cloned and cloned.int and cloned.int ~= 0 then
                            self_state.preview_ped = cloned.int
                            self_state.preview_active = true
                            self_state.preview_rotation = h + 180.0  -- Face player

                            -- Position clone in front of player (using correct GTA V heading math)
                            local rad = math.rad(h)
                            -- GTA V forward: x = -sin(heading), y = cos(heading)
                            local preview_x = px - math.sin(rad) * 3.0
                            local preview_y = py + math.cos(rad) * 3.0

                            invoker.call(0x06843DA7060A026B, self_state.preview_ped, preview_x, preview_y, pz, false, false, false, true)

                            -- Make preview ped styled (facing player)
                            invoker.call(0x8E2530AA8ADA980E, self_state.preview_ped, self_state.preview_rotation)
                            invoker.call(0x71BC8E838B9C6035, self_state.preview_ped, true) -- FREEZE_ENTITY_POSITION
                            invoker.call(0x3882114BDE571AD4, self_state.preview_ped, true) -- SET_ENTITY_INVINCIBLE
                            invoker.call(0x1794B4FCC84D812F, self_state.preview_ped, false) -- SET_PED_CAN_RAGDOLL
                            invoker.call(0x1CF38D529D7441D9, self_state.preview_ped, false, false) -- SET_ENTITY_COLLISION
                            invoker.call(0xE3B6097CC25AA69E, self_state.preview_ped, true) -- SET_ENTITY_VISIBLE

                            -- Also initialize state variables from player's current clothing
                            for comp_id = 0, 11 do
                                local drawable = invoker.call(0x67F3780DD425D4FC, me.ped, comp_id)
                                local texture = invoker.call(0x04A355E041E004E6, me.ped, comp_id)
                                if drawable and texture then
                                    local d = drawable.int or 0
                                    local t = texture.int or 0
                                    if comp_id == 1 then self_state.mask_style, self_state.mask_tex = d, t
                                    elseif comp_id == 2 then self_state.hair_style, self_state.hair_tex = d, t
                                    elseif comp_id == 3 then self_state.torso_style, self_state.torso_tex = d, t
                                    elseif comp_id == 4 then self_state.pants_style, self_state.pants_tex = d, t
                                    elseif comp_id == 5 then self_state.bag_style, self_state.bag_tex = d, t
                                    elseif comp_id == 6 then self_state.shoes_style, self_state.shoes_tex = d, t
                                    elseif comp_id == 7 then self_state.accessories_style, self_state.accessories_tex = d, t
                                    elseif comp_id == 8 then self_state.undershirt_style, self_state.undershirt_tex = d, t
                                    elseif comp_id == 9 then self_state.armor_style, self_state.armor_tex = d, t
                                    elseif comp_id == 10 then self_state.decals_style, self_state.decals_tex = d, t
                                    elseif comp_id == 11 then self_state.tops_style, self_state.tops_tex = d, t
                                    end
                                end
                            end

                            -- Initialize prop state variables
                            for prop_id = 0, 7 do
                                local prop_idx = invoker.call(0x898CC20EA75BACD8, me.ped, prop_id)
                                local prop_tex = invoker.call(0xE131A28626F81AB2, me.ped, prop_id)
                                if prop_idx then
                                    local idx = prop_idx.int or -1
                                    local tex = (prop_tex and prop_tex.int) or 0
                                    if prop_id == 0 then self_state.hat_style, self_state.hat_tex = idx, tex
                                    elseif prop_id == 1 then self_state.glasses_style, self_state.glasses_tex = idx, tex
                                    elseif prop_id == 2 then self_state.ears_style, self_state.ears_tex = idx, tex
                                    elseif prop_id == 6 then self_state.watches_style, self_state.watches_tex = idx, tex
                                    elseif prop_id == 7 then self_state.bracelets_style, self_state.bracelets_tex = idx, tex
                                    end
                                end
                            end
                        end
                    end
                end)
            end

            -- Auto-rotate preview ped + keep it in front of player wherever they face
            if self_state.preview_active and self_state.preview_ped then
                pcall(function()
                    if invoker.call(0x7239B21A38F536BA, self_state.preview_ped).bool then
                        -- Auto-rotate the preview ped
                        self_state.preview_rotation = (self_state.preview_rotation + 0.8) % 360.0
                        invoker.call(0x8E2530AA8ADA980E, self_state.preview_ped, self_state.preview_rotation)

                        -- Keep clone in front of player wherever they're facing
                        local player_pos = invoker.call(0x3FEF770D40960D5A, me.ped, true)
                        local heading = invoker.call(0xE83A169C1F547683, me.ped)
                        if player_pos and player_pos.scr_vec3 and heading then
                            local px, py, pz = player_pos.scr_vec3.x, player_pos.scr_vec3.y, player_pos.scr_vec3.z
                            local h = heading.float or 0.0
                            local rad = math.rad(h)
                            -- GTA V forward: x = -sin(heading), y = cos(heading)
                            local preview_x = px - math.sin(rad) * 3.0
                            local preview_y = py + math.cos(rad) * 3.0
                            invoker.call(0x06843DA7060A026B, self_state.preview_ped, preview_x, preview_y, pz, false, false, false, true)
                        end
                    end
                end)
            end

            -- Update preview ped clothing to match player
            if self_state.preview_active and self_state.preview_ped and invoker.call(0x7239B21A38F536BA, self_state.preview_ped).bool then
                pcall(function()
                    -- Update all components (skip component 0 - head/face)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 1, math.floor(self_state.mask_style), math.floor(self_state.mask_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 2, math.floor(self_state.hair_style), math.floor(self_state.hair_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 3, math.floor(self_state.torso_style), math.floor(self_state.torso_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 4, math.floor(self_state.pants_style), math.floor(self_state.pants_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 5, math.floor(self_state.bag_style), math.floor(self_state.bag_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 6, math.floor(self_state.shoes_style), math.floor(self_state.shoes_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 7, math.floor(self_state.accessories_style), math.floor(self_state.accessories_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 8, math.floor(self_state.undershirt_style), math.floor(self_state.undershirt_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 9, math.floor(self_state.armor_style), math.floor(self_state.armor_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 10, math.floor(self_state.decals_style), math.floor(self_state.decals_tex), 0)
                    invoker.call(0x262B14F48D29DE80, self_state.preview_ped, 11, math.floor(self_state.tops_style), math.floor(self_state.tops_tex), 0)

                    -- Update all props
                    if math.floor(self_state.hat_style) == -1 then
                        invoker.call(0x0943E5B8E078E76E, self_state.preview_ped, 0)
                    else
                        invoker.call(0x93376B65A266EB5F, self_state.preview_ped, 0, math.floor(self_state.hat_style), math.floor(self_state.hat_tex), true, 0)
                    end

                    if math.floor(self_state.glasses_style) == -1 then
                        invoker.call(0x0943E5B8E078E76E, self_state.preview_ped, 1)
                    else
                        invoker.call(0x93376B65A266EB5F, self_state.preview_ped, 1, math.floor(self_state.glasses_style), math.floor(self_state.glasses_tex), true, 0)
                    end

                    if math.floor(self_state.ears_style) == -1 then
                        invoker.call(0x0943E5B8E078E76E, self_state.preview_ped, 2)
                    else
                        invoker.call(0x93376B65A266EB5F, self_state.preview_ped, 2, math.floor(self_state.ears_style), math.floor(self_state.ears_tex), true, 0)
                    end

                    if math.floor(self_state.watches_style) == -1 then
                        invoker.call(0x0943E5B8E078E76E, self_state.preview_ped, 6)
                    else
                        invoker.call(0x93376B65A266EB5F, self_state.preview_ped, 6, math.floor(self_state.watches_style), math.floor(self_state.watches_tex), true, 0)
                    end

                    if math.floor(self_state.bracelets_style) == -1 then
                        invoker.call(0x0943E5B8E078E76E, self_state.preview_ped, 7)
                    else
                        invoker.call(0x93376B65A266EB5F, self_state.preview_ped, 7, math.floor(self_state.bracelets_style), math.floor(self_state.bracelets_tex), true, 0)
                    end
                end)
            end

            -- ========== OUTFIT SAVE/LOAD (JSON FILES LIKE VEHICLES/CONSTRUCTS) ==========
            -- Load outfits from disk on first access
            if not self_state.saved_outfits_loaded then
                self_state.saved_outfits_loaded = true
                load_outfits_from_disk()
            end

            draw_text("Save Current Outfit", panel_x + side_pad, ly, UI.font_small, C.accent)
            ly = ly + math.floor(24 * s)

            -- Name input label
            draw_text("Outfit Name:", panel_x + side_pad, ly, UI.font_tiny, C.text_dim)
            ly = ly + math.floor(18 * s)

            -- Name input box (EXACTLY like vehicle save)
            self_state.outfit_name_focused = self_state.outfit_name_focused or false
            local input_h = math.floor(28 * s)
            local input_w = usable_w
            local input_hover = is_mouse_in(panel_x + side_pad, ly, input_w, input_h)

            -- Click to focus/unfocus (BEFORE keyboard input)
            if input_hover and MOUSE.just_pressed then
                self_state.outfit_name_focused = not self_state.outfit_name_focused
            end

            -- Keyboard input (like vehicle save)
            if self_state.outfit_name_focused and input and input.key then
                -- Backspace
                if input.key(0x08).just_pressed then
                    if #self_state.outfit_name > 0 then
                        self_state.outfit_name = self_state.outfit_name:sub(1, -2)
                    end
                end

                -- Numbers (0-9)
                for code = 0x30, 0x39 do
                    if input.key(code).just_pressed then
                        self_state.outfit_name = self_state.outfit_name .. string.char(code)
                    end
                end

                -- Letters (A-Z)
                for code = 0x41, 0x5A do
                    if input.key(code).just_pressed then
                        self_state.outfit_name = self_state.outfit_name .. string.char(code):lower()
                    end
                end

                -- Space
                if input.key(0x20).just_pressed then
                    self_state.outfit_name = self_state.outfit_name .. " "
                end

                -- Underscore
                if input.key(0xBD).just_pressed or input.key(0x6D).just_pressed then
                    self_state.outfit_name = self_state.outfit_name .. "_"
                end

                -- Enter (save and close)
                if input.key(0x0D).just_pressed then
                    self_state.outfit_name_focused = false
                    if self_state.outfit_name ~= "" then
                        save_current_outfit(self_state.outfit_name)
                        self_state.outfit_name = ""  -- Clear input after save
                        load_outfits_from_disk()  -- Refresh list
                    end
                end

                -- Escape (cancel)
                if input.key(0x1B).just_pressed then
                    self_state.outfit_name_focused = false
                end
            end

            -- Draw input box (EXACTLY like vehicle save - after click handler)
            local input_bg = self_state.outfit_name_focused and C.widget_hover or (input_hover and C.widget_hover or C.widget_bg)
            draw_rect(panel_x + side_pad, ly, input_w, input_h, input_bg, math.floor((UI.widget_rounding or 5) * s))

            -- Accent border when focused (like vehicle save)
            if self_state.outfit_name_focused then
                draw_rect(panel_x + side_pad, ly, input_w, math.floor(2 * s), C.accent, math.floor(6 * s))
                draw_rect(panel_x + side_pad, ly + input_h - math.floor(2 * s), input_w, math.floor(2 * s), C.accent, math.floor(6 * s))
                draw_rect(panel_x + side_pad, ly, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
                draw_rect(panel_x + side_pad + input_w - math.floor(2 * s), ly, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
            end

            -- Display text (like vehicle save)
            local display_name = self_state.outfit_name or ""
            if self_state.outfit_name_focused then
                display_name = display_name .. "_"
            end
            if display_name == "" or display_name == "_" then
                draw_text("Enter name...", panel_x + side_pad + math.floor(10 * s), ly + math.floor(6 * s), UI.font_tiny, color(100,100,100,180))
            else
                draw_text(display_name, panel_x + side_pad + math.floor(10 * s), ly + math.floor(6 * s), UI.font_tiny, C.text)
            end

            ly = ly + input_h + math.floor(10 * s)

            -- Save Button (like vehicle save)
            if small_button("Save Outfit", panel_x + side_pad, ly, usable_w, btn_h) then
                if self_state.outfit_name and self_state.outfit_name ~= "" then
                    save_current_outfit(self_state.outfit_name)
                    self_state.outfit_name = ""  -- Clear after save
                    self_state.outfit_name_focused = false  -- Unfocus
                    load_outfits_from_disk()  -- Refresh list
                else
                    safe_toast("Enter outfit name first")
                end
            end

            ly = ly + btn_h + math.floor(16 * s)

            -- Saved Outfits List
            draw_text("Saved Outfits (" .. #self_state.saved_outfits .. ")", panel_x + side_pad, ly, UI.font_small, C.accent)
            ly = ly + math.floor(20 * s)

            -- List saved outfits with Load/Delete buttons
            for i, outfit in ipairs(self_state.saved_outfits) do
                local item_h = math.floor(32 * s)
                local btn_w = math.floor(60 * s)
                local name_w = panel_w - side_pad * 2 - btn_w * 2 - math.floor(16 * s)

                -- Outfit name background
                local is_selected = (self_state.selected_outfit == i)
                local bg_color = is_selected and C.widget_hover or C.widget_bg
                draw_rect(panel_x + side_pad, ly, name_w, item_h, bg_color, math.floor((UI.widget_rounding or 5) * s))
                draw_text(outfit.name or "Unknown", panel_x + side_pad + math.floor(8 * s), ly + math.floor(8 * s), UI.font_small, C.text)

                -- Select on click
                if is_mouse_in(panel_x + side_pad, ly, name_w, item_h) and MOUSE.just_pressed then
                    self_state.selected_outfit = i
                end

                -- Load button
                local load_x = panel_x + side_pad + name_w + math.floor(8 * s)
                if small_button("Load", load_x, ly, btn_w, item_h) then
                    if outfit.path then
                        load_outfit_from_file(outfit.path)
                    end
                end

                -- Delete button
                local del_x = load_x + btn_w + math.floor(8 * s)
                if small_button("Delete", del_x, ly, btn_w, item_h) then
                    delete_outfit(i)
                    load_outfits_from_disk()  -- Refresh list
                    break  -- Exit loop since we modified the array
                end

                ly = ly + item_h + math.floor(6 * s)
            end

            ly = ly + math.floor(10 * s)

            -- Calculate total content height
            local slider_h = math.floor(40 * s)
            local header_h = math.floor(18 * s)
            local spacing = math.floor(12 * s)
            local total_content_h = 0

            -- 16 clothing categories + 4 section headers (removed Head/Face component)
            -- Each category: header + 2 sliders (style + texture) + spacing
            total_content_h = (header_h + (slider_h * 2) + spacing) * 16
            -- Add 4 section headers (HEAD & FACE, UPPER BODY, LOWER BODY, ACCESSORIES)
            total_content_h = total_content_h + (header_h * 4)

            -- Check if scrolling needed (account for button space at top)
            local button_space = btn_h + math.floor(18 * s)
            local content_area_h = panel_h - button_space
            local needs_scroll = total_content_h > content_area_h
            local max_scroll = math.max(0, total_content_h - content_area_h + math.floor(20 * s))

            -- Clamp scroll
            self_state.scroll_offset = math.max(0, math.min(self_state.scroll_offset, max_scroll))

            -- Handle mouse wheel scroll (only in content area, NOT over outfit buttons)
            local content_start_y = ly
            if is_mouse_in(panel_x, content_start_y, panel_w, panel_h - (content_start_y - panel_y)) and needs_scroll then
                local scroll_amt = math.floor(50 * s)
                if MOUSE.scroll_up then
                    self_state.scroll_offset = math.max(0, self_state.scroll_offset - scroll_amt)
                elseif MOUSE.scroll_down then
                    self_state.scroll_offset = math.min(max_scroll, self_state.scroll_offset + scroll_amt)
                end
            end

            -- Draw items with scroll offset and clipping
            local draw_y = ly - self_state.scroll_offset
            local clip_top = ly  -- Start BELOW outfit section
            local clip_bottom = panel_y + panel_h - math.floor(4 * s)

            -- Enable scissor clipping to prevent content from drawing over buttons
            if render and render.push_clip then
                render.push_clip(panel_x, clip_top, panel_w, clip_bottom - clip_top)
            end

            -- === HEAD & FACE ===
            if draw_y > clip_top and draw_y < clip_bottom then
                draw_text("═══ HEAD & FACE ═══", panel_x + side_pad, draw_y, UI.font_small, C.text)
            end
            draw_y = draw_y + header_h

            -- Hair (Component 2)
            if draw_y + header_h + (slider_h * 2) > clip_top and draw_y < clip_bottom then
                draw_text("Hair", panel_x + side_pad, draw_y, UI.font_small, C.accent)
            end
            draw_y = draw_y + header_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Style", self_state.hair_style, 0, 77, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.hair_style then
                    self_state.hair_style = new_val
                    if me and me.ped then invoker.call(0x262B14F48D29DE80, me.ped, 2, math.floor(self_state.hair_style), math.floor(self_state.hair_tex), 0) end
                end
            end
            draw_y = draw_y + slider_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Texture", self_state.hair_tex, 0, 63, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.hair_tex then
                    self_state.hair_tex = new_val
                    if me and me.ped then invoker.call(0x262B14F48D29DE80, me.ped, 2, math.floor(self_state.hair_style), math.floor(self_state.hair_tex), 0) end
                end
            end
            draw_y = draw_y + slider_h + spacing

            -- Masks (Component 1)
            if draw_y + header_h + (slider_h * 2) > clip_top and draw_y < clip_bottom then
                draw_text("Masks / Beards", panel_x + side_pad, draw_y, UI.font_small, C.accent)
            end
            draw_y = draw_y + header_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Style", self_state.mask_style, 0, 254, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.mask_style then
                    self_state.mask_style = new_val
                    if me and me.ped then invoker.call(0x262B14F48D29DE80, me.ped, 1, math.floor(self_state.mask_style), math.floor(self_state.mask_tex), 0) end
                end
            end
            draw_y = draw_y + slider_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Texture", self_state.mask_tex, 0, 100, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.mask_tex then
                    self_state.mask_tex = new_val
                    if me and me.ped then invoker.call(0x262B14F48D29DE80, me.ped, 1, math.floor(self_state.mask_style), math.floor(self_state.mask_tex), 0) end
                end
            end
            draw_y = draw_y + slider_h + spacing

            -- Hats/Helmets (Prop 0)
            if draw_y + header_h + (slider_h * 2) > clip_top and draw_y < clip_bottom then
                draw_text("Hats / Helmets (-1=off)", panel_x + side_pad, draw_y, UI.font_small, C.accent)
            end
            draw_y = draw_y + header_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Style", self_state.hat_style, -1, 253, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.hat_style then
                    self_state.hat_style = new_val
                    if me and me.ped then
                        if math.floor(self_state.hat_style) == -1 then
                            invoker.call(0x0943E5B8E078E76E, me.ped, 0)
                        else
                            invoker.call(0x93376B65A266EB5F, me.ped, 0, math.floor(self_state.hat_style), math.floor(self_state.hat_tex), true, 0)
                        end
                    end
                end
            end
            draw_y = draw_y + slider_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Texture", self_state.hat_tex, 0, 100, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.hat_tex then
                    self_state.hat_tex = new_val
                    if me and me.ped and math.floor(self_state.hat_style) >= 0 then
                        invoker.call(0x93376B65A266EB5F, me.ped, 0, math.floor(self_state.hat_style), math.floor(self_state.hat_tex), true, 0)
                    end
                end
            end
            draw_y = draw_y + slider_h + spacing

            -- Glasses (Prop 1)
            if draw_y + header_h + (slider_h * 2) > clip_top and draw_y < clip_bottom then
                draw_text("Glasses (-1=off)", panel_x + side_pad, draw_y, UI.font_small, C.accent)
            end
            draw_y = draw_y + header_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
                new_val, h = recovery_slider("Style", self_state.glasses_style, -1, 60, panel_x + side_pad, draw_y, usable_w, s, "")
                if new_val ~= self_state.glasses_style then
                    self_state.glasses_style = new_val
                    if me and me.ped then
                        if math.floor(self_state.glasses_style) == -1 then
                            invoker.call(0x0943E5B8E078E76E, me.ped, 1)
                        else
                            invoker.call(0x93376B65A266EB5F, me.ped, 1, math.floor(self_state.glasses_style), math.floor(self_state.glasses_tex), true, 0)
                        end
                    end
                end
            end
            draw_y = draw_y + slider_h
            if draw_y + slider_h > clip_top and draw_y < clip_bottom then
