                local sb_h = panel_h - math.floor(10 * s)
                local thumb_h = math.max(math.floor(30 * s), sb_h * (content_area_h / total_content_h))
                local thumb_y = panel_y + math.floor(5 * s) + (sb_h - thumb_h) * (self_state.scroll_offset / max_scroll)

                draw_rect(sb_x, panel_y + math.floor(5 * s), sb_w, sb_h, C.checkbox_off, math.floor(2 * s))
                draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(2 * s))

                -- Scrollbar drag
                if is_mouse_in(sb_x - math.floor(5 * s), panel_y, sb_w + math.floor(10 * s), panel_h) and MOUSE.pressed then
                    local rel_y = MOUSE.y - panel_y - math.floor(5 * s) - thumb_h / 2
                    local scroll_pct = rel_y / (sb_h - thumb_h)
                    self_state.scroll_offset = math.max(0, math.min(max_scroll, scroll_pct * max_scroll))
