            local toggle_x = panel_x + item_w + pad - toggle_w
            local toggle_y = ly + math.floor(4 * s)
            local toggle_h = math.floor(30 * s)
            hover = is_mouse_in(toggle_x, toggle_y, toggle_w, toggle_h)
            local toggle_bg = self_state.aimbot_enabled and color(60, 180, 60, 255) or color(160, 40, 40, 255)
            if hover then
                toggle_bg = self_state.aimbot_enabled and color(80, 200, 80, 255) or color(180, 60, 60, 255)
            end
            draw_rect(toggle_x, toggle_y, toggle_w, toggle_h, toggle_bg, math.floor(4 * s))
            local toggle_text = self_state.aimbot_enabled and "ON" or "OFF"
            draw_text(toggle_text, toggle_x + math.floor(23 * s), toggle_y + math.floor(7 * s), UI.font_small, color(255, 255, 255, 255))
            if hover and MOUSE.just_pressed then
                self_state.aimbot_enabled = not self_state.aimbot_enabled
            end

            ly = ly + status_h + math.floor(10 * s)

            -- TARGETING Section
            draw_rect(panel_x, ly, panel_w, math.floor(26 * s), C.group_header, math.floor(4 * s))
            draw_text("TARGETING", panel_x + pad, ly + math.floor(6 * s), UI.font_small, C.text)
            ly = ly + math.floor(30 * s)

            -- FOV Slider
            local slider_h = math.floor(12 * s)
            draw_text("FOV Radius: " .. math.floor(self_state.aimbot_fov) .. " pixels", panel_x + pad, ly, UI.font_tiny, color(200, 200, 200, 255))
            ly = ly + math.floor(16 * s)

            draw_rect(panel_x + pad, ly, item_w, slider_h, C.slider_bg, math.floor(5 * s))
            local fov_pct = (self_state.aimbot_fov - 50) / (400 - 50)
            local fill_w = math.floor(item_w * fov_pct)
            draw_rect(panel_x + pad, ly, fill_w, slider_h, color(100, 150, 255, 255), math.floor(5 * s))
            hover = is_mouse_in(panel_x + pad, ly - math.floor(4 * s), item_w, slider_h + math.floor(8 * s))
            if hover and MOUSE.pressed then
                local rel = MOUSE.x - (panel_x + pad)
                local pct = math.max(0, math.min(1, rel / item_w))
                self_state.aimbot_fov = 50 + (pct * (400 - 50))
            end
            ly = ly + slider_h + math.floor(18 * s)

            -- Max Range Slider
            draw_text("Max Range: " .. math.floor(self_state.aimbot_max_range) .. " meters", panel_x + pad, ly, UI.font_tiny, color(200, 200, 200, 255))
            ly = ly + math.floor(16 * s)

            draw_rect(panel_x + pad, ly, item_w, slider_h, C.slider_bg, math.floor(5 * s))
            local range_pct = (self_state.aimbot_max_range - 50) / (500 - 50)
            fill_w = math.floor(item_w * range_pct)
            draw_rect(panel_x + pad, ly, fill_w, slider_h, color(255, 150, 100, 255), math.floor(5 * s))
            hover = is_mouse_in(panel_x + pad, ly - math.floor(4 * s), item_w, slider_h + math.floor(8 * s))
            if hover and MOUSE.pressed then
                local rel = MOUSE.x - (panel_x + pad)
                local pct = math.max(0, math.min(1, rel / item_w))
                self_state.aimbot_max_range = 50 + (pct * (500 - 50))
            end
            ly = ly + slider_h + math.floor(18 * s)

            -- Smoothness Slider
            draw_text("Smoothness: " .. string.format("%.1f", self_state.aimbot_smoothness), panel_x + pad, ly, UI.font_tiny, color(200, 200, 200, 255))
            ly = ly + math.floor(16 * s)

            draw_rect(panel_x + pad, ly, item_w, slider_h, C.slider_bg, math.floor(5 * s))
            local smooth_pct = (self_state.aimbot_smoothness - 1) / (15 - 1)
            fill_w = math.floor(item_w * smooth_pct)
            draw_rect(panel_x + pad, ly, fill_w, slider_h, color(150, 255, 150, 255), math.floor(5 * s))
            hover = is_mouse_in(panel_x + pad, ly - math.floor(4 * s), item_w, slider_h + math.floor(8 * s))
            if hover and MOUSE.pressed then
                local rel = MOUSE.x - (panel_x + pad)
                local pct = math.max(0, math.min(1, rel / item_w))
                self_state.aimbot_smoothness = 1 + (pct * (15 - 1))
            end
            ly = ly + slider_h + math.floor(18 * s)

            -- Bone Target Selection
            draw_text("Target Bone:", panel_x + pad, ly, UI.font_tiny, color(200, 200, 200, 255))
            ly = ly + math.floor(16 * s)

            local bone_options = {"Head", "Neck", "Chest"}
            local bone_w = math.floor((item_w - math.floor(8 * s)) / 3)
            local bone_h = math.floor(28 * s)
            for i, bone_name in ipairs(bone_options) do
                local bone_x = panel_x + pad + ((i - 1) * (bone_w + math.floor(4 * s)))
                hover = is_mouse_in(bone_x, ly, bone_w, bone_h)
                local selected = self_state.aimbot_bone_target == i
                bg = selected and color(100, 120, 255, 255) or (hover and C.widget_hover or C.widget_bg)
                draw_rect(bone_x, ly, bone_w, bone_h, bg, math.floor(4 * s))
                local text_w = #bone_name * (UI.font_tiny * 0.55)
                local text_x = bone_x + (bone_w / 2) - (text_w / 2)
                draw_text(bone_name, text_x, ly + math.floor(7 * s), UI.font_tiny, selected and color(255, 255, 255, 255) or C.text)
                if hover and MOUSE.just_pressed then
                    self_state.aimbot_bone_target = i
                end
            end
            ly = ly + bone_h + math.floor(12 * s)

            -- OPTIONS Section
            draw_rect(panel_x, ly, panel_w, math.floor(26 * s), C.group_header, math.floor(4 * s))
            draw_text("OPTIONS", panel_x + pad, ly + math.floor(6 * s), UI.font_small, C.text)
            ly = ly + math.floor(30 * s)

            local opt_h = math.floor(30 * s)
            local options = {
                {name = "Wall Check", var = "aimbot_wall_check"},
                {name = "Show FOV Circle", var = "aimbot_show_fov"}
            }

            for _, opt in ipairs(options) do
                hover = is_mouse_in(panel_x + pad, ly, item_w, opt_h)
                bg = self_state[opt.var] and color(60, 180, 80, 200) or (hover and C.widget_hover or color(40, 40, 45, 255))
                draw_rect(panel_x + pad, ly, item_w, opt_h, bg, math.floor(4 * s))

                -- Checkbox
                local check_x = panel_x + pad + math.floor(8 * s)
                local check_size = math.floor(14 * s)
                local check_y = ly + math.floor(8 * s)
                draw_rect(check_x, check_y, check_size, check_size, color(60, 60, 65, 255), math.floor(2 * s))
                if self_state[opt.var] then
                    draw_rect(check_x + 2, check_y + 2, check_size - 4, check_size - 4, color(100, 255, 120, 255), math.floor(2 * s))
                end

                draw_text(opt.name, panel_x + pad + math.floor(28 * s), ly + math.floor(8 * s), UI.font_tiny, C.text)

                if hover and MOUSE.just_pressed then
                    self_state[opt.var] = not self_state[opt.var]
                end
                ly = ly + opt_h + math.floor(4 * s)
            end

        else
            -- Use the cleanup function when switching categories within Self tab
            cleanup_preview_clone()
        end
    end

