    local function draw_visuals_tab()
        group_header("Player ESP")
        esp_state.enabled = checkbox("Enable ESP", esp_state.enabled)
        
        if esp_state.enabled then
            separator()
            esp_state.draw_boxes = checkbox("3D Boxes", esp_state.draw_boxes)
            esp_state.draw_snaplines = checkbox("Snaplines", esp_state.draw_snaplines)
            esp_state.draw_health = checkbox("Health Bar", esp_state.draw_health)
            esp_state.draw_names = checkbox("Names", esp_state.draw_names)
            esp_state.draw_distance = checkbox("Distance", esp_state.draw_distance)
            esp_state.draw_player_list = checkbox("Player List (Side Panel)", esp_state.draw_player_list)

            -- Player List Color Mode selector
            if esp_state.draw_player_list then
                local color_modes = {"Distance", "Rainbow", "White", "Cyan", "Pink"}
                local current_mode = color_modes[esp_state.player_list_color_mode] or "Distance"
                if button("List Color: " .. current_mode) then
                    esp_state.player_list_color_mode = (esp_state.player_list_color_mode % 5) + 1
                    safe_toast("Player List Color: " .. color_modes[esp_state.player_list_color_mode])
                end
            end

            separator()
            esp_state.max_distance = slider("Max Distance", esp_state.max_distance, 100.0, 1000.0, 50.0)
        end

        group_header("Custom Screen Messages")
        esp_state.custom_message_enabled = checkbox("Enable Custom Message", esp_state.custom_message_enabled)

        if esp_state.custom_message_enabled then
            separator()

            -- Text input box with keyboard support (like Spawn tab and Player tab)
            text_label("Click the box below to type your message:")

            -- Calculate position for text input using widget_y
            local s = UI.scale
            local input_w = content_w - math.floor(20 * s)
            local input_h = math.floor(50 * s)
            local input_x = content_x + math.floor(10 * s)
            local input_y = widget_y

            -- Update widget_y to track position
            widget_y = widget_y + math.floor(20 * s)

            esp_state.custom_message_text, esp_state.custom_message_input_active, _ =
                text_input_box("Message", esp_state.custom_message_text, esp_state.custom_message_input_active,
                               input_x, widget_y, input_w, input_h)

            widget_y = widget_y + input_h + math.floor(8 * s)

            separator()

            -- Color mode selector
            local color_modes = {"White", "Rainbow", "Red", "Green", "Blue", "Yellow", "Cyan", "Pink"}
            local current_color = color_modes[esp_state.custom_message_color_mode] or "Rainbow"
            if button("Color: " .. current_color) then
                esp_state.custom_message_color_mode = (esp_state.custom_message_color_mode % 8) + 1
                safe_toast("Message Color: " .. color_modes[esp_state.custom_message_color_mode])
            end

            -- Rainbow speed slider (only show if rainbow mode)
            if esp_state.custom_message_color_mode == 2 then
                esp_state.custom_message_rainbow_speed = slider("Rainbow Speed", esp_state.custom_message_rainbow_speed, 0.1, 5.0, 0.1)
            end

            text_label("Message will appear at the top of your screen")
        end

        -- Visual Effect Auras (Collapsible Section)
        local aura_button_label = (esp_state.aura_section_collapsed and "> " or "v ") .. "Visual Effect Auras"
        if button(aura_button_label) then
            esp_state.aura_section_collapsed = not esp_state.aura_section_collapsed
        end

        -- Only show content when expanded
        if not esp_state.aura_section_collapsed then
            text_label("Toggle effects that follow you (100% visual only)")
            separator()

            -- Rainbow Lights (colored lights around you)
            esp_state.aura_rainbow_lights = checkbox("Rainbow Lights Circle", esp_state.aura_rainbow_lights)

            -- Spotlight (bright light on you from above)
            esp_state.aura_spotlight = checkbox("Spotlight From Above", esp_state.aura_spotlight)

            -- Pulsing Light (single pulsing light above)
            esp_state.aura_pulsing = checkbox("Pulsing Light", esp_state.aura_pulsing)

            -- Ground Ring (lights on the ground in a circle)
            esp_state.aura_ground_ring = checkbox("Ground Ring", esp_state.aura_ground_ring)

            -- Light Pillars (vertical beams around you)
            esp_state.aura_pillars = checkbox("Light Pillars", esp_state.aura_pillars)

            -- Color Wave (wave of colors rotating)
            esp_state.aura_color_wave = checkbox("Color Wave", esp_state.aura_color_wave)

            separator()

            -- Stop All Auras button
            if button("Stop All Effects") then
                esp_state.aura_rainbow_lights = false
                esp_state.aura_spotlight = false
                esp_state.aura_pulsing = false
                esp_state.aura_ground_ring = false
                esp_state.aura_pillars = false
                esp_state.aura_color_wave = false
                safe_toast("All effects disabled!")
            end
        end

        separator()

        esp_state.timecycle_enabled = checkbox("Enable Screen Effect", esp_state.timecycle_enabled)

        if esp_state.timecycle_enabled then
            local timecycle_list = {
                "None", "drunk", "stoned", "Drunk", "DRUG_gas_huffin", "dying",
                "death", "DeathFailMP01", "MP_Celeb_Win", "MP_Celeb_Win_Out",
                "SuccessFranklin", "SuccessTrevor", "SuccessMichael", "DrugsMichaelAliensFight",
                "DrugsMichaelAliensFightIn", "DrugsMichaelAliensFightOut", "DrugsTrevorClownsFight",
                "DrugsTrevorClownsFightIn", "DrugsTrevorClownsFightOut", "HeistCelebPass",
                "HeistCelebPassBW", "HeistCelebEnd", "HeistCelebToast", "MenuMGHeistIn",
                "MenuMGTournamentIn", "MP_race_crash", "NG_filmic01", "NG_filmic02",
                "NG_filmic03", "NG_filmic04", "NG_filmic05", "NG_filmic06",
                "NG_filmic07", "NG_filmic08", "NG_filmic09", "NG_filmic10",
                "NG_filmic11", "NG_filmic12", "NG_filmic13", "NG_filmic14"
            }

            local current_modifier = timecycle_list[esp_state.timecycle_index] or "None"
            if button("Effect: " .. current_modifier) then
                esp_state.timecycle_index = (esp_state.timecycle_index % #timecycle_list) + 1
                esp_state.timecycle_modifier = timecycle_list[esp_state.timecycle_index]
            end

            if esp_state.timecycle_modifier ~= "None" then
                esp_state.timecycle_strength = slider("Effect Strength", esp_state.timecycle_strength, 0.0, 2.0, 0.1)
            end
        end
    end

