    -- =========================================================================
    -- WEAPON TAB - WORKING IMPLEMENTATION
    -- =========================================================================
    local function draw_weapon_tab()
        group_header("Ammo & Clip")
        weapon_features.infinite_ammo = checkbox("Infinite Ammo", weapon_features.infinite_ammo)
        weapon_features.no_reload = checkbox("No Reload", weapon_features.no_reload)
        
        group_header("Damage")
        weapon_features.damage_multiplier = slider("Damage Multiplier", weapon_features.damage_multiplier, 1.0, 10.0, 0.5)
        
        group_header("Actions")
        if button("Give All Weapons") then
            local me = players and players.me and players.me()
            if me and me.ped then
                local given_count = 0
                local GIVE_WEAPON = 0xbf0fd6e56c964fcb
                for _, weapon_name in ipairs(ALL_WEAPONS) do
                    local weapon_hash = invoker.call(0xD24D37CC275948CC, weapon_name)
                    if weapon_hash and weapon_hash.int and weapon_hash.int ~= 0 then
                        invoker.call(GIVE_WEAPON, me.ped, weapon_hash.int, 9999, false, true)
                        given_count = given_count + 1
                    end
                end
                safe_toast("Given " .. given_count .. " weapons!")
            end
        end
        
        if button("Remove All Weapons") then
            local me = players and players.me and players.me()
            if me and me.ped then
                local REMOVE_WEAPONS = 0xf25df915fa38c5f3
                invoker.call(REMOVE_WEAPONS, me.ped, true)
                safe_toast("All weapons removed!")
            end
        end
        
        if button("Max Ammo All") then
            local me = players and players.me and players.me()
            if me and me.ped then
                local count = 0
                local ADD_AMMO = 0x78f0424c34306220
                for _, w in ipairs(ALL_WEAPONS) do
                    local weapon_hash = invoker.call(0xD24D37CC275948CC, w)
                    if weapon_hash and weapon_hash.int and weapon_hash.int ~= 0 then
                        invoker.call(ADD_AMMO, me.ped, weapon_hash.int, 9999)
                        count = count + 1
                    end
                end
                safe_toast("Ammo added to " .. count .. " weapons!")
            end
        end

        group_header("Vehicle Shooter")
        weapon_features.vehicle_shooter_active = checkbox("Enable Vehicle Shooter", weapon_features.vehicle_shooter_active)

        if weapon_features.vehicle_shooter_active then
            -- Vehicle selection (compact single button)
            local shooter_vehicles = {
                {"Cargobob", "cargobob"},
                {"Cargo Plane", "cargoplane"},
                {"Fire Truck", "firetruk"},
                {"Faggio", "faggio"},
                {"Train", "freight"}
            }

            weapon_features.shooter_vehicle_index = weapon_features.shooter_vehicle_index or 1
            local current_veh = shooter_vehicles[weapon_features.shooter_vehicle_index]

            if button("Vehicle: " .. current_veh[1]) then
                -- Cycle to next vehicle
                weapon_features.shooter_vehicle_index = weapon_features.shooter_vehicle_index + 1
                if weapon_features.shooter_vehicle_index > #shooter_vehicles then
                    weapon_features.shooter_vehicle_index = 1
                end
                local new_veh = shooter_vehicles[weapon_features.shooter_vehicle_index]
                weapon_features.vehicle_shooter_name = new_veh[2]
                weapon_features.vehicle_shooter_loaded = false -- Force reload
                weapon_features.vehicle_shooter_hash = nil -- Reset hash to trigger new model load
            end
        end
    end

