    -- Helper function to change player model
    local function change_player_model(model_hash)
        -- Get player ID and ped
        local player_id_result = invoker.call(0x4F8644AF03D0E0D6) -- PLAYER_ID
        if not player_id_result then
            safe_toast("Failed to get player ID")
            return
        end
        local player_id = player_id_result.int

        -- Calculate hash if it's a string
        local hash = model_hash
        if type(model_hash) == "string" then
            local hash_result = invoker.call(0xD24D37CC275948CC, model_hash) -- GET_HASH_KEY
            if hash_result then
                hash = hash_result.int
            else
                safe_toast("Failed to get model hash")
                return
            end
        end

        -- Request model
        if N.REQUEST_MODEL then
            N.REQUEST_MODEL(hash)
        else
            invoker.call(0x963D27A58DF860AC, hash) -- REQUEST_MODEL
        end

        -- Wait for model to load
        local timeout = 0
        while timeout < 100 do
            local loaded_result
            if N.HAS_MODEL_LOADED then
                loaded_result = N.HAS_MODEL_LOADED(hash)
            else
                loaded_result = invoker.call(0x98A4EB5D89A0C952, hash) -- HAS_MODEL_LOADED
                if loaded_result then loaded_result = loaded_result.bool end
            end

            if loaded_result then break end

            util.yield(10)
            timeout = timeout + 1
        end

        if timeout >= 100 then
            safe_toast("Failed to load model (timeout)")
            return
        end

        -- Change model
        if N.SET_PLAYER_MODEL then
            N.SET_PLAYER_MODEL(player_id, hash)
        else
            invoker.call(0x00A1CADD00108836, player_id, hash) -- SET_PLAYER_MODEL
        end

        -- Clean up
        if N.SET_MODEL_AS_NO_LONGER_NEEDED then
            N.SET_MODEL_AS_NO_LONGER_NEEDED(hash)
        else
            invoker.call(0xE532F5D78798DAAB, hash) -- SET_MODEL_AS_NO_LONGER_NEEDED
        end

        model_state.current_model = model_hash
        safe_toast("Model changed to " .. (type(model_hash) == "string" and model_hash or "custom"))
        debug_info("MODEL", "Changed to: " .. tostring(model_hash))
    end

