    local function teleport_to(x, y, z, name)
        local me = players and players.me and players.me()
        if not me then
            safe_toast("Cannot get player")
            return
        end

        local entity = (me.vehicle and me.vehicle ~= 0) and me.vehicle or me.ped
        if entity and N.SET_ENTITY_COORDS_NO_OFFSET then
            pcall(N.SET_ENTITY_COORDS_NO_OFFSET, entity, x, y, z, false, false, false)
            safe_toast("Teleported to " .. name)
        else
            safe_toast("Teleport not available")
        end
    end

    local function draw_model_tab()
        local s = UI.scale
        local base_x = content_x
        local base_y = widget_y
        local total_w = content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- TWO columns: category list (left) + models panel (right)
        local gap = math.floor(10 * s)
        local list_w = math.floor(160 * s)
        local panel_w = total_w - list_w - gap - math.floor(10 * s)

        -- LEFT: Category List
        local list_x = base_x + math.floor(5 * s)
        local list_y = base_y

        local header_h = math.floor(24 * s)
        draw_rect(list_x, list_y, list_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Model Types", list_x + math.floor(8 * s), list_y + math.floor(5 * s), UI.font_small, C.text)
        list_y = list_y + header_h + 2

        draw_rect(list_x, list_y, list_w, total_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local item_h = math.floor(36 * s)
        local py = list_y + math.floor(5 * s)

        for i, cat in ipairs(MODEL_CATEGORIES) do
            local is_selected = (model_state.selected_category == i)
            local label = cat.icon .. "  " .. cat.name
            if selectable(label, is_selected, nil, list_x + 2, py, list_w - 4, item_h - 4) then
                model_state.selected_category = i
                model_state.scroll_offset = 0
            end
            py = py + item_h
        end

        -- RIGHT: Models Panel
        local panel_x = list_x + list_w + gap
        local panel_y = base_y

        local selected_cat = MODEL_CATEGORIES[model_state.selected_category]

        -- Get models based on selected category
        local models = {}
        if selected_cat.name == "Player Models" then
            models = PLAYER_MODELS
        elseif selected_cat.name == "Animals" then
            models = ANIMAL_MODELS
        elseif selected_cat.name == "NPCs" then
            models = NPC_MODELS
        elseif selected_cat.name == "Gang Members" then
            models = GANG_MODELS
        elseif selected_cat.name == "Emergency" then
            models = EMERGENCY_MODELS
        end

        draw_rect(panel_x, panel_y, panel_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text(selected_cat.name, panel_x + math.floor(8 * s), panel_y + math.floor(5 * s), UI.font_small, C.text)

        local panel_content_y = panel_y + header_h + 2
        local panel_content_h = total_h - header_h - 2

        draw_rect(panel_x, panel_content_y, panel_w, panel_content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Scrollable model list
        local btn_h = math.floor((UI.button_h or 32) * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)
        local usable_h = panel_content_h - side_pad * 2
        local total_content = #models * (btn_h + btn_gap)
        local max_scroll = math.max(0, total_content - usable_h)

        local btn_y = panel_content_y + side_pad - model_state.scroll_offset

        for i, model in ipairs(models) do
            if btn_y + btn_h >= panel_content_y and btn_y <= panel_content_y + panel_content_h then
                local hover = is_mouse_in(panel_x + side_pad, btn_y, panel_w - side_pad * 2, btn_h)

                draw_rect(panel_x + side_pad, btn_y, panel_w - side_pad * 2, btn_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                draw_text(model.name, panel_x + side_pad + math.floor(8 * s), btn_y + math.floor(8 * s), UI.font_small, C.text)

                if hover and MOUSE.pressed then
                    change_player_model(model.hash)
                end
            end
            btn_y = btn_y + btn_h + btn_gap
        end

        -- Scroll shadows for model list
        if total_content > usable_h then
            local shadow_h = math.floor(8 * s)
            if model_state.scroll_offset > 0 then
                draw_rect(panel_x, panel_content_y, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            if model_state.scroll_offset < max_scroll then
                draw_rect(panel_x, panel_content_y + usable_h - shadow_h, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
        end

        -- Scrollbar for panel
        if total_content > usable_h then
            local sb_w = math.floor(6 * s)
            local sb_x = panel_x + panel_w - sb_w - math.floor(1 * s)
            local sb_y = panel_content_y + side_pad
            local sb_h = usable_h
            local thumb_h = math.max(math.floor(30 * s), (usable_h / total_content) * sb_h)
            local thumb_y = sb_y + (model_state.scroll_offset / max_scroll) * (sb_h - thumb_h)

            draw_rect(sb_x, sb_y, sb_w, sb_h, C.track, math.floor(3 * s))
            draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.thumb, math.floor(3 * s))

            if is_mouse_in(sb_x, thumb_y, sb_w, thumb_h) and MOUSE.pressed then
                local rel_y = MOUSE.y - thumb_y
                model_state.scroll_offset = math.max(0, math.min(max_scroll, ((MOUSE.y - sb_y) / (sb_h - thumb_h)) * max_scroll))
            end
        end

        -- Show current model info at bottom
        if model_state.current_model ~= "" then
            local info_h = math.floor(24 * s)
            local info_y = panel_content_y + panel_content_h - info_h - math.floor(4 * s)
            draw_rect(panel_x + side_pad, info_y, panel_w - side_pad * 2, info_h, C.accent, math.floor((UI.widget_rounding or 5) * s))
            draw_text("Current: " .. model_state.current_model, panel_x + side_pad + math.floor(8 * s), info_y + math.floor(4 * s), UI.font_small, C.text)
        end
    end

    local function draw_world_tab()
        local s = UI.scale
        local base_x = content_x
        local base_y = widget_y
        local total_w = content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- TWO columns: category list (left) + locations panel (right)
        local gap = math.floor(10 * s)
        local list_w = math.floor(160 * s)
        local panel_w = total_w - list_w - gap - math.floor(10 * s)

        -- LEFT: Category List
        local list_x = base_x + math.floor(5 * s)
        local list_y = base_y

        local header_h = math.floor(24 * s)
        draw_rect(list_x, list_y, list_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Categories", list_x + math.floor(8 * s), list_y + math.floor(5 * s), UI.font_small, C.text)
        list_y = list_y + header_h + 2

        draw_rect(list_x, list_y, list_w, total_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local item_h = math.floor(36 * s)
        local py = list_y + math.floor(5 * s)

        for i, cat in ipairs(TELEPORT_CATEGORIES) do
            local is_selected = (world_state.selected_category == i)
            local label = cat.icon .. "  " .. cat.name
            if selectable(label, is_selected, nil, list_x + 2, py, list_w - 4, item_h - 4) then
                world_state.selected_category = i
                world_state.list_scroll = 0
            end
            py = py + item_h
        end

        -- RIGHT: Locations Panel (side panel like player info)
        local panel_x = list_x + list_w + gap
        local panel_y = base_y

        local selected_cat = TELEPORT_CATEGORIES[world_state.selected_category]
        local locations = TELEPORT_LOCATIONS[selected_cat.name] or {}

        draw_rect(panel_x, panel_y, panel_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text(selected_cat.name .. " Locations", panel_x + math.floor(8 * s), panel_y + math.floor(5 * s), UI.font_small, C.text)
        panel_y = panel_y + header_h + 2

        draw_rect(panel_x, panel_y, panel_w, total_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Draw location buttons in panel
        local btn_h = math.floor((UI.button_h or 32) * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)
        local ly = panel_y + math.floor(8 * s)

        -- TELEPORT TO WAYPOINT (special button)
        if small_button("Teleport to Waypoint", panel_x + side_pad, ly, panel_w - side_pad * 2, btn_h) then
            local waypoint_blip = HUD.GET_FIRST_BLIP_INFO_ID(8) -- 8 = waypoint blip
            if waypoint_blip and waypoint_blip ~= 0 then
                local waypoint_pos = HUD.GET_BLIP_INFO_ID_COORD(waypoint_blip)
                if waypoint_pos then
                    local ground_z = 0.0
                    local found_ground = false
                    -- Try to get ground Z coord
                    for z_offset = 0, 1000, 50 do
                        local test_z = z_offset * 1.0
                        local result = GAMEPLAY.GET_GROUND_Z_FOR_3D_COORD(waypoint_pos.x, waypoint_pos.y, test_z, ground_z, false, false)
                        if result then
                            ground_z = result
                            found_ground = true
                            break
                        end
                    end

                    local final_z = found_ground and ground_z or 1000.0
                    teleport_to(waypoint_pos.x, waypoint_pos.y, final_z, "Waypoint")
                else
                    safe_toast("Could not get waypoint position!")
                end
            else
                safe_toast("No waypoint set! Mark one on the map.")
            end
        end
        ly = ly + btn_h + btn_gap

        -- Separator
        draw_rect(panel_x + side_pad, ly + math.floor(8 * s), panel_w - side_pad * 2, 1, color(80, 80, 80, 100), 0)
        ly = ly + math.floor(20 * s)

        for _, loc in ipairs(locations) do
            if small_button(loc.name, panel_x + side_pad, ly, panel_w - side_pad * 2, btn_h) then
                teleport_to(loc.x, loc.y, loc.z, loc.name)
            end
            ly = ly + btn_h + btn_gap
        end
    end

