    -- Helper to draw a slider in heist panel
    local function heist_slider(label, value, min, max, px, py, pw, s)
        local slider_w = pw
        local slider_h = math.floor(36 * s)
        local track_h = math.floor(6 * s)
        local hover = is_mouse_in(px, py, slider_w, slider_h)

        draw_rect(px, py, slider_w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
        draw_text(string.format("%s: %d%%", label, math.floor(value)), px + math.floor(8 * s), py + math.floor(4 * s), UI.font_small, C.text)

        local track_y = py + math.floor(22 * s)
        local track_x = px + math.floor(8 * s)
        local track_w = slider_w - math.floor(16 * s)

        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))
        local pct = (value - min) / (max - min)
        draw_rect(track_x, track_y, track_w * pct, track_h, C.accent, math.floor(3 * s))

        if hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
            value = min + (max - min) * mouse_pct
        end

        return value, slider_h
    end

    -- Helper to draw a casino slider (no % sign, with description)
    local function casino_slider(label, value, min, max, px, py, pw, s, descriptions)
        local slider_w = pw
        local slider_h = math.floor(36 * s)
        local track_h = math.floor(6 * s)
        local hover = is_mouse_in(px, py, slider_w, slider_h)

        draw_rect(px, py, slider_w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))

        -- Build label with description
        local desc = ""
        if descriptions and descriptions[math.floor(value)] then
            desc = " - " .. descriptions[math.floor(value)]
        end
        draw_text(string.format("%s: %d%s", label, math.floor(value), desc), px + math.floor(8 * s), py + math.floor(4 * s), UI.font_small, C.text)

        local track_y = py + math.floor(22 * s)
        local track_x = px + math.floor(8 * s)
        local track_w = slider_w - math.floor(16 * s)

        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))
        local pct = (value - min) / (max - min)
        draw_rect(track_x, track_y, track_w * pct, track_h, C.accent, math.floor(3 * s))

        if hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
            value = min + (max - min) * mouse_pct
        end

        return value, slider_h
    end

