        -- Calculate total content height
        local total_content_h = 0
        for _, item in ipairs(items) do
            if item.type == "section" then
                total_content_h = total_content_h + math.floor(20 * s) + section_gap
            elseif item.type == "slider" then
                total_content_h = total_content_h + math.floor(36 * s) + btn_gap
            else
                total_content_h = total_content_h + btn_h + btn_gap
            end
        end

        -- Check if scrolling needed (add extra padding at bottom to prevent overflow)
        local content_area_h = panel_h - math.floor(16 * s)
        local needs_scroll = total_content_h > content_area_h
        local max_scroll = math.max(0, total_content_h - content_area_h + math.floor(30 * s))

        -- Clamp scroll
        heist_state.scroll_offset = math.max(0, math.min(heist_state.scroll_offset, max_scroll))

        -- Handle mouse wheel scroll in panel
        if is_mouse_in(panel_x, panel_y, panel_w, panel_h) and needs_scroll then
            local scroll_amt = math.floor(50 * s)
            if MOUSE.scroll_up then
                heist_state.scroll_offset = math.max(0, heist_state.scroll_offset - scroll_amt)
            elseif MOUSE.scroll_down then
                heist_state.scroll_offset = math.min(max_scroll, heist_state.scroll_offset + scroll_amt)
            end
        end

        -- Draw items with scroll offset
        local ly = panel_y + math.floor(8 * s) - heist_state.scroll_offset
        local clip_top = panel_y + math.floor(4 * s)
        local clip_bottom = panel_y + panel_h - math.floor(8 * s)

        for _, item in ipairs(items) do
            local item_h_current = btn_h
            if item.type == "section" then
                item_h_current = math.floor(20 * s)
            elseif item.type == "slider" then
                item_h_current = math.floor(36 * s)
            end

            -- Only draw if visible (within clip bounds)
            if ly + item_h_current > clip_top and ly < clip_bottom then
                if item.type == "section" then
                    draw_text(item.text, panel_x + side_pad, ly + math.floor(2 * s), UI.font_small, C.accent)
                    ly = ly + item_h_current + section_gap
                elseif item.type == "slider" then
                    local new_val, h = heist_slider(item.text, item.state[item.key], item.min, item.max, panel_x + side_pad, ly, usable_w, s)
                    item.state[item.key] = new_val
                    ly = ly + h + btn_gap
                else
                    if small_button(item.text, panel_x + side_pad, ly, usable_w, btn_h) then
                        if item.action and account and account.stats then
                            pcall(item.action)
                        end
                    end
                    ly = ly + btn_h + btn_gap
                end
            else
                -- Skip drawing but still advance position
                if item.type == "section" then
                    ly = ly + item_h_current + section_gap
                elseif item.type == "slider" then
                    ly = ly + math.floor(36 * s) + btn_gap
                else
                    ly = ly + btn_h + btn_gap
                end
            end
        end

        -- Scroll shadows
        if needs_scroll then
            local shadow_h = math.floor(8 * s)
            if heist_state.scroll_offset > 0 then
                draw_rect(panel_x, panel_y, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            if heist_state.scroll_offset < max_scroll then
                draw_rect(panel_x, panel_y + panel_h - shadow_h, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
        end

        -- Draw scroll indicator if needed
        if needs_scroll then
            local sb_w = math.floor(4 * s)
            local sb_x = panel_x + panel_w - sb_w - math.floor(1 * s)
            local sb_h = panel_h - math.floor(10 * s)
            local thumb_h = math.max(math.floor(30 * s), sb_h * (content_area_h / total_content_h))
            local thumb_y = panel_y + math.floor(5 * s) + (sb_h - thumb_h) * (heist_state.scroll_offset / max_scroll)

            draw_rect(sb_x, panel_y + math.floor(5 * s), sb_w, sb_h, C.checkbox_off, math.floor(2 * s))
            draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(2 * s))

            -- Scrollbar drag
            if is_mouse_in(sb_x - math.floor(5 * s), panel_y, sb_w + math.floor(10 * s), panel_h) and MOUSE.pressed then
                local rel_y = MOUSE.y - panel_y - math.floor(5 * s) - thumb_h / 2
                local scroll_pct = rel_y / (sb_h - thumb_h)
                heist_state.scroll_offset = math.max(0, math.min(max_scroll, scroll_pct * max_scroll))
            end
        end
    end

    -- =========================================================================
    -- ONLINE TAB - CASINO AND OTHER ONLINE FEATURES
    -- =========================================================================

    local ONLINE_CATEGORIES = {
        {name = "Weather", icon = ""},
        {name = "Time", icon = ""},
        {name = "World", icon = ""},
        {name = "Casino", icon = ""},
        {name = "Radio", icon = ""},
    }

    local online_state = {
        selected_category = 1,
        scroll_offset = 0,
        -- Weather
        selected_weather = 1,
        freeze_weather = false,
        -- Time
        time_hour = 12,
        time_minute = 0,
        time_second = 0,
        time_override = false,
        freeze_time = false,
        -- World
        slow_motion_speed = 1.0,
        traffic_density = 1.0,
        apply_traffic_density = false,
        -- Radio
        selected_radio = 1,
        bus_count = 1,
        festive_bus_mode = false,
        festive_bus_instances = {},
    }

    -- Radio station hashes (defined here so festive bus callback can access them)
    local radio_hashes = {
        "RADIO_01_CLASS_ROCK", "RADIO_02_POP", "RADIO_03_HIPHOP_NEW",
        "RADIO_04_PUNK", "RADIO_05_TALK_01", "RADIO_06_COUNTRY",
        "RADIO_07_DANCE_01", "RADIO_08_MEXICAN", "RADIO_09_HIPHOP_OLD",
        "RADIO_11_TALK_02", "RADIO_12_REGGAE", "RADIO_13_JAZZ",
        "RADIO_14_DANCE_02", "RADIO_15_MOTOWN", "RADIO_16_SILVERLAKE",
        "RADIO_17_FUNK", "RADIO_18_90S_ROCK", "RADIO_19_USER",
        "RADIO_20_THELAB", "RADIO_21_DLC_XM17", "RADIO_22_DLC_BATTLE_MIX1_RADIO",
        "RADIO_23_DLC_XM19_RADIO", "RADIO_27_DLC_PRHEI4", "RADIO_34_DLC_HEI4_MLR"
    }

    -- Helper to draw online panel content with scrolling (matching heist pattern)
    local function draw_online_panel_content(panel_x, panel_y, panel_w, panel_h)
        local s = UI.scale
        local btn_h = math.floor(28 * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)
        local section_gap = math.floor(12 * s)
        local usable_w = panel_w - side_pad * 2

        local cat = ONLINE_CATEGORIES[online_state.selected_category]

        -- Build content list for current category
        local items = {}

        local function add_section(title)
            table.insert(items, {type = "section", text = title})
        end

        local function add_button(label, callback)
            table.insert(items, {type = "button", text = label, action = callback})
        end

        local function add_slider(label, state_table, key, min, max)
            table.insert(items, {type = "slider", text = label, state = state_table, key = key, min = min, max = max})
        end

        local function add_casino_slider(label, state_table, key, min, max, descriptions)
            table.insert(items, {type = "casino_slider", text = label, state = state_table, key = key, min = min, max = max, descriptions = descriptions})
        end

        local function add_text(text)
            table.insert(items, {type = "text", text = text})
        end

        local function add_checkbox(label, state_table, key, callback)
            table.insert(items, {type = "checkbox", text = label, state = state_table, key = key, action = callback})
        end

        -- ===================== WEATHER =====================
        if cat.name == "Weather" then
            add_section("Weather Control")
            local weather_types = {"Extra Sunny", "Clear", "Cloudy", "Smog", "Foggy", "Overcast", "Rain", "Thunder", "Clearing", "Neutral", "Snow", "Blizzard"}
            local weather_ids = {"EXTRASUNNY", "CLEAR", "CLOUDS", "SMOG", "FOGGY", "OVERCAST", "RAIN", "THUNDER", "CLEARING", "NEUTRAL", "SNOW", "BLIZZARD"}

            add_text("Current: " .. weather_types[online_state.selected_weather])

            for i, wname in ipairs(weather_types) do
                add_button(wname, function()
                    online_state.selected_weather = i
                    local weather_id = weather_ids[i]
                    debug_info("WEATHER", "Setting weather to: " .. weather_id)

                    -- Use ZODIAC's weather native
                    pcall(natives.SET_WEATHER_TYPE_ZODIAC, weather_id)
                    safe_toast("Weather: " .. wname)
                    debug_info("WEATHER", "Weather changed to " .. wname)
                end)
            end

            add_section("Options")
            add_checkbox("Freeze Weather", online_state, "freeze_weather", function()
                if online_state.freeze_weather then
                    safe_toast("Freeze Weather: ON")
                    debug_info("WEATHER", "Freeze weather ENABLED")
                else
                    safe_toast("Freeze Weather: OFF")
                    debug_info("WEATHER", "Freeze weather DISABLED")
                end
            end)

        -- ===================== TIME =====================
        elseif cat.name == "Time" then
            add_section("Time Presets")
            add_button("Morning (6:00)", function()
                online_state.time_override = true
                online_state.time_hour = 6
                online_state.time_minute = 0
                online_state.time_second = 0
                debug_info("TIME", "Time override: Morning (6:00)")
                safe_toast("Time: Morning")
            end)
            add_button("Noon (12:00)", function()
                online_state.time_override = true
                online_state.time_hour = 12
                online_state.time_minute = 0
                online_state.time_second = 0
                debug_info("TIME", "Time override: Noon (12:00)")
                safe_toast("Time: Noon")
            end)
            add_button("Evening (18:00)", function()
                online_state.time_override = true
                online_state.time_hour = 18
                online_state.time_minute = 0
                online_state.time_second = 0
                debug_info("TIME", "Time override: Evening (18:00)")
                safe_toast("Time: Evening")
            end)
            add_button("Midnight (0:00)", function()
                online_state.time_override = true
                online_state.time_hour = 0
                online_state.time_minute = 0
                online_state.time_second = 0
                debug_info("TIME", "Time override: Midnight (0:00)")
                safe_toast("Time: Midnight")
            end)
            add_button("Disable Time Override", function()
                online_state.time_override = false
                debug_info("TIME", "Time override disabled")
                safe_toast("Time Override: OFF")
            end)

            add_section("Options")
            add_checkbox("Freeze Time", online_state, "freeze_time", function()
                if online_state.freeze_time then
                    safe_toast("Freeze Time: ON")
                    debug_info("TIME", "Freeze time ENABLED")
                else
                    safe_toast("Freeze Time: OFF")
                    debug_info("TIME", "Freeze time DISABLED")
                end
            end)

        -- ===================== WORLD =====================
        elseif cat.name == "World" then
            add_section("Speed & Physics")
            add_slider("Slow Motion (0.1-1.0)", online_state, "slow_motion_speed", 0.1, 1.0)
            add_button("Apply Slow Motion", function()
                debug_info("WORLD", "Setting time scale to: " .. online_state.slow_motion_speed)
                pcall(natives.SET_TIME_SCALE, online_state.slow_motion_speed)
                safe_toast("Slow Motion: " .. string.format("%.1fx", online_state.slow_motion_speed))
                debug_info("WORLD", "Slow motion applied")
            end)
            add_button("Reset Speed", function()
                online_state.slow_motion_speed = 1.0
                debug_info("WORLD", "Resetting time scale to 1.0")
                pcall(natives.SET_TIME_SCALE, 1.0)
                safe_toast("Speed Reset")
                debug_info("WORLD", "Speed reset complete")
            end)

            add_section("Population")
