    -- ===== CONSTRUCTOR UI =====

    local function draw_constructor_ui()
        local s = UI.scale  -- UI scale factor (REQUIRED!)

        -- Get screen dimensions (Lexis API)
        local screen_w, screen_h = 1920, 1080
        if game and game.resolution then
            local res = game.resolution()
            if res then
                screen_w = res.x or 1920
                screen_h = res.y or 1080
            end
        end

        local base_x, base_y = UI.x + UI.w + math.floor(10 * s), UI.y
        local total_w = screen_w - base_x - math.floor(10 * s)
        local total_h = UI.h

        -- Background
        draw_rect(base_x, base_y, total_w, total_h, C.bg, math.floor((UI.widget_rounding or 5) * s))

        -- Tabs
        local tab_names = {"Objects", "Properties", "Save/Load", "Settings"}
        local tab_h = math.floor(35 * s)
        local tab_w = total_w / #tab_names

        for i, name in ipairs(tab_names) do
            local tab_x = base_x + (i - 1) * tab_w
            local is_active = (constructor.ui_tab == i)
            local is_hover = is_mouse_in(tab_x, base_y, tab_w, tab_h)

            local tab_col = is_active and C.accent or (is_hover and C.sidebar_hover or C.sidebar)
            draw_rect(tab_x, base_y, tab_w, tab_h, tab_col, 0)
            -- Approximate text width (no get_text_width function in Lexis)
            local text_w = #name * (UI.font_small * 0.6)
            draw_text(name, tab_x + tab_w / 2 - text_w / 2, base_y + (tab_h - UI.font_small) / 2, UI.font_small, is_active and C.text or C.text_dim)

            if is_hover and MOUSE.just_pressed then
                constructor.ui_tab = i
                -- Cancel attach mode when switching tabs
                if constructor.attach_mode then
                    constructor.attach_mode = false
                    constructor.attach_source = nil
                end
            end
        end

        local content_y = base_y + tab_h + math.floor(10 * s)
        local content_h = total_h - tab_h - math.floor(20 * s)
        local panel_bottom = content_y + content_h
        local max_scroll = 0

        -- Helper to check if element is visible (for scroll clipping)
        local function is_visible(y_pos, height)
            return y_pos + height > content_y and y_pos < panel_bottom
        end

        -- Tab Content
        if constructor.ui_tab == 1 then
            -- OBJECTS TAB
            local start_y = content_y
            local scroll_y = start_y - constructor.objects_scroll

            if is_visible(scroll_y, math.floor(25 * s)) then
                draw_text("Object List", base_x + math.floor(10 * s), scroll_y, UI.font_small, C.accent)
            end
            scroll_y = scroll_y + math.floor(30 * s)

            local list_y = scroll_y
            local item_h = math.floor(30 * s)

            -- Spawn new object button
            if is_visible(list_y, item_h) then
                if small_button("+ Spawn Prop", base_x + math.floor(10 * s), list_y, total_w - math.floor(20 * s), item_h) then
                    if constructor.selected_prop_hash ~= "" then
                        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int
                        local pos = invoker.call(0x3FEF770D40960D5A, player_ped, true).scr_vec3
                        local heading = invoker.call(0xE83D4F9BA2A38914, player_ped).float

                        -- Calculate spawn position 3 units in front of player
                        local rad = math.rad(heading)
                        local spawn_pos = {
                            x = pos.x - math.sin(rad) * 3,
                            y = pos.y + math.cos(rad) * 3,
                            z = pos.z  -- Spawn at player height, not below
                        }

                        local obj = create_constructor_object(constructor.selected_prop_hash, spawn_pos)
                        if obj then
                            constructor.selected_object = obj
                            constructor.selected_index = #constructor.objects
                            -- Auto enter placement mode so user can move it immediately
                            enter_placement_mode()
                            safe_toast("Spawned: " .. obj.model .. " - Use WASD to move!")
                        end
                    else
                        safe_toast("Select a prop model first!")
                    end
                end
            end
            list_y = list_y + item_h + math.floor(5 * s)

            -- SEARCH BAR
            constructor.prop_search_query = constructor.prop_search_query or ""
            constructor.prop_search_focused = constructor.prop_search_focused or false

            local search_h = math.floor(32 * s)
            local search_x = base_x + math.floor(10 * s)
            local search_w = total_w - math.floor(20 * s)

            if is_visible(list_y, search_h) then
                local search_hover = is_mouse_in(search_x, list_y, search_w, search_h)

                -- Click to focus/unfocus
                local clear_btn_w = math.floor(24 * s)
                local clear_x = search_x + search_w - clear_btn_w - math.floor(2 * s)
                local on_clear_btn = #constructor.prop_search_query > 0 and is_mouse_in(clear_x, list_y, clear_btn_w, search_h)

                if search_hover and MOUSE.just_pressed and not on_clear_btn then
                    constructor.prop_search_focused = not constructor.prop_search_focused
                end

                -- Keyboard input
                if constructor.prop_search_focused and input and input.key then
                    if input.key(0x08).just_pressed then -- Backspace
                        if #constructor.prop_search_query > 0 then
                            constructor.prop_search_query = constructor.prop_search_query:sub(1, -2)
                        end
                    end
                    for code = 0x30, 0x39 do -- 0-9
                        if input.key(code).just_pressed then
                            constructor.prop_search_query = constructor.prop_search_query .. string.char(code)
                        end
                    end
                    for code = 0x41, 0x5A do -- A-Z
                        if input.key(code).just_pressed then
                            constructor.prop_search_query = constructor.prop_search_query .. string.char(code):lower()
                        end
                    end
                    if input.key(0x20).just_pressed then -- Space
                        constructor.prop_search_query = constructor.prop_search_query .. " "
                    end
                end

                -- Draw search box
                local search_bg = constructor.prop_search_focused and C.widget_hover or (search_hover and C.widget_hover or C.widget_bg)
                draw_rect(search_x, list_y, search_w, search_h, search_bg, math.floor(4 * s))

                -- Focused border
                if constructor.prop_search_focused then
                    draw_rect(search_x, list_y, search_w, math.floor(2 * s), C.accent, math.floor(6 * s))
                    draw_rect(search_x, list_y + search_h - math.floor(2 * s), search_w, math.floor(2 * s), C.accent, math.floor(6 * s))
                    draw_rect(search_x, list_y, math.floor(2 * s), search_h, C.accent, math.floor(6 * s))
                    draw_rect(search_x + search_w - math.floor(2 * s), list_y, math.floor(2 * s), search_h, C.accent, math.floor(6 * s))
                end

                -- Clear button
                if #constructor.prop_search_query > 0 then
                    local clear_hover = is_mouse_in(clear_x, list_y, clear_btn_w, search_h)
                    draw_rect(clear_x, list_y + math.floor(2 * s), clear_btn_w, search_h - math.floor(4 * s), clear_hover and color(80,80,80,200) or color(60,60,60,180), math.floor(4 * s))
                    draw_text_centered("X", clear_x, list_y, clear_btn_w, search_h, UI.font_small, clear_hover and color(255,100,100,255) or C.text_dim)
                    if clear_hover and MOUSE.just_pressed then
                        constructor.prop_search_query = ""
                    end
                end

                -- Search text
                local display_text = constructor.prop_search_query
                if constructor.prop_search_focused then
                    display_text = display_text .. "_"
                end
                local text_x = search_x + math.floor(8 * s)
                if #constructor.prop_search_query == 0 then
                    draw_text("Search props...", text_x, list_y + math.floor(8 * s), UI.font_tiny, color(100,100,100,180))
                else
                    draw_text(display_text, text_x, list_y + math.floor(8 * s), UI.font_tiny, C.text)
                end
            end
            list_y = list_y + search_h + math.floor(5 * s)

            -- Filter props by search (trim whitespace and convert to lowercase)
            local search_query = constructor.prop_search_query or ""
            search_query = search_query:match("^%s*(.-)%s*$") -- Trim whitespace
            local search_lower = string.lower(search_query)
            local filtered_categories = {}
            if search_lower ~= "" then
                for _, category in ipairs(PROP_CATEGORIES) do
                    local props = PROPS_DATA[category]
                    if props then
                        for _, prop in ipairs(props) do
                            if string.find(string.lower(prop.name), search_lower, 1, true) then
                                if not filtered_categories[category] then
                                    filtered_categories[category] = {}
                                end
                                table.insert(filtered_categories[category], prop)
                            end
                        end
                    end
                end
            end

            -- Prop selection dropdown with categories
            for _, category in ipairs(PROP_CATEGORIES) do
                local props = search_lower ~= "" and (filtered_categories[category] or {}) or PROPS_DATA[category]
                if props and #props > 0 then
                    local header_h = math.floor(26 * s)
                    -- Auto-expand when searching, otherwise use saved state
                    local collapsed = search_lower ~= "" and false or (constructor.category_collapsed[category] == nil and true or constructor.category_collapsed[category])

                    if is_visible(list_y, header_h) then
                        local header_hover = is_mouse_in(base_x + math.floor(10 * s), list_y, total_w - math.floor(20 * s), header_h)
                        draw_rect(base_x + math.floor(10 * s), list_y, total_w - math.floor(20 * s), header_h, header_hover and C.accent or C.header, math.floor(3 * s))
                        local arrow = collapsed and ">" or "v"
                        draw_text(arrow .. " " .. category .. " (" .. #props .. ")", base_x + math.floor(15 * s), list_y + math.floor(5 * s), UI.font_small, C.text)

                        -- Allow clicking to collapse/expand categories even while searching
                        if header_hover and MOUSE.just_pressed then
                            constructor.category_collapsed[category] = not collapsed
                        end
                    end
                    list_y = list_y + header_h + math.floor(2 * s)

                    if not collapsed then
                        for _, prop in ipairs(props) do
                            if is_visible(list_y, item_h) then
                                local is_hover = is_mouse_in(base_x + math.floor(20 * s), list_y, total_w - math.floor(30 * s), item_h)
                                local is_selected = (constructor.selected_prop_hash == prop.hash)

                                local bg_col = is_selected and C.checkbox_on or (is_hover and C.widget_hover or C.widget_bg)
                                draw_rect(base_x + math.floor(20 * s), list_y, total_w - math.floor(30 * s), item_h, bg_col, math.floor(3 * s))
                                draw_text(prop.name, base_x + math.floor(25 * s), list_y + (item_h - UI.font_small) / 2, UI.font_small, C.text)

                                if is_hover and MOUSE.just_pressed then
                                    constructor.selected_prop_hash = prop.hash
                                end
                            end
                            list_y = list_y + item_h + math.floor(2 * s)
                        end
                    end
                end
            end

            list_y = list_y + math.floor(10 * s)

            -- Placed objects list
            if is_visible(list_y, math.floor(25 * s)) then
                draw_text("Placed Objects (" .. #constructor.objects .. ")", base_x + math.floor(10 * s), list_y, UI.font_small, C.accent)
            end
            list_y = list_y + math.floor(25 * s)

            for i, obj in ipairs(constructor.objects) do
                local obj_y = list_y + (i - 1) * item_h
                if is_visible(obj_y, item_h) then
                    local is_hover = is_mouse_in(base_x + math.floor(10 * s), obj_y, total_w - math.floor(20 * s), item_h)
                    local is_selected = (constructor.selected_object and constructor.selected_object.id == obj.id)

                    local bg_col = is_selected and C.checkbox_on or (is_hover and C.widget_hover or C.widget_bg)
                    draw_rect(base_x + math.floor(10 * s), obj_y, total_w - math.floor(20 * s), item_h, bg_col, math.floor(3 * s))
                    draw_text(obj.model, base_x + math.floor(15 * s), obj_y + (item_h - UI.font_small) / 2, UI.font_small, C.text)

                    if is_hover and MOUSE.just_pressed then
                        -- Check if we're in attach mode
                        if constructor.attach_mode and constructor.attach_source then
                            if obj.id ~= constructor.attach_source.id then
                                -- Attach the source to this target
                                attach_object(constructor.attach_source, obj)
                                safe_toast("Attached " .. constructor.attach_source.model .. " to " .. obj.model)
                                constructor.attach_mode = false
                                constructor.attach_source = nil
                            else
                                safe_toast("Can't attach to itself!")
                            end
                        else
                            -- Normal selection - update placement coordinates to prevent teleporting
                            constructor.selected_object = obj
                            constructor.selected_index = i
                            -- IMPORTANT: Update placement position to this object's current position
                            if constructor.placement_mode then
                                constructor.placement_obj_x = obj.position.x
                                constructor.placement_obj_y = obj.position.y
                                constructor.placement_obj_z = obj.position.z
                            end
                        end
                    end
                end
            end

            -- Calculate total content height for scroll
            local total_content = list_y + (#constructor.objects * item_h) - start_y + constructor.objects_scroll
            max_scroll = math.max(0, total_content - content_h)

        elseif constructor.ui_tab == 2 then
            -- PROPERTIES TAB (with scrolling)
            local start_y = content_y + math.floor(10 * s)
            local prop_y = start_y - constructor.props_scroll
            local btn_h = math.floor(35 * s)
            local line_h = math.floor(25 * s)

            -- Prop Cycling Header
            if is_visible(prop_y, line_h) then
                draw_text("Selected: " .. (constructor.selected_index or 0) .. "/" .. #constructor.objects, base_x + math.floor(10 * s), prop_y, UI.font_small, C.accent)
            end
            prop_y = prop_y + math.floor(25 * s)

            -- Previous / Next buttons for cycling props
            local cycle_w = (total_w - math.floor(30 * s)) / 2
            local prev_hover = is_mouse_in(base_x + math.floor(10 * s), prop_y, cycle_w, btn_h)
            local next_hover = is_mouse_in(base_x + math.floor(15 * s) + cycle_w, prop_y, cycle_w, btn_h)

            draw_rect(base_x + math.floor(10 * s), prop_y, cycle_w, btn_h, prev_hover and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("< Previous", base_x + math.floor(20 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)

            draw_rect(base_x + math.floor(15 * s) + cycle_w, prop_y, cycle_w, btn_h, next_hover and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("Next >", base_x + math.floor(25 * s) + cycle_w, prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)

            if prev_hover and MOUSE.just_pressed and #constructor.objects > 0 then
                constructor.selected_index = constructor.selected_index or 1
                constructor.selected_index = constructor.selected_index - 1
                if constructor.selected_index < 1 then constructor.selected_index = #constructor.objects end
                constructor.selected_object = constructor.objects[constructor.selected_index]
                -- Update placement position to prevent teleporting
                if constructor.placement_mode and constructor.selected_object then
                    constructor.placement_obj_x = constructor.selected_object.position.x
                    constructor.placement_obj_y = constructor.selected_object.position.y
                    constructor.placement_obj_z = constructor.selected_object.position.z
                end
            end
            if next_hover and MOUSE.just_pressed and #constructor.objects > 0 then
                constructor.selected_index = constructor.selected_index or 1
                constructor.selected_index = constructor.selected_index + 1
                if constructor.selected_index > #constructor.objects then constructor.selected_index = 1 end
                constructor.selected_object = constructor.objects[constructor.selected_index]
                -- Update placement position to prevent teleporting
                if constructor.placement_mode and constructor.selected_object then
                    constructor.placement_obj_x = constructor.selected_object.position.x
                    constructor.placement_obj_y = constructor.selected_object.position.y
                    constructor.placement_obj_z = constructor.selected_object.position.z
                end
            end
            prop_y = prop_y + btn_h + math.floor(15 * s)

            if constructor.selected_object then
                local obj = constructor.selected_object

                draw_text("Object ID: " .. obj.id, base_x + math.floor(10 * s), prop_y, UI.font_small, C.text)
                prop_y = prop_y + line_h

                draw_text("Model: " .. obj.model, base_x + math.floor(10 * s), prop_y, UI.font_small, C.text)
                prop_y = prop_y + line_h

                draw_text(string.format("Pos: %.1f, %.1f, %.1f", obj.position.x, obj.position.y, obj.position.z), base_x + math.floor(10 * s), prop_y, UI.font_small, C.text)
                prop_y = prop_y + line_h

                draw_text(string.format("Rot: %.1f, %.1f, %.1f", obj.rotation.x, obj.rotation.y, obj.rotation.z), base_x + math.floor(10 * s), prop_y, UI.font_small, C.text)
                prop_y = prop_y + line_h + math.floor(10 * s)

                -- Placement mode toggle
                if small_button(constructor.placement_mode and "Exit Placement Mode" or "Enter Placement Mode", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    if constructor.placement_mode then
                        exit_placement_mode()
                    else
                        enter_placement_mode()
                    end
                end
                prop_y = prop_y + btn_h + math.floor(10 * s)

                -- Delete object button
                if small_button("Delete Object", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    delete_constructor_object(obj)
                    constructor.selected_object = nil
                    constructor.selected_index = math.max(1, #constructor.objects)
                    if #constructor.objects > 0 then
                        constructor.selected_object = constructor.objects[constructor.selected_index]
                    end
                end
                prop_y = prop_y + btn_h + math.floor(5 * s)

                -- Duplicate/Place button - spawns a copy at same position/rotation
                if small_button("Place (Duplicate)", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    local new_obj = create_constructor_object(obj.model_hash, {x = obj.position.x, y = obj.position.y, z = obj.position.z})
                    if new_obj then
                        -- Copy rotation to new object
                        update_object_rotation(new_obj, {x = obj.rotation.x, y = obj.rotation.y, z = obj.rotation.z})
                        -- Copy properties
                        new_obj.collision_enabled = obj.collision_enabled
                        new_obj.frozen = obj.frozen
                        if new_obj.handle and new_obj.handle ~= 0 then
                            invoker.call(0x1A9205C1B9EE827F, new_obj.handle, obj.collision_enabled ~= false, true)
                            invoker.call(0x428CA6DBD1094446, new_obj.handle, obj.frozen == true)
                        end
                        -- Select the new object so user can move it
                        constructor.selected_object = new_obj
                        constructor.selected_index = #constructor.objects
                        safe_toast("Duplicated! Move the new prop.")
                    end
                end
                prop_y = prop_y + btn_h + math.floor(5 * s)

                -- Detach button (if attached)
                if obj.is_attached then
                    if small_button("Detach", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                        detach_object(obj)
                        safe_toast("Prop detached!")
                    end
                    prop_y = prop_y + btn_h + math.floor(5 * s)
                end
                prop_y = prop_y + math.floor(10 * s)

                -- ===== PROP CONTROL BUTTONS =====
                draw_text("Prop Controls", base_x + math.floor(10 * s), prop_y, UI.font_small, C.accent)
                prop_y = prop_y + math.floor(25 * s)

                -- Toggle Collision button
                local collision_on = obj.collision_enabled ~= false  -- Default to true
                local collision_label = collision_on and "Collision: ON" or "Collision: OFF"
                if small_button(collision_label, base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    obj.collision_enabled = not collision_on
                    if obj.handle and obj.handle ~= 0 then
                        -- SET_ENTITY_COLLISION(entity, toggle, keepPhysics)
                        invoker.call(0x1A9205C1B9EE827F, obj.handle, obj.collision_enabled, true)
                    end
                    safe_toast(obj.collision_enabled and "Collision enabled" or "Collision disabled")
                end
                prop_y = prop_y + btn_h + math.floor(5 * s)

                -- Toggle Freeze button
                local frozen = obj.frozen == true
                local freeze_label = frozen and "Frozen: YES" or "Frozen: NO"
                if small_button(freeze_label, base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    obj.frozen = not frozen
                    if obj.handle and obj.handle ~= 0 then
                        -- FREEZE_ENTITY_POSITION(entity, toggle)
                        invoker.call(0x428CA6DBD1094446, obj.handle, obj.frozen)
                    end
                    safe_toast(obj.frozen and "Prop frozen" or "Prop unfrozen")
                end
                prop_y = prop_y + btn_h + math.floor(5 * s)

                -- Toggle Invincible button
                local invincible = obj.invincible == true
                local invincible_label = invincible and "Invincible: YES" or "Invincible: NO"
                if small_button(invincible_label, base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    obj.invincible = not invincible
                    if obj.handle and obj.handle ~= 0 then
                        -- SET_ENTITY_INVINCIBLE(entity, toggle)
                        invoker.call(0x3882114831B6BC3, obj.handle, obj.invincible)
                    end
                    safe_toast(obj.invincible and "Prop is invincible" or "Prop can be damaged")
                end
                prop_y = prop_y + btn_h + math.floor(5 * s)

                -- Toggle Visible button
                local visible = obj.visible ~= false  -- Default to true
                local visible_label = visible and "Visible: YES" or "Visible: NO"
                if small_button(visible_label, base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    obj.visible = not visible
                    if obj.handle and obj.handle ~= 0 then
                        -- SET_ENTITY_VISIBLE(entity, toggle, unk)
                        invoker.call(0xEA1C610A04DB6BBB, obj.handle, obj.visible, false)
                    end
                    safe_toast(obj.visible and "Prop visible" or "Prop invisible")
                end
                prop_y = prop_y + btn_h + math.floor(5 * s)

                -- Attach to Current Vehicle button
                if small_button("Attach to Current Vehicle", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                    local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int
                    local vehicle = invoker.call(0x9A9112A0FE9A4713, player_ped, false)  -- GET_VEHICLE_PED_IS_IN
                    if vehicle and (vehicle.int or vehicle.ent or 0) ~= 0 then
                        local veh_handle = vehicle.int or vehicle.ent
                        if obj.handle and obj.handle ~= 0 then
                            -- Get world positions
                            local veh_pos = invoker.call(0x3FEF770D40960D5A, veh_handle, false).scr_vec3
                            local prop_pos = invoker.call(0x3FEF770D40960D5A, obj.handle, false).scr_vec3
                            local veh_rot = invoker.call(0xAFBD61CC738D9EB9, veh_handle, 2).scr_vec3  -- GET_ENTITY_ROTATION
                            local prop_rot = invoker.call(0xAFBD61CC738D9EB9, obj.handle, 2).scr_vec3  -- GET_ENTITY_ROTATION

                            -- Calculate world offset
                            local world_dx = prop_pos.x - veh_pos.x
                            local world_dy = prop_pos.y - veh_pos.y
                            local world_dz = prop_pos.z - veh_pos.z

                            -- Convert to vehicle's local space using rotation matrix
                            local heading_rad = math.rad(-veh_rot.z)  -- Negative for inverse rotation
                            local cos_h = math.cos(heading_rad)
                            local sin_h = math.sin(heading_rad)

                            -- Rotate world offset to local space (2D rotation around Z axis)
                            local local_x = world_dx * cos_h - world_dy * sin_h
                            local local_y = world_dx * sin_h + world_dy * cos_h
                            local local_z = world_dz

                            -- Calculate relative rotation (prop rotation relative to vehicle)
                            local rel_pitch = prop_rot.x - veh_rot.x
                            local rel_roll = prop_rot.y - veh_rot.y
                            local rel_yaw = prop_rot.z - veh_rot.z

                            -- Store local offsets and rotation for saving
                            obj.attach_offset = {x = local_x, y = local_y, z = local_z}
                            obj.attach_rotation = {x = rel_pitch, y = rel_roll, z = rel_yaw}

                            -- ATTACH_ENTITY_TO_ENTITY(entity, target, boneIndex, xPos, yPos, zPos, xRot, yRot, zRot, p9, useSoftPinning, collision, isPed, vertexIndex, fixedRot)
                            invoker.call(0x6B9BBD38AB0796DF, obj.handle, veh_handle, 0, local_x, local_y, local_z, rel_pitch, rel_roll, rel_yaw, false, true, false, false, 2, true)
                            obj.attached_to_vehicle = veh_handle
                            obj.is_attached = true
                            safe_toast("Attached prop to vehicle!")
                        end
                    else
                        safe_toast("You must be in a vehicle!")
                    end
                end
                prop_y = prop_y + btn_h + math.floor(15 * s)

            else
                if is_visible(prop_y, line_h * 2) then
                    draw_text("No object selected", base_x + math.floor(10 * s), prop_y, UI.font_small, C.text_dim)
                    draw_text("Spawn a prop in Objects tab", base_x + math.floor(10 * s), prop_y + line_h, UI.font_small, C.text_dim)
                end
                prop_y = prop_y + line_h * 2
            end

            -- Calculate total content height for Properties tab scroll
            local total_content = prop_y - start_y + constructor.props_scroll
            max_scroll = math.max(0, total_content - content_h)

        elseif constructor.ui_tab == 3 then
            -- SAVE/LOAD TAB (with scrolling)
            local btn_h = math.floor(35 * s)
            local start_y = content_y + math.floor(10 * s)
            local prop_y = start_y - constructor.files_scroll

            -- Save section
            if is_visible(prop_y, math.floor(25 * s)) then
                draw_text("Save Current Build", base_x + math.floor(10 * s), prop_y, UI.font_small, C.accent)
            end
            prop_y = prop_y + math.floor(30 * s)

            -- Save name input (with keyboard handling like other text inputs)
            local input_w = total_w - math.floor(20 * s)
            local input_x = base_x + math.floor(10 * s)
            local input_hover = is_mouse_in(input_x, prop_y, input_w, btn_h)

            -- Handle keyboard input when focused
            if constructor.save_input_focused and input and input.key then
                -- Backspace
                if input.key(0x08).just_pressed then
                    if #constructor.save_name > 0 then
                        constructor.save_name = constructor.save_name:sub(1, -2)
                    end
                end
                -- Letters A-Z
                for code = 0x41, 0x5A do
                    if input.key(code).just_pressed then
                        constructor.save_name = constructor.save_name .. string.char(code):lower()
                    end
                end
                -- Numbers 0-9
                for code = 0x30, 0x39 do
                    if input.key(code).just_pressed then
                        constructor.save_name = constructor.save_name .. string.char(code)
                    end
                end
                -- Underscore (Shift+Minus)
                if input.key(0xBD).just_pressed then
                    constructor.save_name = constructor.save_name .. "_"
                end
                -- Enter to confirm
                if input.key(0x0D).just_pressed then
                    constructor.save_input_focused = false
                    safe_toast("Filename set: " .. constructor.save_name)
                end
                -- Escape to cancel
                if input.key(0x1B).just_pressed then
                    constructor.save_input_focused = false
                end
            end

            -- Draw input box
            local bg_col = constructor.save_input_focused and C.widget_hover or (input_hover and C.widget_hover or C.widget_bg)
            draw_rect(input_x, prop_y, input_w, btn_h, bg_col, math.floor((UI.widget_rounding or 5) * s))
            -- Accent border when focused
            if constructor.save_input_focused then
                draw_rect(input_x, prop_y, input_w, math.floor(2 * s), C.accent, math.floor(6 * s))
                draw_rect(input_x, prop_y + btn_h - math.floor(2 * s), input_w, math.floor(2 * s), C.accent, math.floor(6 * s))
                draw_rect(input_x, prop_y, math.floor(2 * s), btn_h, C.accent, math.floor(6 * s))
                draw_rect(input_x + input_w - math.floor(2 * s), prop_y, math.floor(2 * s), btn_h, C.accent, math.floor(6 * s))
            end

            local display_text = constructor.save_name
            if constructor.save_input_focused then
                display_text = display_text .. "_"
            end
            if constructor.save_name == "" and not constructor.save_input_focused then
                draw_text("Click to enter filename...", input_x + math.floor(10 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, color(100,100,100,180))
            else
                draw_text(display_text, input_x + math.floor(10 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            end

            -- Click to focus/unfocus
            if input_hover and MOUSE.just_pressed then
                constructor.save_input_focused = not constructor.save_input_focused
                if constructor.save_input_focused then
                    safe_toast("Type filename - Press Enter when done")
                end
            end
            prop_y = prop_y + btn_h + math.floor(10 * s)

            if small_button("Save Build", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                if constructor.save_name ~= "" then
                    save_construct_to_json(constructor.save_name)
                    refresh_saved_constructs_list()
                else
                    safe_toast("Enter a filename first!")
                end
            end
            prop_y = prop_y + btn_h + math.floor(20 * s)

            -- Load section
            draw_text("Load Saved Build", base_x + math.floor(10 * s), prop_y, UI.font_small, C.accent)
            prop_y = prop_y + math.floor(30 * s)

            if small_button("Refresh File List", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                refresh_saved_constructs_list()
            end
            prop_y = prop_y + btn_h + math.floor(10 * s)

            -- Saved files list
            for i, filename in ipairs(constructor.saved_constructs) do
                local file_y = prop_y + (i - 1) * btn_h
                if is_visible(file_y, btn_h) then
                    if small_button(filename, base_x + math.floor(10 * s), file_y, total_w - math.floor(20 * s), btn_h) then
                        load_construct_from_json(filename)
                    end
                end
            end

            -- Calculate total content height for Save/Load tab scroll
            local total_content = prop_y + (#constructor.saved_constructs * btn_h) - start_y + constructor.files_scroll
            max_scroll = math.max(0, total_content - content_h)

        elseif constructor.ui_tab == 4 then
            -- SETTINGS TAB
            local prop_y = content_y + math.floor(10 * s)
            local line_h = math.floor(30 * s)
            local btn_h = math.floor(35 * s)
            local small_btn_w = math.floor(50 * s)

            draw_text("Constructor Settings", base_x + math.floor(10 * s), prop_y, UI.font_small, C.accent)
            prop_y = prop_y + math.floor(35 * s)

            -- Movement Speed setting
            draw_text("Movement Speed: " .. string.format("%.2f", constructor.movement_speed), base_x + math.floor(10 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            local move_minus = is_mouse_in(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h)
            local move_plus = is_mouse_in(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h)
            draw_rect(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h, move_minus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("-", base_x + total_w - math.floor(100 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            draw_rect(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h, move_plus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("+", base_x + total_w - math.floor(40 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            if move_minus and MOUSE.just_pressed then
                constructor.movement_speed = math.max(0.01, constructor.movement_speed - 0.02)
            end
            if move_plus and MOUSE.just_pressed then
                constructor.movement_speed = math.min(1.0, constructor.movement_speed + 0.02)
            end
            prop_y = prop_y + btn_h + math.floor(5 * s)

            -- Rotation Speed setting
            draw_text("Rotation Speed: " .. string.format("%.1f°", constructor.rotation_speed), base_x + math.floor(10 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            local rot_minus = is_mouse_in(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h)
            local rot_plus = is_mouse_in(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h)
            draw_rect(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h, rot_minus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("-", base_x + total_w - math.floor(100 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            draw_rect(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h, rot_plus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("+", base_x + total_w - math.floor(40 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            if rot_minus and MOUSE.just_pressed then
                constructor.rotation_speed = math.max(1.0, constructor.rotation_speed - 1.0)
            end
            if rot_plus and MOUSE.just_pressed then
                constructor.rotation_speed = math.min(45.0, constructor.rotation_speed + 1.0)
            end
            prop_y = prop_y + btn_h + math.floor(5 * s)

            -- Camera Sensitivity setting
            draw_text("Camera Speed: " .. string.format("%.2f", constructor.camera_sensitivity), base_x + math.floor(10 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            local cam_minus = is_mouse_in(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h)
            local cam_plus = is_mouse_in(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h)
            draw_rect(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h, cam_minus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("-", base_x + total_w - math.floor(100 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            draw_rect(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h, cam_plus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("+", base_x + total_w - math.floor(40 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            if cam_minus and MOUSE.just_pressed then
                constructor.camera_sensitivity = math.max(0.1, constructor.camera_sensitivity - 0.1)
            end
            if cam_plus and MOUSE.just_pressed then
                constructor.camera_sensitivity = math.min(2.0, constructor.camera_sensitivity + 0.1)
            end
            prop_y = prop_y + btn_h + math.floor(5 * s)

            -- Camera Distance setting
            draw_text("Camera Distance: " .. string.format("%.1f", constructor.camera_distance), base_x + math.floor(10 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            local dist_minus = is_mouse_in(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h)
            local dist_plus = is_mouse_in(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h)
            draw_rect(base_x + total_w - math.floor(120 * s), prop_y, small_btn_w, btn_h, dist_minus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("-", base_x + total_w - math.floor(100 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            draw_rect(base_x + total_w - math.floor(60 * s), prop_y, small_btn_w, btn_h, dist_plus and C.widget_hover or C.widget_bg, math.floor(3 * s))
            draw_text("+", base_x + total_w - math.floor(40 * s), prop_y + (btn_h - UI.font_small) / 2, UI.font_small, C.text)
            if dist_minus and MOUSE.just_pressed then
                constructor.camera_distance = math.max(2.0, constructor.camera_distance - 1.0)
            end
            if dist_plus and MOUSE.just_pressed then
                constructor.camera_distance = math.min(50.0, constructor.camera_distance + 1.0)
            end
            prop_y = prop_y + btn_h + math.floor(15 * s)

            -- Load at Player toggle
            local load_label = constructor.load_at_player and "Load Location: In Front of Me" or "Load Location: Original Position"
            if small_button(load_label, base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                constructor.load_at_player = not constructor.load_at_player
                safe_toast(constructor.load_at_player and "Will load in front of you" or "Will load at original position")
            end
            prop_y = prop_y + btn_h + math.floor(20 * s)

            -- Clear All Objects button
            if small_button("Clear All Objects", base_x + math.floor(10 * s), prop_y, total_w - math.floor(20 * s), btn_h) then
                for i = #constructor.objects, 1, -1 do
                    delete_constructor_object(constructor.objects[i])
                end
                constructor.selected_object = nil
                safe_toast("Cleared all objects")
            end
        end

        -- Handle scrolling for Constructor UI (mouse wheel in panel area)
        local in_panel = is_mouse_in(base_x, content_y, total_w, content_h)
        if in_panel and max_scroll > 0 then
            if MOUSE.scroll_up then
                if constructor.ui_tab == 1 then
                    constructor.objects_scroll = math.max(0, constructor.objects_scroll - math.floor(50 * s))
                elseif constructor.ui_tab == 2 then
                    constructor.props_scroll = math.max(0, constructor.props_scroll - math.floor(50 * s))
                elseif constructor.ui_tab == 3 then
                    constructor.files_scroll = math.max(0, constructor.files_scroll - math.floor(50 * s))
                end
            end
            if MOUSE.scroll_down then
                if constructor.ui_tab == 1 then
                    constructor.objects_scroll = math.min(max_scroll, constructor.objects_scroll + math.floor(50 * s))
                elseif constructor.ui_tab == 2 then
                    constructor.props_scroll = math.min(max_scroll, constructor.props_scroll + math.floor(50 * s))
                elseif constructor.ui_tab == 3 then
                    constructor.files_scroll = math.min(max_scroll, constructor.files_scroll + math.floor(50 * s))
                end
            end
        end
    end

