manchez,manchez2,manchez3,nemesis,nightblade,oppressor,oppressor2,pcj,pizzaboy,powersurge,ratbike,ruffian,rrocket,reever,sanctus,shinobi,shotaro,sovereign,stryder,thrust,vader,vindicator,vortex,wolfsbane,zombiea,zombieb,adder,banshee,bullet,cheetah,entityxf,infernus,osiris,le7b,t20,turismor,tyrus,vacca,voltic,Ztype,alpha,banshee2,bestiagts,blista2,blista3,buffalo,buffalo2,buffalo3,carbonizzare,comet2,comet3,comet5,coquette,coquette4,drifteuros,elegy,elegy2,feltzer2,flashgt,furoregt,fusilade,futo,futo2,gb200,hotring,italigto,jester,jester2,khamelion,komoda,kuruma,lynx,massacro,massacro2,ninef,ninef2,omnis,pariah,penumbra,penumbra2,raiden,rapidgt,rapidgt2,raptor,remus,revolter,ruston,schafter3,schafter4,schafter5,schwarzer,sentinel3,sentinel4,seven70,specter,specter2,streiter,sugoi,sultan,sultanrs,surano,tropos,verlierer2,zr350,zr380,baller,baller2,baller3,baller4,baller5,baller6,baller7,bjxl,Cavalcade,cavalcade2,contender,dubsta,dubsta2,fq2,granger,gresley,habanero,huntley,landstalker,MESA,patriot,patriot2,radi,rocoto,seminole,serrano,streamer216,toros,XLS,xls2,asbo,blista,brioso,club,dilettante,issi2,issi3,kanjo,panto,prairie,rhapsody,weevil,cogcabrio,exemplar,f620,felon,felon2,jackal,oracle,oracle2,sentinel,sentinel2,windsor,windsor2,zion,zion2,bmx,cruiser,fixter,scorcher,tribike,tribike2,tribike3,ambulance,FBI,FBI2,firetruk,lguard,pbus,police,police2,police3,police4,RIOT,SHERIFF,sheriff2"

        local count = 0
        for model in models:gmatch("[^,]+") do
            local hash = invoker.call(0xD24D37CC275948CC, model).int
            if hash and hash ~= 0 then
                spawn_state.hash_to_model[hash] = model
                count = count + 1
            end
            if count % 100 == 0 then
                util.yield() -- Don't block
            end
        end

        debug_info("HASH", "Built lookup for " .. count .. " vehicles")
    end)

    -- Helper: Spawn vehicle (EXACTLY LIKE CLICKUI)
    local function spawn_vehicle(model_name, display_name)
        if not model_name then return end
        display_name = display_name or model_name

        -- LIKE CLICKUI: Check loading flag FIRST and return immediately
        if spawn_state.is_spawning then
            debug_info("SPAWN", "Already spawning, ignoring click")
            return
        end

        -- LIKE CLICKUI: Set loading flag IMMEDIATELY before async
        spawn_state.is_spawning = true

        -- LIKE CLICKUI: Use util.create_job (runs ONCE), NOT util.create_thread (runs EVERY FRAME)
        util.create_job(function()
            debug_info("SPAWN", "Starting spawn: " .. display_name)

            -- Get player ped
            local ped = invoker.call(0x43A66C31C68491C0, -1).int
            if not ped or ped == 0 then
                debug_error("SPAWN", "No player ped")
                spawn_state.is_spawning = false
                return
            end
            debug_info("SPAWN", "Player ped: " .. ped)

            -- Get player coords (ClickUI uses .scr_vec3)
            local coords = invoker.call(0x3FEF770D40960D5A, ped, true).scr_vec3
            if not coords or not coords.x then
                debug_error("SPAWN", "Failed to get coords")
                spawn_state.is_spawning = false
                return
            end
            debug_info("SPAWN", string.format("Coords: %.1f, %.1f, %.1f", coords.x, coords.y, coords.z))

            -- Request model
            local hash = invoker.call(0xD24D37CC275948CC, model_name).int
            if not hash or hash == 0 then
                debug_error("SPAWN", "Invalid model: " .. model_name)
                spawn_state.is_spawning = false
                return
            end
            debug_info("SPAWN", "Model hash: " .. hash)

            invoker.call(0x963D27A58DF860AC, hash)
            local timeout = 0
            while timeout < 50 do
                local loaded = invoker.call(0x98A4EB5D89A0C952, hash)
                if loaded and loaded.bool then break end
                util.yield(100)
                timeout = timeout + 1
            end

            if timeout >= 50 then
                debug_error("SPAWN", "Model timeout")
                spawn_state.is_spawning = false
                return
            end
            debug_info("SPAWN", "Model loaded")

            -- Get heading
            local heading = invoker.call(0xE83A169BE1F8E88F, ped, false).flo or 0.0
            debug_info("SPAWN", "Heading: " .. heading)

            -- Spawn position (5m in front)
            local spawn_x = coords.x - math.sin(math.rad(heading)) * 5.0
            local spawn_y = coords.y + math.cos(math.rad(heading)) * 5.0
            local spawn_z = coords.z + 1.0

            -- Spawn in air for aircraft
            if spawn_state.spawn_in_air then
                spawn_z = coords.z + 30.0
            end
            debug_info("SPAWN", string.format("Spawn pos: %.1f, %.1f, %.1f", spawn_x, spawn_y, spawn_z))

            -- CREATE_VEHICLE (like ZODIACV2 - separate x,y,z params, NOT scr_vec3)
            local veh = invoker.call(0xAF35D0D2583051B0, hash, spawn_x, spawn_y, spawn_z, heading, true, true, false).int
            if not veh or veh == 0 then
                debug_error("SPAWN", "CREATE_VEHICLE failed")
                spawn_state.is_spawning = false
                return
            end
            debug_info("SPAWN", "Vehicle created: " .. veh)

            -- Track spawned vehicle for saving
            spawn_state.last_spawned_vehicle = veh
            spawn_state.last_spawned_model_name = model_name

            -- Build hash->model lookup dynamically
            if not spawn_state.hash_to_model then
                spawn_state.hash_to_model = {}
            end
            spawn_state.hash_to_model[hash] = model_name

            debug_info("SPAWN", "Tracked model: " .. model_name .. " (hash: " .. hash .. ")")

            -- Apply spawn options
            if spawn_state.clean_vehicle then
                invoker.call(0x01891FBF08E6AA46, veh, 0.0)
            end

            if spawn_state.bulletproof_tires then
                invoker.call(0x2B48C4C2D7EE3E3F, veh, true)
            end

            if spawn_state.vehicle_godmode then
                invoker.call(0x3882114BDE571AD4, veh, true)
            end

            if spawn_state.radio_off then
                invoker.call(0xBB6E0FEDB41CAE22, veh, false)
            end

            if spawn_state.max_performance then
                invoker.call(0x0AD87F87DC1D5EA0, veh, 4, 1000.0)
                invoker.call(0x93A3996368C94158, veh, 1000.0)
            end

            if spawn_state.max_upgrade then
                invoker.call(0x1F2AA07F00B3217A, veh, 0)
                for i = 0, 49 do
                    local max = invoker.call(0x33F2E3FE70EAAE1D, veh, i).int
                    if max and max > 0 then
                        invoker.call(0x6AF0636DDEDCB6DD, veh, i, max - 1, false)
                    end
                end
                invoker.call(0x63D03F7B87EAAE94, veh, 18, true)
            end

            -- Apply color preset (COMPLETE CLICKUI SYSTEM)
            if spawn_state.use_preset then
                if spawn_state.color_mode == 1 then
                    -- Classic mode: Standard color IDs
                    invoker.call(0x7141766F91D15BEA, veh, spawn_state.primary_color - 1)
                    invoker.call(0x9D77259E04F6FDDE, veh, spawn_state.secondary_color - 1)

                    -- Pearlescent
                    if spawn_state.pearlescent_id > 0 then
                        invoker.call(0x3AFDC536C3D01674, veh, spawn_state.pearlescent_id - 1, 0)
                    end

                    -- Wheel color
                    if spawn_state.wheel_color_id > 0 then
                        invoker.call(0x3AFDC536C3D01674, veh, 0, spawn_state.wheel_color_id - 1)
                    end

                elseif spawn_state.color_mode == 2 then
                    -- RGB mode: Custom RGB colors
                    local p = spawn_state.primary_color_rgb
                    local s = spawn_state.secondary_color_rgb
                    invoker.call(0x7141766F91D15BEA, veh, p.r, p.g, p.b)
                    invoker.call(0x9D77259E04F6FDDE, veh, s.r, s.g, s.b)

                elseif spawn_state.color_mode == 3 then
                    -- Chameleon mode: Special color IDs (161-222)
                    local preset = CHAMELEON_PRESETS[spawn_state.chameleon_paint]
                    if preset and preset.id >= 161 then
                        invoker.call(0x7141766F91D15BEA, veh, preset.id)
                        invoker.call(0x9D77259E04F6FDDE, veh, preset.id)
                    end
                end

                -- Apply xenon headlights
                if spawn_state.xenon_color > 1 then
                    local preset = XENON_PRESETS[spawn_state.xenon_color]
                    if preset then
                        invoker.call(0x3DFF319A831E0CDB, veh, 22, true)
                        if preset.id >= 0 then
                            invoker.call(0xE41033B25D7A3FDB, veh, preset.id)
                        end
                    end
                end

                -- Apply neon lights
                if spawn_state.neon_color > 1 then
                    local preset = NEON_PRESETS[spawn_state.neon_color]
                    if preset and preset.r then
                        for i = 0, 3 do
                            invoker.call(0x2AA720E4287BF269, veh, i, true)
                        end
                        invoker.call(0x8E0A582209A62695, veh, preset.r, preset.g, preset.b)
                    end
                end

                -- Apply tire smoke
                if spawn_state.tire_smoke_color > 1 then
                    local preset = SMOKE_PRESETS[spawn_state.tire_smoke_color]
                    if preset and preset.r then
                        invoker.call(0x3DFF319A831E0CDB, veh, 20, true)
                        invoker.call(0xB5BA80F839791C0F, veh, preset.r, preset.g, preset.b)
                    end
                end

                -- Apply window tint
                if spawn_state.window_tint > 1 then
                    invoker.call(0x57C51E6BAD752696, veh, spawn_state.window_tint - 1)
                end

                -- Apply plate type
                if spawn_state.plate_type > 1 then
                    invoker.call(0x9088EB5A43FFB0A1, veh, spawn_state.plate_type - 1)
                end
            end

            -- Engine on
            if spawn_state.engine_on then
                invoker.call(0x2497C4717C8B881E, veh, true, true, false)
            end

            -- Teleport to vehicle
            if spawn_state.teleport_to_vehicle then
                invoker.call(0xF75B0D629E1C063D, ped, veh, -1)
            end

            invoker.call(0xE532F5D78798DAAB, hash)
            debug_info("SPAWN", "SUCCESS: Spawned " .. display_name)

            -- Track last spawned vehicle for saving
            spawn_state.last_spawned_model = model_name
            spawn_state.last_spawned_hash = hash

            -- Reset spawning flag
            spawn_state.is_spawning = false
        end)
    end

    -- Helper: Save current vehicle
    local function save_current_vehicle(name)
        if not name or name == "" then
            safe_toast("Please enter a vehicle name")
            return
        end

        -- Get player ped
        local ped = invoker.call(0x43A66C31C68491C0, -1).int
        if not ped or ped == 0 then
            safe_toast("Failed to get player")
            return
        end

        -- Get current vehicle
        local veh = invoker.call(0x9a9112a0fe9a4713, ped, false).int  -- GET_VEHICLE_PED_IS_IN
        if not veh or veh == 0 then
            safe_toast("You must be in a vehicle to save")
            return
        end

        -- Get vehicle model hash (LIKE ZODIACV2 AND CLICKUI)
        local hash = invoker.call(0x9F47B058362C84B5, veh).int  -- GET_ENTITY_MODEL
        if not hash or hash == 0 then
            safe_toast("Failed to get vehicle model")
            return
        end

        debug_info("SAVE", "Vehicle hash: " .. hash)

        -- LIKE CLICKUI: Save the HASH directly (not model name)
        -- REQUEST_MODEL can work with raw hashes!
        debug_info("SAVE", "Saving vehicle with hash: " .. hash)

        -- LIKE CLICKUI: Read customizations using pointer_int()
        -- Enable mod kit
        invoker.call(0x1F2AA07F00B3217A, veh, 0)  -- SET_VEHICLE_MOD_KIT

        local customizations = {}

        -- [Lexis] Get vehicle colors (CORRECT METHOD using pointers)
        local primary_ptr = pointer_int()
        local secondary_ptr = pointer_int()
        local ok = pcall(invoker.call, 0xA19435F193E081AC, veh, primary_ptr, secondary_ptr)  -- GET_VEHICLE_COLOURS
        if ok then
            customizations.colors = {primary_ptr.value or 0, secondary_ptr.value or 0}
        else
            customizations.colors = {0, 0}
        end
        primary_ptr:free()
        secondary_ptr:free()

        -- [Lexis] Custom primary color
        local r1 = pointer_int()
        local g1 = pointer_int()
        local b1 = pointer_int()
        ok = pcall(invoker.call, 0xb64cf2cca9d95f52, veh, r1, g1, b1)  -- GET_VEHICLE_CUSTOM_PRIMARY_COLOUR
        if ok then
            customizations["custom primary"] = {r1.value or 0, g1.value or 0, b1.value or 0}
        else
            customizations["custom primary"] = {0, 0, 0}
        end
        r1:free()
        g1:free()
        b1:free()

        -- [Lexis] Custom secondary color
        local r2 = pointer_int()
        local g2 = pointer_int()
        local b2 = pointer_int()
        ok = pcall(invoker.call, 0x8389cd56ca8072dc, veh, r2, g2, b2)  -- GET_VEHICLE_CUSTOM_SECONDARY_COLOUR
        if ok then
            customizations["custom secondary"] = {r2.value or 0, g2.value or 0, b2.value or 0}
        else
            customizations["custom secondary"] = {0, 0, 0}
        end
        r2:free()
        g2:free()
        b2:free()

        -- [Lexis] Extra colors (pearlescent, wheel)
        local pearl_ptr = pointer_int()
        local wheel_ptr = pointer_int()
        ok = pcall(invoker.call, 0x3bc4245933a166f7, veh, pearl_ptr, wheel_ptr)  -- GET_VEHICLE_EXTRA_COLOURS
        if ok then
            customizations["extra colors"] = {pearl_ptr.value or 0, wheel_ptr.value or 0}
        else
            customizations["extra colors"] = {0, 0}
        end
        pearl_ptr:free()
        wheel_ptr:free()

        -- [Lexis] All mods (slots 0-48) - direct property access
        customizations.mods = {}
        for slot = 0, 48 do
            customizations.mods[slot + 1] = invoker.call(0x772960298da26fdb, veh, slot).int or -1  -- GET_VEHICLE_MOD
        end

        -- [Lexis] Neon color
        local nr = pointer_int()
        local ng = pointer_int()
        local nb = pointer_int()
        ok = pcall(invoker.call, 0x7619eee8c886757f, veh, nr, ng, nb)  -- GET_VEHICLE_NEON_COLOUR
        if ok then
            customizations["neon color"] = {nr.value or 255, ng.value or 255, nb.value or 255}
        else
            customizations["neon color"] = {255, 255, 255}
        end
        nr:free()
        ng:free()
        nb:free()

        -- [Lexis] Neon enabled (4 positions) - direct property access
        customizations["neon enabled"] = {false, false, false, false}
        for i = 0, 3 do
            customizations["neon enabled"][i + 1] = invoker.call(0x8c4b92553e4766a5, veh, i).bool or false  -- GET_VEHICLE_NEON_ENABLED
        end

        -- [Lexis] Window tint (direct property access)
        customizations["window tint"] = invoker.call(0xee21293dad47c95, veh).int or 0  -- GET_VEHICLE_WINDOW_TINT

        -- [Lexis] Plate type (direct property access)
        customizations["plate type"] = invoker.call(0xf11bc2dd9a3e7195, veh).int or 0  -- GET_VEHICLE_NUMBER_PLATE_TEXT_INDEX

        -- [Lexis] Plate text (direct property access)
        customizations["plate text"] = invoker.call(0x7ce1ccb9b293020e, veh).str or ""  -- GET_VEHICLE_NUMBER_PLATE_TEXT

        -- [Lexis] Tire smoke color
        local sr = pointer_int()
        local sg = pointer_int()
        local sb = pointer_int()
        ok = pcall(invoker.call, 0xb635392a4938b3c3, veh, sr, sg, sb)  -- GET_VEHICLE_TYRE_SMOKE_COLOR
        if ok then
            customizations["smoke color"] = {sr.value or 255, sg.value or 255, sb.value or 255}
        else
            customizations["smoke color"] = {255, 255, 255}
        end
        sr:free()
        sg:free()
        sb:free()

        -- [Lexis] Wheel type (direct property access)
        customizations["wheel type"] = invoker.call(0xb3ed1bfb4be636dc, veh).int or 0  -- GET_VEHICLE_WHEEL_TYPE

        -- [Lexis] Extras (0-14) - direct property access
        customizations.extras = {}
        for i = 0, 14 do
            customizations.extras[i + 1] = invoker.call(0xd2e6822dbfd6c8bd, veh, i).bool or false  -- IS_VEHICLE_EXTRA_TURNED_ON
        end

        -- [Lexis] Livery (direct property access)
        customizations.livery = invoker.call(0x2bb9230590da5e8a, veh).int or -1  -- GET_VEHICLE_LIVERY

        -- [Lexis] Interior color
        local interior_ptr = pointer_int()
        ok = pcall(invoker.call, 0x46F3E1EBDB9F2F49, veh, interior_ptr)  -- GET_VEHICLE_INTERIOR_COLOUR
        if ok then
            customizations["extra color 5"] = interior_ptr.value or 0
        else
            customizations["extra color 5"] = 0
        end
        interior_ptr:free()

        -- [Lexis] Static values
        customizations["custom decal"] = {false, false}
        customizations["garage bitset"] = -1

        debug_info("SAVE", "Read all customizations successfully")

        -- Create saved vehicle
        local saved = {
            name = name,
            model = hash,  -- Save the model HASH (exactly like ClickUI)
            customizations = customizations,  -- All customizations!
            spawn_options = {
                -- Spawn options
                teleport_to_vehicle = spawn_state.teleport_to_vehicle,
                delete_old_vehicle = spawn_state.delete_old_vehicle,
                spawn_in_air = spawn_state.spawn_in_air,
                engine_on = spawn_state.engine_on,
                max_performance = spawn_state.max_performance,
                max_upgrade = spawn_state.max_upgrade,
                clean_vehicle = spawn_state.clean_vehicle,
                bulletproof_tires = spawn_state.bulletproof_tires,
                vehicle_godmode = spawn_state.vehicle_godmode,
                radio_off = spawn_state.radio_off,
                keep_velocity = spawn_state.keep_velocity,

                -- Color customization
                use_preset = spawn_state.use_preset,
                color_mode = spawn_state.color_mode,
                primary_color = spawn_state.primary_color,
                secondary_color = spawn_state.secondary_color,
                primary_color_rgb = {
                    r = spawn_state.primary_color_rgb.r,
                    g = spawn_state.primary_color_rgb.g,
                    b = spawn_state.primary_color_rgb.b
                },
                secondary_color_rgb = {
                    r = spawn_state.secondary_color_rgb.r,
                    g = spawn_state.secondary_color_rgb.g,
                    b = spawn_state.secondary_color_rgb.b
                },
                chameleon_paint = spawn_state.chameleon_paint,
                pearlescent_id = spawn_state.pearlescent_id,
                wheel_color_id = spawn_state.wheel_color_id,

                -- Light customization
                xenon_color = spawn_state.xenon_color,
                neon_color = spawn_state.neon_color,

                -- Wheel customization
                wheel_type = spawn_state.wheel_type,
                wheel_index = spawn_state.wheel_index,
                custom_tires = spawn_state.custom_tires,
                tire_smoke_color = spawn_state.tire_smoke_color,

                -- Window/Plate
                window_tint = spawn_state.window_tint,
                plate_type = spawn_state.plate_type,
                plate_text = spawn_state.plate_text,
            }
        }

        table.insert(spawn_state.saved_vehicles, saved)

        -- Save to disk (use paths.script like ClickUI)
        local base = (paths and paths.script) or ".\\"
        if not base:match("[\\/]$") then base = base .. "\\" end
        local save_dir = base .. "Carpie Diem\\vehicles\\"
        local save_path = save_dir .. name .. ".json"

        debug_info("SAVE", "Base path: " .. base)
        debug_info("SAVE", "Save dir: " .. save_dir)
        debug_info("SAVE", "Saving to: " .. save_path)

        -- Ensure directory exists (create if needed)
        if dirs and dirs.create then
            pcall(dirs.create, base .. "Carpie Diem\\")
            pcall(dirs.create, save_dir)
        end

        if file and file.open then
            local ok, err = pcall(function()
                -- Helper to convert table to JSON string
                local function table_to_json(t, indent)
                    indent = indent or "  "
                    local json = "{\n"
                    local first = true
                    for k, v in pairs(t) do
                        if not first then json = json .. ",\n" end
                        first = false
                        json = json .. indent .. '  "' .. tostring(k) .. '": '
                        if type(v) == "table" then
                            json = json .. table_to_json(v, indent .. "  ")
                        elseif type(v) == "boolean" then
                            json = json .. (v and "true" or "false")
                        elseif type(v) == "number" then
                            json = json .. tostring(v)
                        else
                            json = json .. '"' .. tostring(v) .. '"'
                        end
                    end
                    json = json .. "\n" .. indent .. "}"
                    return json
                end

                -- Create comprehensive JSON (EXACTLY LIKE CLICKUI)
                local json_str = "{\n"
                json_str = json_str .. '  "name": "' .. saved.name .. '",\n'
                json_str = json_str .. '  "model": ' .. saved.model .. ',\n'
                json_str = json_str .. '  "customizations": ' .. table_to_json(saved.customizations, "  ") .. ',\n'
                json_str = json_str .. '  "spawn_options": ' .. table_to_json(saved.spawn_options, "  ") .. '\n'
                json_str = json_str .. "}"

                -- Write to file
                local f = file.open(save_path, {create_if_not_exists=true, append=false})
                if f and f.valid then
                    f.text = json_str
                    if f.close then
                        pcall(f.close, f)
                    elseif f.Close then
                        pcall(f.Close, f)
                    end
                    safe_toast("Saved: " .. name .. " (to disk)")
                else
                    safe_toast("Saved: " .. name .. " (memory only)")
                end
            end)

            if not ok then
                safe_toast("Saved: " .. name .. " (memory only)")
            end
        else
            safe_toast("Saved: " .. name .. " (memory only)")
        end

        spawn_state.save_filename = ""
    end

    -- Helper: Load saved vehicles from disk on startup (EXACTLY LIKE CLICKUI)
    local function load_saved_vehicles_from_disk()
        debug_info("LOAD", "load_saved_vehicles_from_disk() called")

        -- Check APIs exactly like ClickUI does
        if not dirs or not dirs.list then
            debug_warn("LOAD", "dirs.list API not available")
            return
        end

        if not file or not file.open then
            debug_warn("LOAD", "file.open API not available")
            return
        end

        debug_info("LOAD", "File and dirs APIs available, searching for JSON files")

        -- Build list of paths to try (dynamic first, then hardcoded fallback)
        local paths_to_try = {}

        -- Try paths.script first (like ClickUI)
        local base = (paths and paths.script) or nil
        if base then
            if not base:match("[\\/]$") then base = base .. "\\" end
            table.insert(paths_to_try, base .. "Carpie Diem\\vehicles\\")
            debug_info("LOAD", "Added dynamic path: " .. base .. "Carpie Diem\\vehicles\\")
        end

        -- Add fallback path using SCRIPT_DIR
        local fallback_base = SCRIPT_DIR or ".\\"
        if not fallback_base:match("[\\/]$") then fallback_base = fallback_base .. "\\" end
        local fallback = fallback_base .. "Carpie Diem\\vehicles\\"
        table.insert(paths_to_try, fallback)
        debug_info("LOAD", "Added fallback path: " .. fallback)

        local json_files = nil
        local used_path = nil

        -- Try each path until we find files
        for _, save_dir in ipairs(paths_to_try) do
            debug_info("LOAD", "Trying path: " .. save_dir)
            local ok_list, files = pcall(dirs.list, save_dir, "json")
            debug_info("LOAD", "dirs.list returned ok=" .. tostring(ok_list) .. ", files=" .. tostring(files and #files or "nil"))

            if ok_list and files and #files > 0 then
                json_files = files
                used_path = save_dir
                debug_info("LOAD", "Found " .. #files .. " files in: " .. save_dir)
                break
            end
        end

        if not json_files or #json_files == 0 then
            debug_info("LOAD", "No saved vehicles found in any path")
            return
        end

        debug_info("LOAD", "Using path: " .. used_path)
        debug_info("LOAD", "Found " .. #json_files .. " saved vehicle files")

        for _, filepath in ipairs(json_files) do
            debug_info("LOAD", "Processing file: " .. tostring(filepath))

            -- Read file EXACTLY like ClickUI's parse_lexis_file does
            local ok_open, f = pcall(file.open, filepath, {create_if_not_exists=false, append=false})

            if ok_open and f and f.valid then
                local json_str = f.text

                -- Close file like ClickUI does
                if f.close then
                    pcall(f.close, f)
                elseif f.Close then
                    pcall(f.Close, f)
                end

                if not json_str or json_str == "" then
                    debug_warn("LOAD", "File is empty: " .. filepath)
                else
                    debug_info("LOAD", "Read " .. #json_str .. " bytes from file")

                    -- Parse JSON manually (simple parser for our format)
                    local name_match = json_str:match('"name"%s*:%s*"([^"]*)"')
                    local model_match = json_str:match('"model"%s*:%s*(%-?%d+)')  -- Support negative hashes

                    debug_info("LOAD", "name_match: " .. tostring(name_match) .. ", model_match: " .. tostring(model_match))

                    if name_match and model_match then
                        -- Create saved vehicle entry with model hash (LIKE CLICKUI)
                        local saved = {
                            name = name_match,
                            model = tonumber(model_match),
                            customizations = {},
                            spawn_options = {}
                        }
                        debug_info("LOAD", "Created saved vehicle entry: " .. saved.name .. " (model hash: " .. saved.model .. ")")

                        -- Parse LEXIS FORMAT customizations
                        local c = saved.customizations

                        -- Helper to extract array like {"1": val1, "2": val2, "3": val3}
                        local function extract_array(key)
                            local pattern = '"' .. key .. '"%s*:%s*{([^}]*)}'
                            local block = json_str:match(pattern)
                            if block then
                                local arr = {}
                                for idx, val in block:gmatch('"(%d+)"%s*:%s*(%-?%d+)') do
                                    arr[tonumber(idx)] = tonumber(val)
                                end
                                return arr
                            end
                            return nil
                        end

                        -- Helper to extract bool array like {"1": true, "2": false}
                        local function extract_bool_array(key)
                            local pattern = '"' .. key .. '"%s*:%s*{([^}]*)}'
                            local block = json_str:match(pattern)
                            if block then
                                local arr = {}
                                for idx, val in block:gmatch('"(%d+)"%s*:%s*(%a+)') do
                                    arr[tonumber(idx)] = (val == "true")
                                end
                                return arr
                            end
                            return nil
                        end

                        -- Helper to extract single number
                        local function extract_num(key)
                            local pattern = '"' .. key .. '"%s*:%s*(%-?%d+)'
                            local match = json_str:match(pattern)
                            return match and tonumber(match) or nil
                        end

                        -- [Lexis] colors: {"1": primary, "2": secondary}
                        c.colors = extract_array("colors")

                        -- [Lexis] custom primary: {"1": r, "2": g, "3": b}
                        c["custom primary"] = extract_array("custom primary")

                        -- [Lexis] custom secondary: {"1": r, "2": g, "3": b}
                        c["custom secondary"] = extract_array("custom secondary")

                        -- [Lexis] extra colors: {"1": pearl, "2": wheel}
                        c["extra colors"] = extract_array("extra colors")

                        -- [Lexis] neon color: {"1": r, "2": g, "3": b}
                        c["neon color"] = extract_array("neon color")

                        -- [Lexis] smoke color: {"1": r, "2": g, "3": b}
                        c["smoke color"] = extract_array("smoke color")

                        -- [Lexis] neon enabled: {"1": bool, "2": bool, "3": bool, "4": bool}
                        c["neon enabled"] = extract_bool_array("neon enabled")

                        -- [Lexis] extras: {"1": bool, ..., "15": bool}
                        c.extras = extract_bool_array("extras")

                        -- [Lexis] mods: {"1": mod_idx, ..., "49": mod_idx}
                        c.mods = extract_array("mods")

                        -- [Lexis] Single values
                        c["wheel type"] = extract_num("wheel type")
                        c["window tint"] = extract_num("window tint")
                        c["plate type"] = extract_num("plate type")
                        c.livery = extract_num("livery")
                        c["extra color 5"] = extract_num("extra color 5")

                        -- [Lexis] plate text
                        local plate_match = json_str:match('"plate text"%s*:%s*"([^"]*)"')
                        if plate_match then
                            c["plate text"] = plate_match
                        end

                        debug_info("LOAD", "Parsed Lexis customizations for: " .. saved.name)

                        table.insert(spawn_state.saved_vehicles, saved)
                        debug_info("LOAD", "Added vehicle to array: " .. saved.name .. " (total: " .. #spawn_state.saved_vehicles .. ")")
                    end
                end
            else
                debug_info("LOAD", "Failed to open file: " .. filepath)
            end
        end

        debug_info("LOAD", "Loaded " .. #spawn_state.saved_vehicles .. " saved vehicles")
        if #spawn_state.saved_vehicles > 0 then
            safe_toast("Loaded " .. #spawn_state.saved_vehicles .. " saved vehicles")
        end
    end

    -- Load saved vehicles at startup (async job) - EXACTLY LIKE CLICKUI
    util.create_job(function()
        util.yield(500)  -- Wait 500ms like ClickUI does
        debug_info("STARTUP", "Loading saved vehicles from disk...")
        load_saved_vehicles_from_disk()
        spawn_state.saved_vehicles_loaded = true  -- Mark as loaded
        debug_info("STARTUP", "Saved vehicles loaded: " .. #spawn_state.saved_vehicles)
    end)

    -- Helper: Spawn saved vehicle with ALL customizations
    local function spawn_saved_vehicle(saved)
        debug_info("SPAWN_SAVED", "spawn_saved_vehicle called")

        if not saved then
            debug_error("SPAWN_SAVED", "saved is nil")
            safe_toast("Invalid saved vehicle (nil)")
            return
        end

        if not saved.model then
            debug_error("SPAWN_SAVED", "model is nil for: " .. tostring(saved.name))
            safe_toast("Invalid saved vehicle (no model)")
            return
        end

        debug_info("SPAWN_SAVED", "Vehicle: " .. tostring(saved.name) .. " Model Hash: " .. tostring(saved.model))

        if spawn_state.is_spawning then
            debug_warn("SPAWN_SAVED", "Already spawning")
            safe_toast("Already spawning a vehicle")
            return
        end

        spawn_state.is_spawning = true
        debug_info("SPAWN_SAVED", "Starting spawn job")
        safe_toast("Spawning: " .. (saved.name or "Saved Vehicle"))

        util.create_job(function()
            -- Wrap everything in pcall to ensure is_spawning gets reset
            local ok, err = pcall(function()
                debug_info("SPAWN_SAVED", "Inside spawn job")

                -- LIKE CLICKUI: Use the hash DIRECTLY (no conversion needed)
                local hash = saved.model
                debug_info("SPAWN_SAVED", "Model hash: " .. hash)

                -- Request model
                debug_info("SPAWN_SAVED", "Requesting model...")
                invoker.call(0x963D27A58DF860AC, hash)

                -- Wait for model to load (timeout after 5 seconds)
                local timeout = 100
                while timeout > 0 and not invoker.call(0x98A4EB5D89A0C952, hash).bool do
                    timeout = timeout - 1
                    util.yield()
                end

                if timeout == 0 then
                    debug_error("SPAWN_SAVED", "Model load timeout for hash: " .. tostring(hash))
                    safe_toast("Failed to load vehicle model")
                    return
                end
                debug_info("SPAWN_SAVED", "Model loaded successfully")

                -- Get player ped and position
                local ped = invoker.call(0x43A66C31C68491C0, -1).int
                local coords = invoker.call(0x3FEF770D40960D5A, ped, true).scr_vec3  -- GET_ENTITY_COORDS (need .scr_vec3)
                local heading = invoker.call(0xe83d4f9ba2a38914, ped).float or 0.0  -- GET_ENTITY_HEADING

                local x, y, z = coords.x, coords.y, coords.z

                -- Spawn offset
                if spawn_state.spawn_in_air then
                    z = z + 5.0
                else
                    z = z + 0.5
                end

                -- Note: Delete old vehicle disabled to prevent crash (DELETE_VEHICLE requires pointer)
                -- The player will be teleported to new vehicle automatically

                -- Create vehicle
                debug_info("SPAWN_SAVED", "Creating vehicle...")
                local veh = invoker.call(0xAF35D0D2583051B0, hash, x, y, z, heading, true, false).int
                debug_info("SPAWN_SAVED", "Vehicle handle: " .. tostring(veh))

                if not veh or veh == 0 then
                    debug_error("SPAWN_SAVED", "CREATE_VEHICLE returned 0")
                    safe_toast("Failed to spawn vehicle")
                    return
                end

                -- Apply ALL saved customizations (EXACTLY LIKE CLICKUI's apply_lexis_mods)
                local c = saved.customizations
                if c and type(c) == "table" then
                    debug_info("SPAWN_SAVED", "Applying Lexis format customizations...")

                    -- Enable mod kit
                    invoker.call(0x1F2AA07F00B3217A, veh, 0)  -- SET_VEHICLE_MOD_KIT

                    -- [Lexis] Wheel Type
                    if c["wheel type"] then
                        invoker.call(0x487EB21CC7295BA1, veh, c["wheel type"])  -- SET_VEHICLE_WHEEL_TYPE
                    end

                    -- [Lexis] Mods (array: index 1-49 maps to slots 0-48)
                    if c.mods and type(c.mods) == "table" then
                        for i, mod_index in ipairs(c.mods) do
                            local slot = i - 1
                            if mod_index and mod_index >= 0 then
                                invoker.call(0x6AF0636DDEDCB6DD, veh, slot, mod_index, false)  -- SET_VEHICLE_MOD
                            end
                        end
                    end

                    -- [Lexis] Colors (array: [primary, secondary])
                    if c.colors and type(c.colors) == "table" then
                        local primary = c.colors[1] or 0
                        local secondary = c.colors[2] or 0
                        invoker.call(0x4F1D4BE3A7F24601, veh, primary, secondary)  -- SET_VEHICLE_COLOURS
                    end

                    -- [Lexis] Custom Primary (array: [r, g, b])
                    if c["custom primary"] and type(c["custom primary"]) == "table" then
                        local r = c["custom primary"][1] or 0
                        local g = c["custom primary"][2] or 0
                        local b = c["custom primary"][3] or 0
                        invoker.call(0x7141766F91D15BEA, veh, r, g, b)  -- SET_VEHICLE_CUSTOM_PRIMARY_COLOUR
                    end

                    -- [Lexis] Custom Secondary (array: [r, g, b])
                    if c["custom secondary"] and type(c["custom secondary"]) == "table" then
                        local r = c["custom secondary"][1] or 0
                        local g = c["custom secondary"][2] or 0
                        local b = c["custom secondary"][3] or 0
                        invoker.call(0x36CED73BFED89754, veh, r, g, b)  -- SET_VEHICLE_CUSTOM_SECONDARY_COLOUR
                    end

                    -- [Lexis] Extra Colors (array: [pearl, wheel])
                    if c["extra colors"] and type(c["extra colors"]) == "table" then
                        local pearl = c["extra colors"][1] or 0
                        local wheel = c["extra colors"][2] or 0
                        invoker.call(0x2036F561ADD12E33, veh, pearl, wheel)  -- SET_VEHICLE_EXTRA_COLOURS
                    end

                    -- [Lexis] Window Tint
                    if c["window tint"] then
                        invoker.call(0x57C51E6BAD752696, veh, c["window tint"])  -- SET_VEHICLE_WINDOW_TINT
                    end

                    -- [Lexis] Tire Smoke (array: [r, g, b])
                    if c["smoke color"] and type(c["smoke color"]) == "table" then
                        local r = c["smoke color"][1] or 255
                        local g = c["smoke color"][2] or 255
                        local b = c["smoke color"][3] or 255
                        invoker.call(0x3DFF319A831E0CDB, veh, 20, true)  -- TOGGLE_VEHICLE_MOD
                        invoker.call(0xB5BA80F839791C0F, veh, r, g, b)  -- SET_VEHICLE_TYRE_SMOKE_COLOR
                    end

                    -- [Lexis] Neon Enabled (array: [left, right, front, back])
                    if c["neon enabled"] and type(c["neon enabled"]) == "table" then
                        for i = 0, 3 do
                            local enabled = c["neon enabled"][i + 1]
                            if enabled ~= nil then
                                invoker.call(0x2AA720E4287BF269, veh, i, enabled)  -- SET_VEHICLE_NEON_ENABLED
                            end
                        end
                    end

                    -- [Lexis] Neon Color (array: [r, g, b])
                    if c["neon color"] and type(c["neon color"]) == "table" then
                        local r = c["neon color"][1] or 255
                        local g = c["neon color"][2] or 0
                        local b = c["neon color"][3] or 255
                        invoker.call(0x8E0A582209A62695, veh, r, g, b)  -- SET_VEHICLE_NEON_COLOUR
                    end

                    -- [Lexis] Plate Text
                    if c["plate text"] and c["plate text"] ~= "" then
                        invoker.call(0x95A88F0B409CDA47, veh, c["plate text"])  -- SET_VEHICLE_NUMBER_PLATE_TEXT
                    end

                    -- [Lexis] Plate Type
                    if c["plate type"] then
                        invoker.call(0x9088EB5A43FFB0A1, veh, c["plate type"])  -- SET_VEHICLE_NUMBER_PLATE_TEXT_INDEX
                    end

                    -- [Lexis] Extras (array: 1-15)
                    if c.extras and type(c.extras) == "table" then
                        for i = 0, 14 do
                            local enabled = c.extras[i + 1]
                            if enabled ~= nil then
                                invoker.call(0x7EE3A3C5E4A40CC9, veh, i, not enabled)  -- SET_VEHICLE_EXTRA
                            end
                        end
                    end

                    -- [Lexis] Livery
                    if c.livery and c.livery >= 0 then
                        invoker.call(0x60bf608f1b8cd1b6, veh, c.livery)  -- SET_VEHICLE_LIVERY
                    end

                    debug_info("SPAWN_SAVED", "Applied all customizations")
                end

                -- Apply spawn options (engine, god mode, etc.)
                if spawn_state.engine_on then
                    invoker.call(0x2497C4717C8B881E, veh, true, true, true)
                end

                if spawn_state.vehicle_godmode then
                    invoker.call(0x3882114bde571ad4, veh, true)  -- SET_ENTITY_INVINCIBLE
                end

                if spawn_state.teleport_to_vehicle then
                    invoker.call(0xF75B0D629E1C063D, ped, veh, -1)
                end

                debug_info("SPAWN_SAVED", "Spawn complete!")
                safe_toast("Spawned: " .. (saved.name or "Saved Vehicle"))
            end)

            -- Always reset spawning flag
            if not ok then
                debug_error("SPAWN_SAVED", "Error during spawn: " .. tostring(err))
                safe_toast("Spawn error: " .. tostring(err))
            end
            spawn_state.is_spawning = false
            debug_info("SPAWN_SAVED", "Reset is_spawning flag")
        end)
    end

    -- Helper: Delete saved vehicle
    local function delete_saved_vehicle(index)
        if not spawn_state.saved_vehicles then
            spawn_state.saved_vehicles = {}
            return
        end

        if not index or index < 1 or index > #spawn_state.saved_vehicles then
            safe_toast("Invalid vehicle selection")
            return
        end

        local saved = spawn_state.saved_vehicles[index]
        table.remove(spawn_state.saved_vehicles, index)

        -- Safe toast with name check
        local vehicle_name = (saved and saved.name) and tostring(saved.name) or "vehicle"
        safe_toast("Deleted: " .. vehicle_name)

        if spawn_state.selected_saved_vehicle == index then
            spawn_state.selected_saved_vehicle = nil
        elseif spawn_state.selected_saved_vehicle and spawn_state.selected_saved_vehicle > index then
            spawn_state.selected_saved_vehicle = spawn_state.selected_saved_vehicle - 1
        end
    end

local function draw_spawn_tab()
    local s = UI.scale
    local base_x = content_x
    local base_y = widget_y
    local total_w = content_w
    local total_h = UI.h - UI.header_h - math.floor(20 * s)

    -- MAIN TAB BAR (4 tabs like ClickUI)
    local maintab_h = math.floor(36 * s)
    local maintabs = {"Vehicles", "Saved Vehicles", "Props", "Map Builder"}
    local maintab_w = total_w / #maintabs

    for i, name in ipairs(maintabs) do
        local tx = base_x + (i - 1) * maintab_w
        local is_active = (spawn_state.main_tab == i)
        local is_hover = is_mouse_in(tx, base_y, maintab_w, maintab_h)

        local bg_col = is_active and C.tab_active or (is_hover and C.subtab_hover or C.subtab_bg)
        draw_rect(tx, base_y, maintab_w, maintab_h, bg_col, 0)

        local text_col = is_active and C.text or C.text_dim
        draw_text_centered(name, tx, base_y, maintab_w, maintab_h, UI.font_small, text_col)

        if is_hover and MOUSE.just_pressed then
            spawn_state.main_tab = i
        end
    end

    local content_y = base_y + maintab_h + math.floor(4 * s)
    local content_h = total_h - maintab_h - math.floor(4 * s)

    -- TAB 1: VEHICLES (Dual column: list + options)
    if spawn_state.main_tab == 1 then
        -- Dual column layout
        local gap = math.floor(12 * s)
        local left_w = math.floor(300 * s)
        local right_w = total_w - left_w - gap

        local left_x = base_x
        local right_x = base_x + left_w + gap

        -- LEFT COLUMN: Vehicle list with search
        draw_rect(left_x, content_y, left_w, content_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        -- Search bar
        local search_h = math.floor(32 * s)
        local search_y = content_y + math.floor(8 * s)
        local search_box_x = left_x + math.floor(8 * s)
        local search_box_w = left_w - math.floor(16 * s)
        local search_hover = is_mouse_in(search_box_x, search_y, search_box_w, search_h)

        -- Click to focus/unfocus (but not on the clear button area)
        local clear_btn_w_pre = math.floor(24 * s)
        local clear_x_pre = search_box_x + search_box_w - clear_btn_w_pre - math.floor(2 * s)
        local on_clear_btn = #spawn_state.search_query > 0 and is_mouse_in(clear_x_pre, search_y, clear_btn_w_pre, search_h)
        if search_hover and MOUSE.just_pressed and not on_clear_btn then
            spawn_state.search_focused = not spawn_state.search_focused
        end

        -- Keyboard input using input.key (like ClickUI)
        if spawn_state.search_focused and input and input.key then
            -- Backspace
            if input.key(0x08).just_pressed then  -- Backspace
                if #spawn_state.search_query > 0 then
                    spawn_state.search_query = spawn_state.search_query:sub(1, -2)
                end
            end

            -- Simple letter input (A-Z, 0-9, Space)
            for code = 0x30, 0x39 do  -- 0-9
                if input.key(code).just_pressed then
                    spawn_state.search_query = spawn_state.search_query .. string.char(code)
                end
            end
            for code = 0x41, 0x5A do  -- A-Z
                if input.key(code).just_pressed then
                    spawn_state.search_query = spawn_state.search_query .. string.char(code):lower()
                end
            end
            if input.key(0x20).just_pressed then  -- Space
                spawn_state.search_query = spawn_state.search_query .. " "
            end
        end

        -- Search box background
        local search_bg = spawn_state.search_focused and C.widget_hover or (search_hover and C.widget_hover or C.widget_bg)
        draw_rect(search_box_x, search_y, search_box_w, search_h, search_bg, math.floor((UI.widget_rounding or 5) * s))
        -- Accent border when focused
        if spawn_state.search_focused then
            draw_rect(search_box_x, search_y, search_box_w, math.floor(2 * s), C.accent, math.floor(6 * s))
            draw_rect(search_box_x, search_y + search_h - math.floor(2 * s), search_box_w, math.floor(2 * s), C.accent, math.floor(6 * s))
            draw_rect(search_box_x, search_y, math.floor(2 * s), search_h, C.accent, math.floor(6 * s))
            draw_rect(search_box_x + search_box_w - math.floor(2 * s), search_y, math.floor(2 * s), search_h, C.accent, math.floor(6 * s))
        end
        -- Clear button (X) when there is text
        local clear_btn_w = math.floor(24 * s)
        if #spawn_state.search_query > 0 then
            local clear_x = search_box_x + search_box_w - clear_btn_w - math.floor(2 * s)
            local clear_hover = is_mouse_in(clear_x, search_y, clear_btn_w, search_h)
            draw_rect(clear_x, search_y + math.floor(2 * s), clear_btn_w, search_h - math.floor(4 * s), clear_hover and color(80,80,80,200) or color(60,60,60,180), math.floor(4 * s))
            draw_text_centered("X", clear_x, search_y, clear_btn_w, search_h, UI.font_small, clear_hover and color(255,100,100,255) or C.text_dim)
            if clear_hover and MOUSE.just_pressed then
                spawn_state.search_query = ""
            end
        end
        -- Search text / placeholder
        local display_text = spawn_state.search_query
        if spawn_state.search_focused then
            display_text = display_text .. "_"
        end
        local text_x = search_box_x + math.floor(12 * s)
        local max_text_w = search_box_w - math.floor(24 * s) - (#spawn_state.search_query > 0 and clear_btn_w or 0)
        if #spawn_state.search_query == 0 then
            draw_text("Search vehicles...", text_x, search_y + math.floor(8 * s), UI.font_small, color(100,100,100,180))
        else
            draw_text(display_text, text_x, search_y + math.floor(8 * s), UI.font_small, spawn_state.search_focused and C.text or C.text)
        end

        -- Vehicle categories (scrollable, collapsible)
        local list_y = search_y + search_h + math.floor(8 * s)
        local list_h = content_h - search_h - math.floor(24 * s)
        local scroll_offset = spawn_state.vehicle_scroll[spawn_state.search_query] or 0
        local item_y = list_y - scroll_offset

        local search_query = (spawn_state.search_query or ""):lower()
        local total_items = 0

        for cat_idx, category in ipairs(VEHICLE_CATEGORIES) do
