    -- WORKING Spectate system - EXACTLY like ClickUI
    local SPECTATE_FREEZE_INTERVAL = 2.0
    local spectate_freeze_timer = 0
    
    -- Spectate background thread like ClickUI
    util.create_thread(function()
        while true do
            if player_state.spectating_id then
                local now = os.clock()
                if now > spectate_freeze_timer then
                    local me = players and players.me and players.me()
                    local ped = me and me.ped
                    if ped then
                        local FREEZE_ENTITY_POSITION = 0x428ca6dbd1094446
                        invoker.call(FREEZE_ENTITY_POSITION, ped, true)
                    end
                    spectate_freeze_timer = now + SPECTATE_FREEZE_INTERVAL
                end
            end
            util.yield(0)
        end
    end)
    
    local function stop_spectating()
        if player_state.spectating_id == nil then return end

        pcall(function()
            local me = players and players.me and players.me()
            local my_ped = me and me.ped

            if my_ped then
                -- Disable spectator mode - EXACTLY LIKE CLICKUI
                local NETWORK_SET_IN_SPECTATOR_MODE = 0x423de3854bb50894
                invoker.call(NETWORK_SET_IN_SPECTATOR_MODE, false, my_ped)
                
                -- Unfreeze player
                local FREEZE_ENTITY_POSITION = 0x428ca6dbd1094446
                invoker.call(FREEZE_ENTITY_POSITION, my_ped, false)
                
                -- Restore position - EXACTLY LIKE CLICKUI
                if player_state.spectate_saved_coords then
                    local c = player_state.spectate_saved_coords
                    local SET_ENTITY_COORDS_NO_OFFSET = 0x239a3351ac1da385
                    invoker.call(SET_ENTITY_COORDS_NO_OFFSET, my_ped, c.x, c.y, c.z, false, false, false)
                    player_state.spectate_saved_coords = nil
                end
            end
        end)
        
        player_state.spectating_id = nil
        spectate_freeze_timer = 0
    end

    local function start_spectating(target_id, target_ped)
        local me = players and players.me and players.me()
        if not me or not me.ped or not me.coords then return false end

        pcall(function()
            -- Save current position - EXACTLY LIKE CLICKUI
            player_state.spectate_saved_coords = {x = me.coords.x, y = me.coords.y, z = me.coords.z}
            
            -- Freeze my ped - EXACTLY LIKE CLICKUI
            local FREEZE_ENTITY_POSITION = 0x428ca6dbd1094446
            invoker.call(FREEZE_ENTITY_POSITION, me.ped, true)
            
            -- Enable spectator mode - EXACTLY LIKE CLICKUI (pass target ped, not player ID)
            local NETWORK_SET_IN_SPECTATOR_MODE = 0x423de3854bb50894
            invoker.call(NETWORK_SET_IN_SPECTATOR_MODE, true, target_ped)
        end)
        
        player_state.spectating_id = target_id
        spectate_freeze_timer = os.clock() + SPECTATE_FREEZE_INTERVAL
        return true
    end

    -- Helper for info panel rows - SEPARATE INFO PANEL outside main window (matching ClickUI PlayerInfo.lua)
    local function draw_info_row(label1, value1, label2, value2, x, y, w, font_size, pad, row_h)
        local half = w / 2
        local fs = font_size or UI.font_widget
        local p = pad or math.floor(10 * UI.scale)

        -- Left column: label + value (value right-aligned within left half)
        draw_text(label1, x + p, y, fs, C.overlay_text)

        -- Estimate text width for right-alignment
        local v1_str = tostring(value1)
        local v1_w = #v1_str * (fs * 0.55)
        draw_text(v1_str, x + half - v1_w - p, y, fs, C.overlay_text)

        -- Divider
        draw_text("|", x + half - 2, y - 2, fs, C.overlay_divider)

        -- Right column
        if label2 then
            draw_text(label2, x + half + p, y, fs, C.overlay_text)
            local v2_str = tostring(value2)
            local v2_w = #v2_str * (fs * 0.55)
            draw_text(v2_str, x + w - v2_w - p, y, fs, C.overlay_text)
        end

        return y + (row_h or math.floor(24 * UI.scale))
    end

    local function draw_player_tab()
        update_player_list()

        local s = UI.scale
        local base_x = content_x
        local base_y = widget_y
        local total_w = content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- TWO columns inside main window (player list + actions) - scaled properly
        local gap = math.floor(10 * s)
        local list_w = math.floor(280 * s)
        local action_w = total_w - list_w - gap - math.floor(10 * s)

        -- LEFT: Player List
        local list_x = base_x + math.floor(5 * s)
        local list_y = base_y
        local list_h = total_h

        local player_count = #player_state.player_list
        local header_h = math.floor(24 * s)
        draw_rect(list_x, list_y, list_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))
        draw_text("Online Players (" .. player_count .. "/32)", list_x + math.floor(8 * s), list_y + math.floor(5 * s), UI.font_small, C.text)
        list_y = list_y + header_h + 2

        draw_rect(list_x, list_y, list_w, list_h - header_h - 2, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local item_h = math.floor(26 * s)
        local visible_items = math.floor((list_h - header_h - 2) / item_h)

        -- Handle mouse wheel scrolling for player list
        local list_hover = is_mouse_in(list_x, list_y, list_w, list_h - header_h - 2)
        if list_hover then
            if MOUSE.scroll_up then
                player_state.list_scroll = math.max(0, player_state.list_scroll - 1)
            elseif MOUSE.scroll_down then
                local max_scroll = math.max(0, player_count - visible_items)
                player_state.list_scroll = math.min(max_scroll, player_state.list_scroll + 1)
            end
        end

        local start_idx = math.max(1, player_state.list_scroll + 1)
        local end_idx = math.min(player_count, start_idx + visible_items - 1)

        local py = list_y + math.floor(3 * s)
        for i = start_idx, end_idx do
            local p = player_state.player_list[i]
            if p then
                local label = p.name .. " [" .. p.id .. "]"
                if player_state.selected_id == p.id then label = "> " .. label end
                if selectable(label, player_state.selected_id == p.id, p.tags, list_x + 2, py, list_w - 4, item_h - 2) then
                    local prev_id = player_state.selected_id
                    player_state.selected_id = p.id
                    if DEBUG.feature_debug and prev_id ~= p.id then
                        debug_info("PLAYER", string.format("Selected player: %s [ID: %d]", p.name or "Unknown", p.id))
                    end
                end
                py = py + item_h
            end
        end

        -- RIGHT: Actions panel
        local action_x = list_x + list_w + gap
        local action_y = base_y

        local new_sub_tab, tab_h = sub_tab_bar(PLAYER_SUB_TABS, player_state.sub_tab, action_x, action_y, action_w)
        player_state.sub_tab = new_sub_tab
        action_y = action_y + tab_h

        draw_rect(action_x, action_y, action_w, list_h - tab_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local selected = get_selected_player()
        local ay = action_y + math.floor(8 * s)
        local btn_h = math.floor(28 * s)
        local btn_gap = math.floor(4 * s)
        local side_pad = math.floor(8 * s)

        if not selected then
            draw_text("Select a player", action_x + math.floor(10 * s), ay, UI.font_widget, C.text_dim)
        else
            local btn_w = (action_w - side_pad * 3) / 2

            if player_state.sub_tab == 1 then
                -- GENERAL
                local is_spec = (player_state.spectating_id == selected.id)
                local cb_h = math.floor(26 * s)
                local new_spec = inline_toggle("Spectate Player", is_spec, action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                if new_spec ~= is_spec then
                    if is_spec then stop_spectating(); safe_toast("Stopped spectating")
                    else if start_spectating(selected.id, selected.ped) then safe_toast("Spectating " .. selected.name) end end
                end
                ay = ay + cb_h + btn_gap
                if small_button("Copy Name", action_x + side_pad, ay, btn_w, btn_h) then safe_toast("Name: " .. selected.name) end
                if small_button("Copy RID", action_x + side_pad * 2 + btn_w, ay, btn_w, btn_h) then safe_toast("RID: " .. tostring(selected.rockstar_id)) end
                ay = ay + btn_h + btn_gap

                -- CUSTOM MESSAGE SECTION
                ay = ay + math.floor(10 * s)
                draw_text("  Send Phone Message (to selected player)", action_x + side_pad, ay, UI.font_widget, C.accent)
                ay = ay + math.floor(18 * s)

                -- Message input box
                local input_h = math.floor(32 * s)
                local input_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, input_h)
                local bg_col = player_state.message_text_focused and C.widget_hover or (input_hover and C.widget_hover or C.widget_bg)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, input_h, bg_col, math.floor((UI.widget_rounding or 5) * s))
                -- Accent border when focused
                if player_state.message_text_focused then
                    local mx = action_x + side_pad
                    local mw = action_w - side_pad * 2
                    draw_rect(mx, ay, mw, math.floor(2 * s), C.accent, math.floor(6 * s))
                    draw_rect(mx, ay + input_h - math.floor(2 * s), mw, math.floor(2 * s), C.accent, math.floor(6 * s))
                    draw_rect(mx, ay, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
                    draw_rect(mx + mw - math.floor(2 * s), ay, math.floor(2 * s), input_h, C.accent, math.floor(6 * s))
                end

                -- Handle focus
                if input_hover and MOUSE.just_pressed then
                    player_state.message_text_focused = true
                elseif MOUSE.just_pressed and not input_hover then
                    player_state.message_text_focused = false
                end

                -- Handle keyboard input
                if player_state.message_text_focused and input and input.key then
                    if input.key(0x08).just_pressed and #player_state.message_text > 0 then
                        player_state.message_text = player_state.message_text:sub(1, -2)
                    end
                    for code = 0x30, 0x39 do
                        if input.key(code).just_pressed then
                            player_state.message_text = player_state.message_text .. string.char(code)
                        end
                    end
                    local shift_pressed = input.key(0x10).pressed
                    for code = 0x41, 0x5A do
                        if input.key(code).just_pressed then
                            player_state.message_text = player_state.message_text .. (shift_pressed and string.char(code) or string.char(code):lower())
                        end
                    end
                    if input.key(0x20).just_pressed then player_state.message_text = player_state.message_text .. " " end
                    if input.key(0xBD).just_pressed then player_state.message_text = player_state.message_text .. "-" end
                    if input.key(0xBB).just_pressed then player_state.message_text = player_state.message_text .. "=" end
                    if input.key(0xBC).just_pressed then player_state.message_text = player_state.message_text .. "," end
                    if input.key(0xBE).just_pressed then player_state.message_text = player_state.message_text .. "." end
                    if input.key(0xBF).just_pressed then player_state.message_text = player_state.message_text .. "/" end
                    if input.key(0xBA).just_pressed then player_state.message_text = player_state.message_text .. ":" end
                    if input.key(0xDE).just_pressed then player_state.message_text = player_state.message_text .. "'" end
                    if input.key(0xC0).just_pressed then player_state.message_text = player_state.message_text .. "`" end
                    if input.key(0xBD).just_pressed and shift_pressed then player_state.message_text = player_state.message_text .. "_" end
                end

                -- Display text
                if player_state.message_text ~= "" then
                    local display_text = player_state.message_text .. (player_state.message_text_focused and "_" or "")
                    draw_text(display_text, action_x + side_pad + math.floor(10 * s), ay + math.floor(8 * s), UI.font_small, C.text)
                else
                    draw_text("Type your message...", action_x + side_pad + math.floor(10 * s), ay + math.floor(8 * s), UI.font_small, color(100,100,100,180))
                end
                ay = ay + input_h + btn_gap

                -- Send button
                if small_button(" > Send Message", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if player_state.message_text ~= "" then
                        -- Send to selected player (phone message via NETWORK_SEND_TEXT_MESSAGE)
                        if selected then
                            -- Don't send to yourself (causes crash)
                            if selected.id == player_state.my_id then
                                safe_toast("Cannot send message to yourself!")
                            else
                                pcall(function()
                                    -- Use NETWORK_SEND_TEXT_MESSAGE (shows as phone message)
                                    local success = invoker.call(0x3A214F2EC889B100, player_state.message_text, selected.gamer_handle)
                                    if success and success.bool then
                                        safe_toast("Message sent to " .. selected.name)
                                    else
                                        safe_toast("Failed to send message (player may have blocked messages)")
                                    end
                                end)
                            end
                        else
                            safe_toast("Select a player first!")
                        end

                        -- Don't reset message so user can re-send if needed
                    else
                        safe_toast("Enter a message first")
                    end
                end
                ay = ay + btn_h + btn_gap

            elseif player_state.sub_tab == 2 then
                -- TELEPORT
                if small_button("Teleport To Player", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.coords and N.SET_ENTITY_COORDS_NO_OFFSET then
                        local me = players and players.me and players.me()
                        if me then
                            local entity = (me.vehicle and me.vehicle ~= 0) and me.vehicle or me.ped
                            if entity then
                                pcall(N.SET_ENTITY_COORDS_NO_OFFSET, entity, selected.coords.x, selected.coords.y, selected.coords.z, false, false, false)
                                safe_toast("Teleported to " .. selected.name)
                            end
                        end
                    else
                        safe_toast("Teleport not available")
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Teleport Above", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.coords and N.SET_ENTITY_COORDS_NO_OFFSET then
                        local me = players and players.me and players.me()
                        if me then
                            local entity = (me.vehicle and me.vehicle ~= 0) and me.vehicle or me.ped
                            if entity then
                                pcall(N.SET_ENTITY_COORDS_NO_OFFSET, entity, selected.coords.x, selected.coords.y, selected.coords.z + 10, false, false, false)
                                safe_toast("Teleported above " .. selected.name)
                            end
                        end
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Teleport Into Vehicle", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.vehicle and selected.vehicle ~= 0 then
                        local me = players and players.me and players.me()
                        if me and me.ped and N.SET_ENTITY_COORDS_NO_OFFSET then
                            -- Teleport to vehicle location
                            pcall(N.SET_ENTITY_COORDS_NO_OFFSET, me.ped, selected.coords.x, selected.coords.y, selected.coords.z, false, false, false)
                            -- Wait a moment then put in vehicle
                            util.yield(100)
                            -- TASK_WARP_PED_INTO_VEHICLE (0x9A7D091411C5F684) - seat -1 = driver
                            if invoker and invoker.call then
                                pcall(function()
                                    invoker.call(0x9A7D091411C5F684, me.ped, selected.vehicle, -1)
                                end)
                            end
                            safe_toast("Teleported into " .. selected.name .. "'s vehicle")
                        end
                    else
                        safe_toast(selected.name .. " is not in a vehicle")
                    end
                end

            elseif player_state.sub_tab == 3 then
                -- FRIENDLY
                if small_button("Give All Weapons", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.ped and N.GIVE_WEAPON_TO_PED and N.GET_HASH_KEY then
                        local weapons = {"WEAPON_PISTOL", "WEAPON_SMG", "WEAPON_ASSAULTRIFLE", "WEAPON_SNIPERRIFLE", "WEAPON_RPG"}
                        for _, w in ipairs(weapons) do
                            local hash = N.GET_HASH_KEY(w)
                            if hash and hash ~= 0 then
                                pcall(N.GIVE_WEAPON_TO_PED, selected.ped, hash, 9999, false, true)
                            end
                        end
                        safe_toast("Gave weapons to " .. selected.name)
                    else
                        safe_toast("Cannot give weapons")
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Give Max Health", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.ped and N.SET_ENTITY_HEALTH then
                        pcall(N.SET_ENTITY_HEALTH, selected.ped, 328, 0)
                        safe_toast("Gave health to " .. selected.name)
                    end
                end
                ay = ay + btn_h + btn_gap
                if small_button("Give Armor", action_x + side_pad, ay, action_w - side_pad * 2, btn_h) then
                    if selected.ped and N.SET_PED_ARMOUR then
                        pcall(N.SET_PED_ARMOUR, selected.ped, 100)
                        safe_toast("Gave armor to " .. selected.name)
                    end
                end

            elseif player_state.sub_tab == 4 then
                -- TROLLING
                local troll = get_troll_state(selected.id)
                local player_obj = get_player_object(selected.id)

                local cb_h = math.floor(26 * s)
                local box_size = math.floor(16 * s)

                -- One-Shot Attacks Dropdown
                local attack_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, cb_h, attack_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                local attack_arrow = (troll.attack_trolls_open or false) and "v" or ">"
                draw_text(attack_arrow .. " One-Shot Attacks", action_x + side_pad + math.floor(6 * s), ay + (cb_h - UI.font_small) / 2, UI.font_small, C.text)
                if attack_hover and MOUSE.just_pressed then
                    troll.attack_trolls_open = not (troll.attack_trolls_open or false)
                end
                ay = ay + cb_h + btn_gap

                if troll.attack_trolls_open then
                    -- Kill Player (button - instant action)
                    if small_button("Kill Player", action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), btn_h) then
                        if selected.ped and N.SET_ENTITY_HEALTH then N.SET_ENTITY_HEALTH(selected.ped, 0, 0); safe_toast("Killed") end
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Launch Into Sky (exact copy from testtrollscript)
                    local new_launch = inline_toggle("Launch Into Sky", troll.launch_sky, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_launch ~= troll.launch_sky then
                        troll.launch_sky = new_launch
                        if new_launch and selected.ped then
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.launch_sky = false
                                    return
                                end
                                local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z

                                local entity = selected.ped
                                local veh_result = invoker.call(0x9A9112A0FE9A4713, selected.ped, false)  -- GET_VEHICLE_PED_IS_IN
                                if veh_result and veh_result.int and veh_result.int ~= 0 then
                                    if request_control(veh_result.int) then
                                        entity = veh_result.int
                                    end
                                end

                                invoker.call(0x06843DA7060A026B, entity, px, py, pz + 2500.0, false, false, false, false)  -- SET_ENTITY_COORDS
                                safe_toast("Target launched to space!")
                                troll.launch_sky = false
                            end)
                        elseif not new_launch then
                            troll.launch_sky = false
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- TP to Ocean (button - instant action)
                    if small_button("TP to Ocean", action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), btn_h) then
                        if player_obj and player_obj.teleport then pcall(function() player_obj:teleport(vec3(4500, 8000, 0)) end); safe_toast("Ocean TP") end
                    end
                    ay = ay + btn_h + math.floor(2 * s)

                    -- Spawn Clones (toggle - loops while active)
                    local new_spawn_clones = inline_toggle("Spawn Clones", troll.spawn_clones, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_spawn_clones ~= troll.spawn_clones then
                        troll.spawn_clones = new_spawn_clones
                        if new_spawn_clones and selected.ped then
                            local sid = {}
                            troll.spawn_clones_sid = sid
                            local selected_id = selected.id
                            util.create_thread(function()
                                while troll.spawn_clones and troll.spawn_clones_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped then
                                        local clone = invoker.call(0xEF29A16337FACADB, target_ped, false, false, true).int
                                        if clone and clone ~= 0 then
                                            networkise_entity(clone)
                                            pcall(function()
                                                invoker.call(0xF166E48407BAC484, clone, target_ped, 0, 16)
                                            end)
                                        end
                                    else
                                        break
                                    end
                                    util.yield(1000)
                                end
                                troll.spawn_clones = false
                            end)
                            safe_toast("Spawn Clones: ON")
                        elseif not new_spawn_clones then
                            troll.spawn_clones_sid = nil
                            safe_toast("Spawn Clones: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)
                end

                -- Vehicle Trolls Dropdown
                local veh_trolls_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
                draw_rect(action_x + side_pad, ay, action_w - side_pad * 2, cb_h, veh_trolls_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
                local v_arrow = (troll.veh_trolls_open or false) and "v" or ">"
                draw_text(v_arrow .. " Vehicle Trolls", action_x + side_pad + math.floor(6 * s), ay + (cb_h - UI.font_small) / 2, UI.font_small, C.text)
                if veh_trolls_hover and MOUSE.just_pressed then
                    troll.veh_trolls_open = not (troll.veh_trolls_open or false)
                end
                ay = ay + cb_h + btn_gap

                if troll.veh_trolls_open then
                    -- Lock Doors (toggle - loops to keep locked)
                    local new_lock = inline_toggle("Lock Doors", troll.lock_doors, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_lock ~= troll.lock_doors then
                        troll.lock_doors = new_lock
                        if new_lock then
                            local sid = {}
                            troll.lock_doors_sid = sid
                            local selected_id = selected.id
                            util.create_thread(function()
                                while troll.lock_doors and troll.lock_doors_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped then
                                        local veh = invoker.call(0x9A9112A0FE9A4713, target_ped, false)
                                        if veh and veh.int and veh.int ~= 0 and request_control(veh.int) then
                                            invoker.call(0xB664292EAECF7FA6, veh.int, 4)  -- Lock doors
                                        end
                                    end
                                    util.yield(500)
                                end
                                troll.lock_doors = false
                            end)
                            safe_toast("Lock Doors: ON")
                        else
                            troll.lock_doors_sid = nil
                            safe_toast("Lock Doors: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- Kill Engine (toggle - loops to keep dead)
                    local new_kill = inline_toggle("Kill Engine", troll.kill_engine, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_kill ~= troll.kill_engine then
                        troll.kill_engine = new_kill
                        if new_kill then
                            local sid = {}
                            troll.kill_engine_sid = sid
                            local selected_id = selected.id
                            util.create_thread(function()
                                while troll.kill_engine and troll.kill_engine_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped then
                                        local veh = invoker.call(0x9A9112A0FE9A4713, target_ped, false)
                                        if veh and veh.int and veh.int ~= 0 and request_control(veh.int) then
                                            invoker.call(0x45F6D8EEF34ABEF1, veh.int, -1.0)  -- SET_VEHICLE_ENGINE_HEALTH
                                            invoker.call(0x2497C4717C8B881A, veh.int, false, true, true)  -- SET_VEHICLE_ENGINE_ON (off)
                                        end
                                    end
                                    util.yield(500)
                                end
                                troll.kill_engine = false
                            end)
                            safe_toast("Kill Engine: ON")
                        else
                            troll.kill_engine_sid = nil
                            safe_toast("Kill Engine: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ INVISIBLE STALKER CAR (toggle - loop) ============
                    local stalker_active = (troll.stalker_car_toggle or false)
                    local new_stalker = inline_toggle("Invisible Stalker Car", stalker_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_stalker ~= stalker_active then
                        troll.stalker_car_toggle = new_stalker
                        if new_stalker and selected.ped then
                            local sid = {}
                            troll.stalker_car_sid = sid
                            local selected_id = selected.id
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.stalker_car_toggle = false
                                    return
                                end
                                local tx, ty, tz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                local heading_result = invoker.call(0xE83A3E3557A56640, selected.ped)
                                local heading = heading_result and heading_result.float or 0.0

                                local car_hash = joaat("zentorno")
                                local driver_hash = joaat("s_m_y_marine_01")
                                request.model(car_hash)
                                request.model(driver_hash)
                                util.yield(200)

                                -- Spawn car 40m behind target
                                local rad = math.rad(heading)
                                local sx = tx - math.sin(rad) * 40.0
                                local sy = ty - math.cos(rad) * 40.0

                                local car = invoker.call(0xAF35D0D2583051B0, car_hash, sx, sy, tz, heading, true, true, false).int
                                if not car or car == 0 then
                                    troll.stalker_car_toggle = false
                                    return
                                end
                                networkise_entity(car)

                                local driver = invoker.call(0xD49F9B0955C367DE, 29, driver_hash, sx, sy, tz, 0.0, true, true).int
                                if driver and driver ~= 0 then
                                    networkise_entity(driver)
                                    invoker.call(0xF75B0D629E1C063D, driver, car, -1)  -- SET_PED_INTO_VEHICLE
                                end

                                -- Make car and driver invisible
                                invoker.call(0xEA1C610A04DB6BBB, car, false, 0)  -- SET_ENTITY_VISIBLE
                                invoker.call(0xEA1C610A04DB6BBB, driver, false, 0)  -- SET_ENTITY_VISIBLE
                                -- Make both invincible
                                invoker.call(0x3882114BA7B7E164, car, true)  -- SET_ENTITY_INVINCIBLE
                                invoker.call(0x3882114BA7B7E164, driver, true)
                                invoker.call(0x2497C4717C8B881A, car, true, true, false)  -- ENGINE ON
                                -- Driver settings
                                invoker.call(0xB195FFA8042FC5C3, driver, 1.0)  -- SET_DRIVER_ABILITY
                                invoker.call(0xA731F608CA104E3C, driver, 1.0)  -- SET_DRIVER_AGGRESSIVENESS
                                invoker.call(0x9F8AA94D6D97DBF4, driver, true)  -- BLOCKING
                                invoker.call(0x971D38760FBC02EF, driver, true)  -- KEEP_TASK

                                troll.stalker_car_entity = car
                                troll.stalker_driver_entity = driver

                                invoker.call(0x4AD96EE8E9A3C880, car_hash)
                                invoker.call(0x4AD96EE8E9A3C880, driver_hash)
                                safe_toast("Invisible Stalker: Active!")

                                -- Loop: keep retasking driver to chase target
                                while troll.stalker_car_toggle and troll.stalker_car_sid == sid do
                                    local target_ped = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id and p.ped then
                                                target_ped = p.ped
                                                break
                                            end
                                        end
                                    end
                                    if target_ped and car and driver then
                                        -- TASK_VEHICLE_MISSION_PED_TARGET: missionType 7 = ram
                                        invoker.call(0x9454528DF15D657A, driver, car, target_ped, 7, 200.0, 786468, 5.0, 5.0, true)
                                    end
                                    util.yield(3000)
                                end

                                -- Cleanup on toggle off
                                pcall(function()
                                    if car and invoker.call(0x7239B21A38F536BA, car).bool then
                                        invoker.call(0xAD738C3085FE7E11, car, true, true)
                                        invoker.call(0xAE3CBE5BF394C9C9, car)
                                    end
                                end)
                                pcall(function()
                                    if driver and invoker.call(0x7239B21A38F536BA, driver).bool then
                                        invoker.call(0xAD738C3085FE7E11, driver, true, true)
                                        invoker.call(0xAE3CBE5BF394C9C9, driver)
                                    end
                                end)
                                troll.stalker_car_entity = nil
                                troll.stalker_driver_entity = nil
                                troll.stalker_car_toggle = false
                            end)
                        else
                            troll.stalker_car_sid = nil
                            safe_toast("Invisible Stalker: OFF")
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ CAR MAGNET (auto-reset) ============
                    local magnet_active = (troll.car_magnet_toggle or false)
                    local new_magnet = inline_toggle("Car Magnet", magnet_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_magnet ~= magnet_active then
                        troll.car_magnet_toggle = new_magnet
                        if new_magnet and selected.ped then
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.car_magnet_toggle = false
                                    return
