                            safe_toast("Whale Rain: OFF")
                        end
                    end
                    ay = ay + cb_h + btn_gap

                    -- ============ RAIN DORITOS (auto-reset, one-shot) ============
                    local doritos_active = (troll.doritos_rain_toggle or false)
                    local new_doritos = inline_toggle("Rain Doritos", doritos_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_doritos ~= doritos_active then
                        troll.doritos_rain_toggle = new_doritos
                        if new_doritos and selected.ped then
                            util.create_job(function()
                                local hash = joaat("xs_prop_nacho_wl")  -- Doritos/nacho chip prop
                                request.model(hash)
