                                        invoker.call(0x4A4722448F18EEF5, obj, true)   -- SET_ENTITY_HAS_GRAVITY
                                        invoker.call(0x1C99BB7B6E96D16F, obj, 0.0, 0.0, -0.5)  -- SET_ENTITY_VELOCITY (slight downward push)
                                    end
