                                while troll.toilet_bomb_toggle and troll.toilet_bomb_sid == sid do
                                    local target_coords = nil
                                    if players and players.list then
                                        for _, p in ipairs(players.list()) do
                                            if p and p.id == selected_id then
                                                target_coords = p.coords
