                                            end
                                        end
                                    end

                                    if target_coords then
                                        local spawn_x = target_coords.x + math.random(-5, 5)
                                        local spawn_y = target_coords.y + math.random(-5, 5)
                                        local spawn_z = target_coords.z + 30.0 + math.random(0, 10)

                                        local toilet = invoker.call(0x509D5878EB39E842, toilet_hash, spawn_x, spawn_y, spawn_z, true, true, false).int
                                        if toilet and toilet ~= 0 then
                                            invoker.call(0x428CA6DBD1094446, toilet, false)  -- FREEZE off
                                            invoker.call(0x1718DE8E3F2823CA, toilet, true)   -- SET_ENTITY_DYNAMIC
                                            invoker.call(0x4A4722448F18EEF5, toilet, true)   -- SET_ENTITY_HAS_GRAVITY
                                            invoker.call(0x8E2530AA8ADA980E, toilet, math.random(0, 360) * 1.0)  -- Random rotation
                                            invoker.call(0x1C99BB7B6E96D16F, toilet, 0.0, 0.0, -2.0)  -- Push down

                                            table.insert(spawned_toilets, toilet)
                                            spawn_count = spawn_count + 1

                                            if spawn_count > 20 then
                                                local oldest = table.remove(spawned_toilets, 1)
