                    end
                    ay = ay + cb_h + btn_gap

            end

                -- =====================================================
                -- ADVANCED TROLLS DROPDOWN
                -- =====================================================
                if player_state.sub_tab == 4 and selected then
                local cb_h = math.floor(26 * s)
                local btn_gap = math.floor(4 * s)
                local troll = get_troll_state(selected.id)
                local player_obj = get_player_object(selected.id)
                local adv_trolls_hover = is_mouse_in(action_x + side_pad, ay, action_w - side_pad * 2, cb_h)
