                                -- Spawn cougar ~45m behind the target (opposite their facing direction)
                                local rad = math.rad(heading)
                                local spawn_x = px + (math.sin(-rad) * -45.0)
                                local spawn_y = py + (math.cos(-rad) * -45.0)

                                local cougar_hash = joaat("a_c_mtlion")
                                request.model(cougar_hash)
                                util.yield(200)

                                -- CREATE_PED (type 28 = animal)
                                local cougar = invoker.call(0xD49F9B0955C367DE, 28, cougar_hash, spawn_x, spawn_y, pz, 0.0, true, true).int
                                if not cougar or cougar == 0 then
                                    safe_toast("Failed to spawn cougar")
