                                -- Combat attributes
                                invoker.call(0xC7622C0D36B2FDA8, cougar, 46, true)  -- always fight
                                invoker.call(0xC7622C0D36B2FDA8, cougar, 5, true)   -- fight armed peds
                                invoker.call(0xC7622C0D36B2FDA8, cougar, 0, true)   -- can use cover
                                -- Face the target
                                local angle = math.deg(math.atan(px - spawn_x, py - spawn_y))
                                invoker.call(0x8E2530AA8ADA980E, cougar, angle)  -- SET_ENTITY_HEADING
                                -- Attack target
                                invoker.call(0xF166E48407BAC484, cougar, selected.ped, 0, 16)  -- TASK_COMBAT_PED

                                invoker.call(0x4AD96EE8E9A3C880, cougar_hash)
                                safe_toast("A cougar is hunting...")
                                troll.cougar_hunt_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + btn_gap

                    -- ============ THE GAUNTLET (auto-reset) ============
                    local gauntlet_active = (troll.gauntlet_toggle or false)
                    local new_gauntlet = inline_toggle("The Gauntlet", gauntlet_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_gauntlet ~= gauntlet_active then
                        troll.gauntlet_toggle = new_gauntlet
                        if new_gauntlet and selected.ped then
                            util.create_job(function()
                                -- Alley coords (user-specified)
                                local alley_x = 970.0
                                local player_y = -1627.0
