                                    for _, p in ipairs(players.list()) do
                                        if p and p.id == selected.id and p.ped then
                                            target_ped = p.ped
                                            break
                                        end
                                    end
                                end
                                if target_ped then
                                    -- REMOVE_ALL_PED_WEAPONS (0x33985BDA3356E6F2)
                                    invoker.call(0x33985BDA3356E6F2, target_ped, true)
                                    util.yield(200)
                                    -- GIVE_WEAPON_TO_PED - knife (melee weapon)
                                    local knife_hash = joaat("weapon_knife")
                                    invoker.call(0xBF0FD6E56C964FCB, target_ped, knife_hash, 1, false, true)
                                    -- SET_CURRENT_PED_WEAPON to force equip
                                    invoker.call(0xADF692B254977C0C, target_ped, knife_hash, true)
                                    safe_toast("Knife equipped - fight for survival!")
                                end

                                -- Spawn barriers: 2 containers per side, going east-west (heading 0 = north-south, 90 = east-west)
                                local barrier_hash = 2140719283  -- prop_container_01d
