                                    if b and b ~= 0 then
                                        invoker.call(0x8E2530AA8ADA980E, b, 90.0)  -- heading 90 = east-west
                                        invoker.call(0x428CA6DBD1094446, b, true)  -- FREEZE
                                    end
                                end
                                -- South wall: 2 containers side by side going east-west
                                for offset = -6, 6, 12 do
                                    local b = invoker.call(0x509D5878EB39E842, barrier_hash, alley_x + offset, barrier_south_y, alley_z, true, true, false).int
                                    if b and b ~= 0 then
                                        invoker.call(0x8E2530AA8ADA980E, b, 90.0)  -- heading 90 = east-west
                                        invoker.call(0x428CA6DBD1094446, b, true)  -- FREEZE
                                    end
                                end

                                -- Spawn 4 hostile armed prisoners near the player
                                local prisoner_hash = joaat("s_m_y_prisoner_01")
                                request.model(prisoner_hash)
