                                    local ox, oy = offsets[i][1], offsets[i][2]
                                    local npc = invoker.call(0xD49F9B0955C367DE, 26, prisoner_hash, alley_x + ox, player_y + oy, alley_z, 0.0, true, true).int
                                    if npc and npc ~= 0 then
