                                        invoker.call(0x9F8AA94D6D97DBF4, npc, true)  -- SET_BLOCKING_OF_NON_TEMPORARY_EVENTS
                                        invoker.call(0x971D38760FBC02EF, npc, true)  -- SET_PED_KEEP_TASK
                                        invoker.call(0xC7622C0D36B2FDA8, npc, 46, true)  -- always fight
                                        invoker.call(0xC7622C0D36B2FDA8, npc, 5, true)   -- fight armed
                                        invoker.call(0xF166E48407BAC484, npc, selected.ped, 0, 16)  -- TASK_COMBAT_PED
                                    end
                                end

                                invoker.call(0x4AD96EE8E9A3C880, barrier_hash)
                                invoker.call(0x4AD96EE8E9A3C880, prisoner_hash)
                                safe_toast("Welcome to The Gauntlet!")
                                troll.gauntlet_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + btn_gap

                    -- ============ PAPARAZZI SWARM (auto-reset) ============
                    local paparazzi_active = (troll.paparazzi_toggle or false)
                    local new_paparazzi = inline_toggle("Paparazzi Swarm", paparazzi_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_paparazzi ~= paparazzi_active then
                        troll.paparazzi_toggle = new_paparazzi
                        if new_paparazzi and selected.ped then
                            util.create_job(function()
                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)  -- GET_ENTITY_COORDS
                                if not coords or not coords.scr_vec3 then
                                    troll.paparazzi_toggle = false
                                    return
                                end
                                local px, py, pz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z

                                -- Male-only ped models (WORLD_HUMAN_PAPARAZZI is male-only scenario)
                                local pap_models = {
                                    "a_m_y_business_01", "a_m_y_hipster_01",
                                    "a_m_m_bevhills_01", "a_m_y_vinewood_01",
                                    "a_m_y_stwhi_02", "a_m_m_socenlat_01",
                                    "a_m_y_beach_01", "a_m_m_tramp_01"
                                }

                                -- Spawn 8 paparazzi in a circle around target (~3.5m radius)
                                for i = 0, 7 do
                                    local angle = (i / 8) * 360.0
                                    local rad = math.rad(angle)
                                    local sx = px + math.cos(rad) * 3.5
                                    local sy = py + math.sin(rad) * 3.5

                                    local model_name = pap_models[(i % #pap_models) + 1]
                                    local model_hash = joaat(model_name)
                                    request.model(model_hash)
                                    util.yield(50)

                                    local pap = invoker.call(0xD49F9B0955C367DE, 26, model_hash, sx, sy, pz, 0.0, true, true).int
                                    if pap and pap ~= 0 then
                                        networkise_entity(pap)

                                        -- Set invincible
                                        invoker.call(0x3882114BA7B7E164, pap, true)  -- SET_ENTITY_INVINCIBLE

                                        -- Paparazzi scenario: auto-spawns camera prop + correct animation (male only)
                                        -- TASK_START_SCENARIO_IN_PLACE(ped, scenarioName, unkDelay, playEnterAnim)
                                        invoker.call(0x142A02425FF02BD9, pap, "WORLD_HUMAN_PAPARAZZI", 0, true)

                                        -- Face the target (AFTER scenario starts so it doesn't get overridden)
                                        local face_angle = math.deg(math.atan(px - sx, py - sy))
                                        invoker.call(0x8E2530AA8ADA980E, pap, face_angle)  -- SET_ENTITY_HEADING
                                        invoker.call(0xBF29516833893561, pap, face_angle)  -- SET_PED_DESIRED_HEADING (forces turn)

                                        invoker.call(0x4AD96EE8E9A3C880, model_hash)
                                    end
                                    util.yield(100)
                                end
                                safe_toast("PAPARAZZI INCOMING! Say cheese!")
                                troll.paparazzi_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ PLANE KAMIKAZE (auto-reset) ============
                    local kamikaze_active = (troll.kamikaze_jets_toggle or false)
                    local new_kamikaze = inline_toggle("Plane Kamikaze", kamikaze_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_kamikaze ~= kamikaze_active then
                        troll.kamikaze_jets_toggle = new_kamikaze
                        if new_kamikaze and selected.ped then
                            util.create_job(function()
                                local hash = joaat("lazer")
                                local pilot_hash = joaat("s_m_y_marine_01")
                                request.model(hash)
                                request.model(pilot_hash)
                                util.yield(200)

                                local coords = invoker.call(0x3FEF770D40960D5A, selected.ped, true)
                                if not coords or not coords.scr_vec3 then
                                    troll.kamikaze_jets_toggle = false
                                    return
                                end
                                local tx, ty, tz = coords.scr_vec3.x, coords.scr_vec3.y, coords.scr_vec3.z
                                local cleanup_list = {}

                                for i = 1, 3 do
                                    local angle = (i * 120) * (math.pi / 180)
                                    local sx = tx + math.cos(angle) * 100.0
                                    local sy = ty + math.sin(angle) * 100.0
                                    local sz = tz + 80.0

                                    local plane = invoker.call(0xAF35D0D2583051B0, hash, sx, sy, sz, 0.0, true, true, false).int
                                    if plane and plane ~= 0 then
                                        networkise_entity(plane)
                                        table.insert(cleanup_list, plane)
                                        invoker.call(0x2497C4717C8B881A, plane, true, true, false)  -- ENGINE ON
                                        invoker.call(0xAB54A438726D25D5, plane, 150.0)  -- SET_VEHICLE_FORWARD_SPEED

                                        local dx = tx - sx
                                        local dy = ty - sy
                                        local dz = tz - sz
                                        invoker.call(0xC5F68BE9613E2D18, plane, 1, dx * 20.0, dy * 20.0, dz * 20.0, 0.0, 0.0, 0.0, 0, false, true, true, false, true)

                                        local pilot = invoker.call(0xD49F9B0955C367DE, 26, pilot_hash, sx, sy, sz, 0.0, true, true).int
                                        if pilot and pilot ~= 0 then
                                            networkise_entity(pilot)
                                            table.insert(cleanup_list, pilot)
                                            invoker.call(0xF75B0D629E1C063D, pilot, plane, -1)  -- SET_PED_INTO_VEHICLE
                                            -- TASK_PLANE_MISSION: fly at target (missionFlag 4)
                                            invoker.call(0x23703CD154E83B88, pilot, plane, 0, 0, tx, ty, tz, 4, 100.0, 0.0, 90.0, 0, 200.0)
                                        end
                                    end
                                    util.yield(500)
                                end

                                safe_toast("KAMIKAZE JETS INBOUND!")
                                -- Cleanup after 10 seconds
                                util.yield(10000)
                                for _, handle in ipairs(cleanup_list) do
                                    pcall(function()
                                        if invoker.call(0x7239B21A38F536BA, handle).bool then
                                            invoker.call(0xAD738C3085FE7E11, handle, true, true)
                                            invoker.call(0xAE3CBE5BF394C9C9, handle)
                                        end
                                    end)
                                end
                                invoker.call(0x4AD96EE8E9A3C880, hash)
                                invoker.call(0x4AD96EE8E9A3C880, pilot_hash)
                                troll.kamikaze_jets_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ OCEANGATE EXPERIENCE (auto-reset) ============
                    local oceangate_active = (troll.oceangate_toggle or false)
                    local new_oceangate = inline_toggle("OceanGate Experience", oceangate_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_oceangate ~= oceangate_active then
                        troll.oceangate_toggle = new_oceangate
                        if new_oceangate and selected.ped then
                            util.create_job(function()
                                -- Get target's vehicle
                                local veh_result = invoker.call(0x9A9112A0FE9A4713, selected.ped, false)
                                local veh = veh_result and veh_result.int or 0
                                if veh ~= 0 and request_control(veh) then
                                    -- TP vehicle deep underwater
                                    invoker.call(0x06843DA7060A026B, veh, 4500.0, -4400.0, -50.0, false, false, false, true)
                                    -- Lock all doors
                                    invoker.call(0xB664292EAECF7FA6, veh, 4)  -- SET_VEHICLE_DOORS_LOCKED
                                    util.yield(2000)
                                    -- Destroy engine and explode
                                    invoker.call(0x45F6D8EEF34ABEF1, veh, -1000.0)  -- SET_VEHICLE_ENGINE_HEALTH
                                    invoker.call(0xBA71116ADF5B514C, veh, true, false)  -- EXPLODE_VEHICLE
                                    safe_toast("Implosion successful. Welcome to the deep.")
                                else
                                    safe_toast("Target must be in a vehicle!")
                                end
                                troll.oceangate_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + math.floor(2 * s)

                    -- ============ ONE PUNCH MAN - JESUS BOXING RING (auto-reset) ============
                    local opm_active = (troll.one_punch_toggle or false)
                    local new_opm = inline_toggle("One Punch Man", opm_active, action_x + side_pad + math.floor(20 * s), ay, action_w - side_pad * 2 - math.floor(20 * s), cb_h)
                    if new_opm ~= opm_active then
                        troll.one_punch_toggle = new_opm
                        if new_opm and selected.ped then
                            util.create_job(function()
                                -- Same alley location as The Gauntlet
                                local alley_x = 970.0
                                local player_y = -1627.0
                                local alley_z = 30.0
                                local barrier_north_y = -1605.0
                                local barrier_south_y = -1653.0

                                -- TP target to center of alley
                                local target_player_obj = get_player_object(selected.id)
                                if target_player_obj and target_player_obj.teleport then
                                    pcall(function()
                                        target_player_obj:teleport(vec3(alley_x, player_y, alley_z))
                                    end)
                                end
                                util.yield(500)

                                -- Remove all weapons from target (fresh ped)
                                local target_ped = nil
                                if players and players.list then
                                    for _, p in ipairs(players.list()) do
                                        if p and p.id == selected.id and p.ped then
                                            target_ped = p.ped
                                            break
                                        end
                                    end
                                end
                                if target_ped then
                                    invoker.call(0x33985BDA3356E6F2, target_ped, true)  -- REMOVE_ALL_PED_WEAPONS
                                    util.yield(200)
                                end

                                -- Spawn barriers: same as Gauntlet - north/south walls (alley has east/west walls)
                                local barrier_hash = 2140719283  -- prop_container_01d
                                request.model(barrier_hash)
                                util.yield(200)

                                -- North wall: 2 containers side by side going east-west
                                for offset = -6, 6, 12 do
                                    local b = invoker.call(0x509D5878EB39E842, barrier_hash, alley_x + offset, barrier_north_y, alley_z, true, true, false).int
                                    if b and b ~= 0 then
                                        invoker.call(0x8E2530AA8ADA980E, b, 90.0)  -- heading 90 = east-west
                                        invoker.call(0x428CA6DBD1094446, b, true)  -- FREEZE
                                    end
                                end
                                -- South wall: 2 containers side by side going east-west
                                for offset = -6, 6, 12 do
                                    local b = invoker.call(0x509D5878EB39E842, barrier_hash, alley_x + offset, barrier_south_y, alley_z, true, true, false).int
                                    if b and b ~= 0 then
                                        invoker.call(0x8E2530AA8ADA980E, b, 90.0)  -- heading 90 = east-west
                                        invoker.call(0x428CA6DBD1094446, b, true)  -- FREEZE
                                    end
                                end

                                -- Spawn Jesus NPC with godmode
                                local jesus_hash = joaat("u_m_m_jesus_01")
                                request.model(jesus_hash)
                                util.yield(200)

                                local jesus = invoker.call(0xD49F9B0955C367DE, 29, jesus_hash, alley_x, player_y + 5.0, alley_z, 180.0, true, true).int
                                if jesus and jesus ~= 0 then
                                    networkise_entity(jesus)
                                    -- Set max health + health
                                    invoker.call(0x166E7CF68597D8B5, jesus, 5000)  -- SET_ENTITY_MAX_HEALTH
                                    invoker.call(0x6B76DC1F3AE6E6A3, jesus, 5000, 0)  -- SET_ENTITY_HEALTH
                                    invoker.call(0x3882114BA7B7E164, jesus, true)  -- SET_ENTITY_INVINCIBLE (godmode)
                                    invoker.call(0xEBD76F2359F190AC, jesus, false)  -- SET_PED_SUFFERS_CRITICAL_HITS
                                    -- Combat attributes
                                    invoker.call(0xC7622C0D36B2FDA8, jesus, 46, true)  -- always fight
                                    invoker.call(0xC7622C0D36B2FDA8, jesus, 5, true)   -- fight armed peds
                                    -- Combat floats for max damage
                                    invoker.call(0xFF41B4B141ED981C, jesus, 6, 100.0)  -- SET_COMBAT_FLOAT
                                    invoker.call(0xFF41B4B141ED981C, jesus, 29, 1000.0)  -- SET_COMBAT_FLOAT

                                    -- Give brass knuckles
                                    invoker.call(0xBF0FD6E56C964FCB, jesus, joaat("weapon_knuckle"), 1, false, true)
                                    -- Task: fight target
                                    invoker.call(0x9F8AA94D6D97DBF4, jesus, true)  -- BLOCKING_OF_NON_TEMPORARY_EVENTS
                                    invoker.call(0x971D38760FBC02EF, jesus, true)  -- SET_PED_KEEP_TASK
                                    if target_ped then
                                        invoker.call(0xF166E48407BAC484, jesus, target_ped, 0, 16)  -- TASK_COMBAT_PED
                                    end
                                end

                                invoker.call(0x4AD96EE8E9A3C880, barrier_hash)
                                invoker.call(0x4AD96EE8E9A3C880, jesus_hash)
                                safe_toast("ONE PUUUUNCH! Jesus has entered the ring!")
                                troll.one_punch_toggle = false
                            end)
                        end
                    end
                    ay = ay + cb_h + btn_gap

                end
                end  -- close: if player_state.sub_tab == 4 (Advanced Trolls guard)
        end

        -- SEPARATE INFO PANEL (outside main window, to the right) - Matching ClickUI PlayerInfo.lua
        if selected then
            local info_x = UI.x + UI.w + UI.info_panel_gap
            local info_y = UI.y
            local info_w = UI.info_panel_w
            local font_size = UI.font_widget
            local pad = math.floor(10 * s)
            local row_h = math.floor((font_size + 10) * s)
            local overlay_rows = 13

            -- Calculate total height needed
            local info_h = (overlay_rows * row_h) + pad * 2

            -- Info panel background
            draw_rect(info_x, info_y, info_w, info_h, C.overlay_bg, math.floor((UI.widget_rounding or 5) * s))

            local iy = info_y + pad

            -- Row helper with proper scaling
            local function row(l1, v1, l2, v2)
                iy = draw_info_row(l1, v1, l2, v2, info_x, iy, info_w, font_size, pad, row_h)
            end

            -- Calculate distance
            local distance = "N/A"
            if selected.coords and players and players.me then
                local me = players.me()
                if me and me.coords then
                    local dx, dy, dz = selected.coords.x - me.coords.x, selected.coords.y - me.coords.y, selected.coords.z - me.coords.z
                    distance = string.format("%.1fm", math.sqrt(dx*dx + dy*dy + dz*dz))
                end
            end

            -- Format money
            local function fmt_money(v)
                if not v or v == 0 then return "$0" end
                if v >= 1000000 then return string.format("$%d,%03d,%03d", math.floor(v/1000000), math.floor((v%1000000)/1000), v%1000)
                elseif v >= 1000 then return string.format("$%d,%03d", math.floor(v/1000), v%1000)
                else return "$" .. v end
            end

            -- Role determination
            local role = "Player"
            if selected.boss then role = "Boss"
            elseif selected.in_ceo then role = "Associate"
            elseif selected.id == player_state.script_host_id then role = "Script Host"
            elseif selected.id == player_state.session_host_id then role = "Session Host" end

            -- Status determination
            local status = "Idle"
            if selected.in_vehicle then status = "In Vehicle"
            elseif not selected.alive then status = "Dead" end

            -- Draw all info rows (matching ClickUI PlayerInfo.lua order)
            row("Name", selected.name or "Unknown", "RID", tostring(selected.rockstar_id or 0))
            row("Rank", tostring(selected.rank or 0), "Role", role)
            row("Health", selected.alive and "Full" or "Dead", "Armor", tostring(selected.armor or 0))
            row("Input", selected.controller and "Controller" or "KB/M", "Distance", distance)
            row("Bank", fmt_money(selected.bank or 0), "Wallet", fmt_money(selected.money or 0))
            row("Wanted", (selected.wanted or 0) .. "/5", "Ammo", "N/A")
            row("Model", "N/A", "Weapon", "N/A")
            row("Status", status, "Interior", selected.in_interior and "YES" or "NO")
            row("Modder", selected.modder and "YES" or "NO", "GodMode", selected.god and "YES" or "NO")
            row("In Vehicle", selected.in_vehicle and "YES" or "NO", "Vehicle", "N/A")

            local pos_str = selected.coords and string.format("%.0f, %.0f, %.0f", selected.coords.x, selected.coords.y, selected.coords.z) or "N/A"
            row("K/D", string.format("%.2f", selected.kd or 0), "Pos", pos_str)
            row("Heading", string.format("%.0f", selected.heading or 0), "Speed", "N/A")
        end
    end

