    -- Settings sliders helper
    local function settings_slider(label, value, min, max, step, x, y, w, s)
        local slider_h = math.floor(42 * s)
        local track_h = math.floor(6 * s)
        local hover = is_mouse_in(x, y, w, slider_h)

        draw_rect(x, y, w, slider_h, hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
        draw_text(string.format("%s: %d", label, math.floor(value)), x + math.floor(8 * s), y + math.floor(6 * s), UI.font_small, C.text)

        local track_y = y + math.floor(26 * s)
        local track_x = x + math.floor(8 * s)
        local track_w = w - math.floor(16 * s)

        draw_rect(track_x, track_y, track_w, track_h, C.checkbox_off, math.floor(3 * s))
        local pct = (value - min) / (max - min)
        draw_rect(track_x, track_y, track_w * pct, track_h, C.accent, math.floor(3 * s))

        if hover and MOUSE.pressed then
            local mouse_pct = math.max(0, math.min(1, (MOUSE.x - track_x) / track_w))
            value = min + (max - min) * mouse_pct
            if step and step > 0 then
                value = math.floor(value / step + 0.5) * step
            end
        end

        return value, slider_h
    end

    -- =========================================================================
    -- DEBUG CONSOLE OVERLAY (Separate Window)
    -- =========================================================================
    local function draw_debug_console()
        if not DEBUG.show_console then return end

        local s = UI.scale
        local console_w = math.floor(600 * s)
        local console_h = math.floor(500 * s)

        -- Position to the right of the main menu
        local console_x = UI.x + UI.w + UI.info_panel_gap
        local console_y = UI.y

        -- Make sure console stays on screen
        if console_x + console_w > screen_w then
            console_x = UI.x - console_w - UI.info_panel_gap
        end

        -- Draw background
        draw_rect(console_x, console_y, console_w, console_h, C.overlay_bg, math.floor((UI.widget_rounding or 5) * s))

        -- Draw header
        local header_h = math.floor(32 * s)
        draw_rect(console_x, console_y, console_w, header_h, C.header, math.floor((UI.widget_rounding or 5) * s))

        -- Title with feature debug indicator
        local title = "Debug Console"
        if DEBUG.feature_debug then
            title = title .. " [FEATURE DEBUG ON]"
        end
        draw_text(title, console_x + math.floor(10 * s), console_y + math.floor(8 * s), UI.font_header, DEBUG.feature_debug and color(255, 100, 100, 255) or C.text)

        -- Close button
        local close_btn_size = math.floor(24 * s)
        local close_x = console_x + console_w - close_btn_size - math.floor(4 * s)
        local close_y = console_y + math.floor(4 * s)
        local close_hover = is_mouse_in(close_x, close_y, close_btn_size, close_btn_size)

        draw_rect(close_x, close_y, close_btn_size, close_btn_size, close_hover and C.widget_hover or C.widget_bg, math.floor((UI.widget_rounding or 5) * s))
        draw_text_centered("X", close_x, close_y, close_btn_size, close_btn_size, UI.font_widget, C.text)

        if close_hover and MOUSE.just_pressed then
            DEBUG.show_console = false
            debug_info("UI", "Debug console closed")
        end

        -- Stats bar
        local stats_y = console_y + header_h
        local stats_h = math.floor(24 * s)
        draw_rect(console_x, stats_y, console_w, stats_h, color(0, 0, 0, 100), 0)

        local fps = debug_get_fps()
        local mem_kb = collectgarbage("count")
        local stats_text = string.format("FPS: %.1f | Memory: %dKB | Logs: %d/%d", fps, math.floor(mem_kb), DEBUG.log_count, DEBUG.max_logs)
        draw_text(stats_text, console_x + math.floor(10 * s), stats_y + math.floor(5 * s), UI.font_small, C.text)

        -- Log area
        local log_pad = math.floor(8 * s)
        local log_y = stats_y + stats_h + log_pad
        local log_area_h = console_h - header_h - stats_h - log_pad * 2
        local log_line_h = math.floor(18 * s)
        local visible_lines = math.floor(log_area_h / log_line_h)

        -- Auto-scroll to bottom if enabled
        local max_scroll_logs = math.max(0, DEBUG.log_count - visible_lines)
        if DEBUG.auto_scroll then
            DEBUG.scroll_offset = max_scroll_logs
        end

        -- Handle mouse wheel in log area
        if is_mouse_in(console_x, log_y, console_w, log_area_h) then
            if MOUSE.scroll_up then
                DEBUG.scroll_offset = math.max(0, DEBUG.scroll_offset - 3)
            elseif MOUSE.scroll_down then
                DEBUG.scroll_offset = math.min(max_scroll_logs, DEBUG.scroll_offset + 3)
            end
        end

        -- Draw visible logs (circular buffer aware)
        local start_idx = math.floor(DEBUG.scroll_offset) + 1
        local end_idx = math.min(DEBUG.log_count, start_idx + visible_lines - 1)

        for i = start_idx, end_idx do
            local log_idx = ((i - 1) % DEBUG.max_logs) + 1
            local log = DEBUG.logs[log_idx]
            if log then
                local line_y = log_y + ((i - start_idx) * log_line_h)

                -- Draw log background (alternating)
                if i % 2 == 0 then
                    draw_rect(console_x + log_pad, line_y, console_w - log_pad * 2, log_line_h, color(0, 0, 0, 30))
                end

                -- Highlight on hover
                local log_hover = is_mouse_in(console_x + log_pad, line_y, console_w - log_pad * 2, log_line_h)
                if log_hover then
                    draw_rect(console_x + log_pad, line_y, console_w - log_pad * 2, log_line_h, color(255, 255, 255, 20))
                end

                -- Draw log text with level color
                draw_text(log.message, console_x + log_pad + math.floor(6 * s), line_y + math.floor(3 * s), UI.font_small - 1, log.color)
            end
        end

        -- Draw scrollbar for logs
        if DEBUG.log_count > visible_lines then
            local sb_w = math.floor(6 * s)
            local sb_x = console_x + console_w - sb_w - math.floor(1 * s)
            local sb_y = log_y
            local sb_h = log_area_h - math.floor(4 * s)
            local thumb_h = math.max(math.floor(40 * s), sb_h * (visible_lines / DEBUG.log_count))
            local thumb_y = sb_y + (sb_h - thumb_h) * (DEBUG.scroll_offset / max_scroll_logs)

            draw_rect(sb_x, sb_y, sb_w, sb_h, C.checkbox_off, math.floor(3 * s))
            draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(3 * s))

            -- Scrollbar drag
            if is_mouse_in(sb_x - math.floor(5 * s), sb_y, sb_w + math.floor(10 * s), sb_h) and MOUSE.pressed then
                local rel_y = MOUSE.y - sb_y - thumb_h / 2
                local scroll_pct = rel_y / (sb_h - thumb_h)
                DEBUG.scroll_offset = math.max(0, math.min(max_scroll_logs, scroll_pct * max_scroll_logs))
            end
        end
    end

    -- =========================================================================
