            if ly + btn_h > clip_top and ly < clip_bottom then
                if small_button("Reset All UI Settings", panel_x + side_pad, ly, usable_w, btn_h) then
                    UI.font_header, UI.font_tab, UI.font_widget, UI.font_small = 16, 14, 12, 10
                    UI.padding, UI.item_spacing, UI.widget_rounding = 10, 6, 5
                    UI.section_gap, UI.button_gap = 14, 4
                    UI.scrollbar_w, UI.scroll_shadow_h, UI.border_thick = 6, 8, 1
                    UI.button_h, UI.slider_h, UI.toggle_size, UI.checkbox_size = 32, 24, 20, 18
                    UI.notif_w, UI.notif_duration, UI.notif_max_stack = 300, 3, 5
                    safe_toast("UI Settings Reset!")
                end
            end

        -- CONFIG TAB
        elseif ui_state.sub_tab == 3 then
            draw_text("Config Management", panel_x + side_pad, ly, UI.font_small, C.accent)
            ly = ly + math.floor(24 * s)

            draw_text("Location: " .. get_config_dir(), panel_x + side_pad, ly, UI.font_small - 2, C.text_dim)
            ly = ly + math.floor(24 * s)

-- FIXED CONFIG SAVE (using same pattern as vehicle save)
if small_button("Save Full Config", panel_x + side_pad, ly, usable_w, btn_h) then
    local config = {
        ui = {
            x = UI.x, y = UI.y, w = UI.w, h = UI.h, scale = UI.scale,
            font_header = UI.font_header, font_tab = UI.font_tab,
            font_widget = UI.font_widget, font_small = UI.font_small,
