            button_h = UI.button_h, slider_h = UI.slider_h, toggle_size = UI.toggle_size, checkbox_size = UI.checkbox_size,
            scrollbar_w = UI.scrollbar_w, scroll_shadow_h = UI.scroll_shadow_h, border_thick = UI.border_thick,
            notif_w = UI.notif_w, notif_duration = UI.notif_duration, notif_max_stack = UI.notif_max_stack,
            accent_r = UI.accent_r, accent_g = UI.accent_g, accent_b = UI.accent_b,
