                god_mode = demo.god_mode, super_jump = demo.super_jump, fast_run = demo.fast_run,
                run_speed = demo.run_speed, never_wanted = demo.never_wanted,
                invisibility = demo.invisibility, off_the_radar = demo.off_the_radar,
                no_ragdoll = demo.no_ragdoll, noclip = demo.noclip, auto_waypoint_tp = demo.auto_waypoint_tp
            },
            vehicle = {
                god_mode = vehicle_state.god_mode, invisible = vehicle_state.invisible,
                rainbow_paint = vehicle_state.rainbow_paint, horn_boost = vehicle_state.horn_boost,
                bulletproof_tires = vehicle_state.bulletproof_tires, livery_cycler = vehicle_state.livery_cycler,
                paint_cycler = vehicle_state.paint_cycler, neon_cycler = vehicle_state.neon_cycler,
                disco_neons = vehicle_state.disco_neons, paint_finish = vehicle_state.paint_finish
            },
