                damage_multiplier = weapon_features.damage_multiplier
            },
            esp = {
                enabled = esp_state.enabled, draw_boxes = esp_state.draw_boxes,
                draw_snaplines = esp_state.draw_snaplines, draw_names = esp_state.draw_names,
                draw_health = esp_state.draw_health, draw_skeleton = esp_state.draw_skeleton,
                max_distance = esp_state.max_distance
            }
        },
        timestamp = os.date("%Y-%m-%d %H:%M:%S")
    }

    -- Manual JSON serialization (same pattern as vehicle save)
    local function val_to_json(v)
        if type(v) == "boolean" then
            return v and "true" or "false"
        elseif type(v) == "number" then
            return tostring(v)
        elseif type(v) == "string" then
            return '"' .. v:gsub('"', '\\"') .. '"'
        else
            return '""'
        end
    end

    local json_str = '{\n  "ui": {\n'
    local ui_first = true
    for k, v in pairs(config.ui) do
        if not ui_first then json_str = json_str .. ',\n' end
        ui_first = false
        json_str = json_str .. '    "' .. k .. '": ' .. val_to_json(v)
    end
    json_str = json_str .. '\n  },\n  "features": {\n'

    -- Self features
    json_str = json_str .. '    "self": {\n'
    local self_first = true
    for k, v in pairs(config.features.self) do
        if not self_first then json_str = json_str .. ',\n' end
        self_first = false
        json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v)
    end
    json_str = json_str .. '\n    },\n'

    -- Vehicle features
    json_str = json_str .. '    "vehicle": {\n'
    local veh_first = true
    for k, v in pairs(config.features.vehicle) do
        if not veh_first then json_str = json_str .. ',\n' end
        veh_first = false
        json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v)
    end
    json_str = json_str .. '\n    },\n'

    -- Weapon features
    json_str = json_str .. '    "weapon": {\n'
    local wpn_first = true
    for k, v in pairs(config.features.weapon) do
        if not wpn_first then json_str = json_str .. ',\n' end
        wpn_first = false
        json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v)
    end
    json_str = json_str .. '\n    },\n'

    -- ESP features
    json_str = json_str .. '    "esp": {\n'
    local esp_first = true
    for k, v in pairs(config.features.esp) do
        if not esp_first then json_str = json_str .. ',\n' end
        esp_first = false
        json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v)
    end
    json_str = json_str .. '\n    }\n'

    json_str = json_str .. '  },\n  "timestamp": "' .. config.timestamp .. '"\n}'

    -- Save using Lexis file.open API (same as vehicle save)
    local save_path = get_config_dir() .. "\\carpie_config.json"

    if file and file.open then
        local ok, err = pcall(function()
            local f = file.open(save_path, {create_if_not_exists=true, append=false})
            if f and f.valid then
                f.text = json_str
                if f.close then
                    pcall(f.close, f)
                elseif f.Close then
                    pcall(f.Close, f)
                end
                safe_toast("Full Config Saved!")
            else
                safe_toast("Failed to save!")
            end
        end)
        if not ok then
            safe_toast("Failed to save: " .. tostring(err))
        end
    else
        safe_toast("File API not available!")
    end
end
ly = ly + btn_h + math.floor(8 * s)

-- FIXED CONFIG LOAD (using same pattern as vehicle load)
if small_button("Load Full Config", panel_x + side_pad, ly, usable_w, btn_h) then
    local save_path = get_config_dir() .. "\\carpie_config.json"

    if file and file.open then
        local ok_open, f = pcall(file.open, save_path, {create_if_not_exists=false, append=false})
        if ok_open and f and f.valid then
            local json_str = f.text

            if f.close then
                pcall(f.close, f)
            elseif f.Close then
                pcall(f.Close, f)
            end

            if json_str and json_str ~= "" then
                -- Manual JSON parsing (same pattern as vehicle load)
                local function extract_val(key, section)
                    section = section or ""
                    local full_key = section ~= "" and (section .. '": {[^}]*"' .. key) or key
                    -- Try number
                    local num = json_str:match('"' .. full_key .. '"%s*:%s*(%-?%d+%.?%d*)')
                    if num then return tonumber(num) end
                    -- Try boolean
                    local bool = json_str:match('"' .. full_key .. '"%s*:%s*(%a+)')
                    if bool == "true" then return true elseif bool == "false" then return false end
                    -- Try string
                    local str = json_str:match('"' .. full_key .. '"%s*:%s*"([^"]*)"')
                    if str then return str end
                    return nil
                end

                -- Load UI settings
                UI.x = extract_val("x", "ui") or UI.x
                UI.y = extract_val("y", "ui") or UI.y
                UI.w = extract_val("w", "ui") or UI.w
                UI.h = extract_val("h", "ui") or UI.h
                UI.scale = extract_val("scale", "ui") or UI.scale
                UI.font_header = extract_val("font_header", "ui") or UI.font_header
                UI.font_tab = extract_val("font_tab", "ui") or UI.font_tab
                UI.font_widget = extract_val("font_widget", "ui") or UI.font_widget
                UI.font_small = extract_val("font_small", "ui") or UI.font_small
                UI.padding = extract_val("padding", "ui") or UI.padding
                UI.item_spacing = extract_val("item_spacing", "ui") or UI.item_spacing
                UI.widget_rounding = extract_val("widget_rounding", "ui") or UI.widget_rounding
                UI.section_gap = extract_val("section_gap", "ui") or UI.section_gap
                UI.button_gap = extract_val("button_gap", "ui") or UI.button_gap
                UI.button_h = extract_val("button_h", "ui") or UI.button_h
                UI.slider_h = extract_val("slider_h", "ui") or UI.slider_h
                UI.toggle_size = extract_val("toggle_size", "ui") or UI.toggle_size
                UI.checkbox_size = extract_val("checkbox_size", "ui") or UI.checkbox_size
                UI.scrollbar_w = extract_val("scrollbar_w", "ui") or UI.scrollbar_w
                UI.scroll_shadow_h = extract_val("scroll_shadow_h", "ui") or UI.scroll_shadow_h
                UI.border_thick = extract_val("border_thick", "ui") or UI.border_thick
                UI.notif_w = extract_val("notif_w", "ui") or UI.notif_w
                UI.notif_duration = extract_val("notif_duration", "ui") or UI.notif_duration
                UI.notif_max_stack = extract_val("notif_max_stack", "ui") or UI.notif_max_stack

                -- Load colors
                local ar = extract_val("accent_r", "ui")
                if ar then
                    UI.accent_r, UI.accent_g, UI.accent_b = ar, extract_val("accent_g", "ui"), extract_val("accent_b", "ui")
                    C.accent = color(UI.accent_r, UI.accent_g, UI.accent_b, 255)
                end
                local br = extract_val("bg_r", "ui")
                if br then
                    UI.bg_r, UI.bg_g, UI.bg_b, UI.bg_a = br, extract_val("bg_g", "ui"), extract_val("bg_b", "ui"), extract_val("bg_a", "ui")
                    C.bg = color(UI.bg_r, UI.bg_g, UI.bg_b, UI.bg_a)
                end
                local sr = extract_val("sidebar_r", "ui")
                if sr then
                    UI.sidebar_r, UI.sidebar_g, UI.sidebar_b = sr, extract_val("sidebar_g", "ui"), extract_val("sidebar_b", "ui")
                    C.sidebar = color(UI.sidebar_r, UI.sidebar_g, UI.sidebar_b, 255)
                end
                local hr = extract_val("header_r", "ui")
                if hr then
                    UI.header_r, UI.header_g, UI.header_b = hr, extract_val("header_g", "ui"), extract_val("header_b", "ui")
                    C.header = color(UI.header_r, UI.header_g, UI.header_b, 255)
                end
                local tr = extract_val("text_r", "ui")
                if tr then
                    UI.text_r, UI.text_g, UI.text_b = tr, extract_val("text_g", "ui"), extract_val("text_b", "ui")
                    C.text = color(UI.text_r, UI.text_g, UI.text_b, 255)
                end
                local tdr = extract_val("text_dim_r", "ui")
                if tdr then
                    UI.text_dim_r, UI.text_dim_g, UI.text_dim_b = tdr, extract_val("text_dim_g", "ui"), extract_val("text_dim_b", "ui")
                    C.text_dim = color(UI.text_dim_r, UI.text_dim_g, UI.text_dim_b, 255)
                end
                local wbr = extract_val("widget_bg_r", "ui")
                if wbr then
                    UI.widget_bg_r, UI.widget_bg_g, UI.widget_bg_b = wbr, extract_val("widget_bg_g", "ui"), extract_val("widget_bg_b", "ui")
                    C.widget_bg = color(UI.widget_bg_r, UI.widget_bg_g, UI.widget_bg_b, 255)
                end
                local whr = extract_val("widget_hover_r", "ui")
                if whr then
                    UI.widget_hover_r, UI.widget_hover_g, UI.widget_hover_b = whr, extract_val("widget_hover_g", "ui"), extract_val("widget_hover_b", "ui")
                    C.widget_hover = color(UI.widget_hover_r, UI.widget_hover_g, UI.widget_hover_b, 255)
                end

                -- Load self features
                local gm = extract_val("god_mode", "self")
                if gm ~= nil then demo.god_mode = gm end
                local sj = extract_val("super_jump", "self")
                if sj ~= nil then demo.super_jump = sj end
                local fr = extract_val("fast_run", "self")
                if fr ~= nil then demo.fast_run = fr end
                local rs = extract_val("run_speed", "self")
                if rs ~= nil then demo.run_speed = rs end
                local nw = extract_val("never_wanted", "self")
                if nw ~= nil then demo.never_wanted = nw end
                local inv = extract_val("invisibility", "self")
                if inv ~= nil then demo.invisibility = inv end
                local otr = extract_val("off_the_radar", "self")
                if otr ~= nil then demo.off_the_radar = otr end
                local nr = extract_val("no_ragdoll", "self")
                if nr ~= nil then demo.no_ragdoll = nr end
                local nc = extract_val("noclip", "self")
                if nc ~= nil then demo.noclip = nc end
                local awt = extract_val("auto_waypoint_tp", "self")
                if awt ~= nil then demo.auto_waypoint_tp = awt end

                -- Load vehicle features
                local vgm = extract_val("god_mode", "vehicle")
                if vgm ~= nil then vehicle_state.god_mode = vgm end
                local vinv = extract_val("invisible", "vehicle")
                if vinv ~= nil then vehicle_state.invisible = vinv end
                local vrp = extract_val("rainbow_paint", "vehicle")
                if vrp ~= nil then vehicle_state.rainbow_paint = vrp end
                local vhb = extract_val("horn_boost", "vehicle")
                if vhb ~= nil then vehicle_state.horn_boost = vhb end
                local vbt = extract_val("bulletproof_tires", "vehicle")
                if vbt ~= nil then vehicle_state.bulletproof_tires = vbt end
                local vlc = extract_val("livery_cycler", "vehicle")
                if vlc ~= nil then vehicle_state.livery_cycler = vlc end
                local vpc = extract_val("paint_cycler", "vehicle")
                if vpc ~= nil then vehicle_state.paint_cycler = vpc end
                local vnc = extract_val("neon_cycler", "vehicle")
                if vnc ~= nil then vehicle_state.neon_cycler = vnc end
                local vdn = extract_val("disco_neons", "vehicle")
                if vdn ~= nil then vehicle_state.disco_neons = vdn end
                local vpf = extract_val("paint_finish", "vehicle")
                if vpf ~= nil then vehicle_state.paint_finish = vpf end

                -- Load weapon features
                local wia = extract_val("infinite_ammo", "weapon")
                if wia ~= nil then weapon_features.infinite_ammo = wia end
                local wnr = extract_val("no_reload", "weapon")
                if wnr ~= nil then weapon_features.no_reload = wnr end
                local wdm = extract_val("damage_multiplier", "weapon")
                if wdm ~= nil then weapon_features.damage_multiplier = wdm end

                -- Load ESP features
                local een = extract_val("enabled", "esp")
                if een ~= nil then esp_state.enabled = een end
                local edb = extract_val("draw_boxes", "esp")
                if edb ~= nil then esp_state.draw_boxes = edb end
                local eds = extract_val("draw_snaplines", "esp")
                if eds ~= nil then esp_state.draw_snaplines = eds end
                local edn = extract_val("draw_names", "esp")
                if edn ~= nil then esp_state.draw_names = edn end
                local edh = extract_val("draw_health", "esp")
                if edh ~= nil then esp_state.draw_health = edh end
                local esk = extract_val("draw_skeleton", "esp")
                if esk ~= nil then esp_state.draw_skeleton = esk end
                local emd = extract_val("max_distance", "esp")
                if emd ~= nil then esp_state.max_distance = emd end

                safe_toast("Full Config Loaded!")
            else
                safe_toast("Config file is empty!")
            end
        else
            safe_toast("Config file not found!")
        end
    else
        safe_toast("File API not available!")
    end
end
        end


        -- Scroll shadows
        if scroll_needed then
            local shadow_h = math.floor((UI.scroll_shadow_h or 8) * s)
            if ui_state.scroll_offset > 0 then
                -- Top shadow
                for i = 0, shadow_h do
                    local alpha = math.floor(60 * (1 - i / shadow_h))
                    draw_rect(panel_x, panel_y + i, panel_w, 1, color(0, 0, 0, alpha), 0)
                end
            end
            if ui_state.scroll_offset < max_scroll then
                -- Bottom shadow
                for i = 0, shadow_h do
                    local alpha = math.floor(60 * (1 - i / shadow_h))
                    draw_rect(panel_x, panel_y + panel_h - shadow_h + i, panel_w, 1, color(0, 0, 0, alpha), 0)
                end
            end

            -- Scrollbar
            local scrollbar_width = math.floor((UI.scrollbar_w or 6) * s)
            local scrollbar_x = panel_x + panel_w - scrollbar_width - math.floor(1 * s)
            local scrollbar_track_h = panel_h - math.floor(4 * s)
            local scrollbar_thumb_h = math.max(math.floor(20 * s), math.floor((panel_h / content_h) * scrollbar_track_h))
            local scrollbar_thumb_y = panel_y + math.floor(2 * s) + math.floor((ui_state.scroll_offset / max_scroll) * (scrollbar_track_h - scrollbar_thumb_h))

            draw_rect(scrollbar_x, scrollbar_thumb_y, scrollbar_width, scrollbar_thumb_h, C.accent, math.floor(3 * s))
        end
    end

    local function draw_settings_tab()
        local s = UI.scale
        local base_x = content_x
        local base_y = widget_y
        local total_w = content_w
        local total_h = UI.h - UI.header_h - math.floor(20 * s)

        -- Sub-tab bar
        local new_sub_tab, tab_h = sub_tab_bar(SETTINGS_SUB_TABS, settings_state.sub_tab, base_x + math.floor(5 * s), base_y, total_w - math.floor(10 * s))
        settings_state.sub_tab = new_sub_tab
        base_y = base_y + tab_h

        -- Content area (standard layout for all tabs)
        local panel_x = base_x + math.floor(5 * s)
        local panel_y = base_y
        local panel_w = total_w - math.floor(10 * s)
        local panel_h = total_h - tab_h

        draw_rect(panel_x, panel_y, panel_w, panel_h, C.sidebar, math.floor((UI.widget_rounding or 5) * s))

        local side_pad = math.floor((UI.padding or 10) * s)
        local item_gap = math.floor((UI.item_spacing or 6) * s)
        local section_gap = math.floor((UI.section_gap or 14) * s)
        local usable_w = panel_w - side_pad * 2

        -- Build items list based on sub-tab
        local items = {}

        local function add_section(title)
            table.insert(items, {type = "section", text = title})
        end

        local function add_slider_item(label, key, min, max, step)
            table.insert(items, {type = "slider", text = label, key = key, min = min, max = max, step = step or 1})
        end

        local function add_checkbox_item(label, key)
            table.insert(items, {type = "checkbox", text = label, key = key})
        end

        local function add_button_item(label, action)
            table.insert(items, {type = "button", text = label, action = action})
        end

        -- ==================== GENERAL ====================
        if settings_state.sub_tab == 1 then
            add_section("Menu Position")
            add_slider_item("Menu X Position", "x", 0, screen_w - UI.w, 10)
            add_slider_item("Menu Y Position", "y", 0, screen_h - UI.h, 10)

            add_section("Menu Appearance")
            add_slider_item("Menu Transparency", "menu_transparency", 0, 100, 1)

            add_section("Actions")
            add_button_item("Center Menu", function()
                UI.x = math.floor((screen_w - UI.w) / 2)
                UI.y = math.floor((screen_h - UI.h) / 2)
                safe_toast("Menu Centered!")
            end)
            add_button_item("Reset Position", function()
                UI.x = 170
                UI.y = 100
                safe_toast("Position Reset!")
            end)

            add_section("Config Save/Load")
            add_button_item("Save Full Config", function()
                local config = {
                    ui = {
                        x = UI.x, y = UI.y, w = UI.w, h = UI.h,
                        font_header = UI.font_header, font_tab = UI.font_tab,
                        font_widget = UI.font_widget, font_small = UI.font_small,
                        padding = UI.padding, item_spacing = UI.item_spacing,
                        widget_rounding = UI.widget_rounding,
                        accent_r = UI.accent_r, accent_g = UI.accent_g, accent_b = UI.accent_b,
                        bg_r = UI.bg_r, bg_g = UI.bg_g, bg_b = UI.bg_b, bg_a = UI.bg_a
                    },
                    features = {
                        self = {
                            god_mode = demo.god_mode, invisibility = demo.invisibility,
                            off_the_radar = demo.off_the_radar, super_jump = demo.super_jump,
                            fast_run = demo.fast_run, no_ragdoll = demo.no_ragdoll,
                            noclip = demo.noclip
                        },
                        vehicle = {
                            god_mode = vehicle_state.god_mode, invisible = vehicle_state.invisible,
                            super_brake = vehicle_state.super_brake, drift_mode = vehicle_state.drift_mode,
                            horn_boost = vehicle_state.horn_boost, bulletproof_tires = vehicle_state.bulletproof_tires
                        }
                    },
                    timestamp = os.date("%Y-%m-%d %H:%M:%S")
                }

                -- Manual JSON serialization
                local function val_to_json(v)
                    if type(v) == "boolean" then
                        return v and "true" or "false"
                    elseif type(v) == "number" then
                        return tostring(v)
                    else
                        return '"' .. tostring(v):gsub('"', '\\"') .. '"'
                    end
                end

                local json_str = '{\n  "ui": {\n'
                for k, v in pairs(config.ui) do
                    json_str = json_str .. '    "' .. k .. '": ' .. val_to_json(v) .. ',\n'
                end
                json_str = json_str:gsub(',\n$', '\n') .. '  },\n  "features": {\n    "self": {\n'
                for k, v in pairs(config.features.self) do
                    json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v) .. ',\n'
                end
                json_str = json_str:gsub(',\n$', '\n') .. '    },\n    "vehicle": {\n'
                for k, v in pairs(config.features.vehicle) do
                    json_str = json_str .. '      "' .. k .. '": ' .. val_to_json(v) .. ',\n'
                end
                json_str = json_str:gsub(',\n$', '\n') .. '    }\n  },\n  "timestamp": "' .. config.timestamp .. '"\n}'

                -- Save using Lexis file.open API
                local save_path = get_config_dir() .. "\\carpie_config.json"
                if file and file.open then
                    pcall(function()
                        local f = file.open(save_path, {create_if_not_exists=true, append=false})
                        if f and f.valid then
                            f.text = json_str
                            if f.close then pcall(f.close, f) elseif f.Close then pcall(f.Close, f) end
                            safe_toast("Config Saved!")
                        else
                            safe_toast("Failed to save!")
                        end
                    end)
                else
                    safe_toast("File API not available!")
                end
            end)
            add_button_item("Load Full Config", function()
                local save_path = get_config_dir() .. "\\carpie_config.json"
                if file and file.open then
                    local ok_open, f = pcall(file.open, save_path, {create_if_not_exists=false, append=false})
                    if ok_open and f and f.valid then
                        local json_str = f.text
                        if f.close then pcall(f.close, f) elseif f.Close then pcall(f.Close, f) end

                        if json_str and json_str ~= "" then
                            -- Manual JSON parsing
                            local function extract_val(key, section)
                                section = section or ""
                                local full_key = section ~= "" and (section .. '": {[^}]*"' .. key) or key
                                local num = json_str:match('"' .. full_key .. '"%s*:%s*(%-?%d+%.?%d*)')
                                if num then return tonumber(num) end
                                local bool = json_str:match('"' .. full_key .. '"%s*:%s*(%a+)')
                                if bool == "true" then return true elseif bool == "false" then return false end
                                local str = json_str:match('"' .. full_key .. '"%s*:%s*"([^"]*)"')
                                if str then return str end
                                return nil
                            end

                            UI.x = extract_val("x", "ui") or UI.x
                            UI.y = extract_val("y", "ui") or UI.y
                            UI.w = extract_val("w", "ui") or UI.w
                            UI.h = extract_val("h", "ui") or UI.h
                            UI.font_header = extract_val("font_header", "ui") or UI.font_header
                            UI.font_tab = extract_val("font_tab", "ui") or UI.font_tab

                            local ar = extract_val("accent_r", "ui")
                            if ar then
                                UI.accent_r, UI.accent_g, UI.accent_b = ar, extract_val("accent_g", "ui"), extract_val("accent_b", "ui")
                                C.accent = color(UI.accent_r, UI.accent_g, UI.accent_b, 255)
                            end

                            local gm = extract_val("god_mode", "self")
                            if gm ~= nil then demo.god_mode = gm end
                            local inv = extract_val("invisibility", "self")
                            if inv ~= nil then demo.invisibility = inv end
                            local otr = extract_val("off_the_radar", "self")
                            if otr ~= nil then demo.off_the_radar = otr end
                            local sj = extract_val("super_jump", "self")
                            if sj ~= nil then demo.super_jump = sj end
                            local fr = extract_val("fast_run", "self")
                            if fr ~= nil then demo.fast_run = fr end
                            local nr = extract_val("no_ragdoll", "self")
                            if nr ~= nil then demo.no_ragdoll = nr end
                            local nc = extract_val("noclip", "self")
                            if nc ~= nil then demo.noclip = nc end

                            local vgm = extract_val("god_mode", "vehicle")
                            if vgm ~= nil then vehicle_state.god_mode = vgm end
                            local vinv = extract_val("invisible", "vehicle")
                            if vinv ~= nil then vehicle_state.invisible = vinv end
                            local vsb = extract_val("super_brake", "vehicle")
                            if vsb ~= nil then vehicle_state.super_brake = vsb end
                            local vdm = extract_val("drift_mode", "vehicle")
                            if vdm ~= nil then vehicle_state.drift_mode = vdm end
                            local vhb = extract_val("horn_boost", "vehicle")
                            if vhb ~= nil then vehicle_state.horn_boost = vhb end
                            local vbt = extract_val("bulletproof_tires", "vehicle")
                            if vbt ~= nil then vehicle_state.bulletproof_tires = vbt end

                            safe_toast("Config Loaded!")
                        else
                            safe_toast("Config file is empty!")
                        end
                    else
                        safe_toast("Config file not found!")
                    end
                else
