            -- Sync UI state with debug config
            if UI.debug_enabled ~= nil then DEBUG.enabled = UI.debug_enabled end
            if UI.debug_timestamps ~= nil then DEBUG.show_timestamp = UI.debug_timestamps end
            if UI.debug_memory ~= nil then DEBUG.show_memory = UI.debug_memory end
            if UI.debug_performance ~= nil then DEBUG.show_performance = UI.debug_performance end
            if UI.debug_auto_scroll ~= nil then DEBUG.auto_scroll = UI.debug_auto_scroll end
            if UI.debug_feature_debug ~= nil then DEBUG.feature_debug = UI.debug_feature_debug end
            if UI.debug_log_level ~= nil then DEBUG.log_level = math.floor(UI.debug_log_level) end

            -- Initialize if not set
            if UI.debug_enabled == nil then UI.debug_enabled = DEBUG.enabled end
            if UI.debug_timestamps == nil then UI.debug_timestamps = DEBUG.show_timestamp end
            if UI.debug_memory == nil then UI.debug_memory = DEBUG.show_memory end
            if UI.debug_performance == nil then UI.debug_performance = DEBUG.show_performance end
            if UI.debug_auto_scroll == nil then UI.debug_auto_scroll = DEBUG.auto_scroll end
            if UI.debug_feature_debug == nil then UI.debug_feature_debug = DEBUG.feature_debug end
            if UI.debug_log_level == nil then UI.debug_log_level = DEBUG.log_level end

        -- ==================== PROTECTIONS ====================
        elseif settings_state.sub_tab == 5 then
            add_section("Network Protections")
            add_checkbox_item("Block Script Events", "block_script_events")
            add_checkbox_item("Block Net Events", "block_net_events")
            add_checkbox_item("Block Crash Attempts", "block_crashes")

            add_section("Specific Protections")
            add_checkbox_item("Block Task Flood (Ped Crash)", "block_task_flood")
            add_checkbox_item("Block Give Control Events", "block_give_control")

            add_section("Information")
            add_button_item("What is Task Flood?", function()
                safe_toast("Task Flood: Modders send malicious ped task syncs")
                debug_info("PROTECT", "Task Flood is the crash method used on you by ChuddyChungus")
                debug_info("PROTECT", "Attackers send 9+ CPedTaskSpecificDataNode syncs to crash your game")
                debug_info("PROTECT", "This protection blocks those malicious task syncs")
            end)
            add_button_item("What is Script Event Crash?", function()
                safe_toast("Script Events: Malicious GIVE_CONTROL_EVENT packets")
                debug_info("PROTECT", "Script event crashes use events like GIVE_CONTROL_EVENT")
                debug_info("PROTECT", "These events can cause memory access violations")
                debug_info("PROTECT", "This protection monitors and blocks suspicious script events")
            end)
            add_button_item("View Last Crash Info", function()
                safe_toast("Last crash: 2026-01-26 20:54:56")
                debug_info("PROTECT", "=== LAST CRASH ANALYSIS ===")
                debug_info("PROTECT", "Attacker 1: ChuddyChungus (NET_OBJ_TYPE_PED with task flood)")
                debug_info("PROTECT", "Attacker 2: -Ripy- (GIVE_CONTROL_EVENT script event)")
                debug_info("PROTECT", "Crash Type: Task Flood + Script Event combination")
                debug_info("PROTECT", "Protection: Now active with 'Block Task Flood' enabled")
            end)
            add_button_item("Test Protections", function()
                local status = ""
                if settings_state.block_task_flood then status = status .. "Task Flood: ON | " end
                if settings_state.block_script_events then status = status .. "Script Events: ON | " end
                if settings_state.block_crashes then status = status .. "Crashes: ON" end
                safe_toast("Protections: " .. status)
                debug_info("PROTECT", "Active protections: " .. status)
            end)
        end

        -- Calculate total content height
        local total_content_h = 0
        for _, item in ipairs(items) do
            if item.type == "section" then
                total_content_h = total_content_h + math.floor(22 * s) + section_gap
            elseif item.type == "slider" then
                total_content_h = total_content_h + math.floor(42 * s) + item_gap
            else
                total_content_h = total_content_h + math.floor(32 * s) + item_gap
            end
        end

        -- Check if scrolling needed
        local content_area_h = panel_h - math.floor(16 * s)
        local needs_scroll = total_content_h > content_area_h
        local max_scroll = math.max(0, total_content_h - content_area_h + math.floor(30 * s))

        -- Reset scroll when changing sub-tab
        settings_state.scroll_offset = math.max(0, math.min(settings_state.scroll_offset, max_scroll))

        -- Handle mouse wheel scroll
        if is_mouse_in(panel_x, panel_y, panel_w, panel_h) and needs_scroll then
            local scroll_amt = math.floor(50 * s)
            if MOUSE.scroll_up then
                settings_state.scroll_offset = math.max(0, settings_state.scroll_offset - scroll_amt)
            elseif MOUSE.scroll_down then
                settings_state.scroll_offset = math.min(max_scroll, settings_state.scroll_offset + scroll_amt)
            end
        end

        -- Draw items with scroll offset
        local ly = panel_y + math.floor(8 * s) - settings_state.scroll_offset
        local clip_top = panel_y + math.floor(4 * s)
        local clip_bottom = panel_y + panel_h - math.floor(8 * s)

        -- Initialize color sliders if needed
        if not UI.accent_r then
            UI.accent_r = 114
            UI.accent_g = 137
            UI.accent_b = 218
        end

        for _, item in ipairs(items) do
            local item_h_current = math.floor(32 * s)
            if item.type == "section" then
                item_h_current = math.floor(22 * s)
            elseif item.type == "slider" then
                item_h_current = math.floor(42 * s)
            end

            -- Only draw if visible
            if ly + item_h_current > clip_top and ly < clip_bottom then
                if item.type == "section" then
                    draw_text(item.text, panel_x + side_pad, ly + math.floor(3 * s), UI.font_small, C.accent)
                    ly = ly + item_h_current + section_gap
                elseif item.type == "slider" then
                    local current_val = UI[item.key] or 0
                    local new_val, h = settings_slider(item.text, current_val, item.min, item.max, item.step, panel_x + side_pad, ly, usable_w, s)
                    UI[item.key] = new_val
                    ly = ly + h + item_gap
                elseif item.type == "checkbox" then
                    local cb_h = math.floor(28 * s)
                    UI[item.key] = inline_toggle(item.text, UI[item.key] or false, panel_x + side_pad, ly, usable_w, cb_h)
                    ly = ly + cb_h + item_gap
                elseif item.type == "button" then
                    if small_button(item.text, panel_x + side_pad, ly, usable_w, math.floor(32 * s)) then
                        if item.action then pcall(item.action) end
                    end
                    ly = ly + math.floor(32 * s) + item_gap
                end
            else
                -- Skip but advance
                if item.type == "section" then
                    ly = ly + item_h_current + section_gap
                elseif item.type == "slider" then
                    ly = ly + math.floor(42 * s) + item_gap
                else
                    ly = ly + math.floor(32 * s) + item_gap
                end
            end
        end

        -- Scroll shadows
        if needs_scroll then
            local shadow_h = math.floor(8 * s)
            if settings_state.scroll_offset > 0 then
                draw_rect(panel_x, panel_y, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
            if settings_state.scroll_offset < max_scroll then
                draw_rect(panel_x, panel_y + panel_h - shadow_h, panel_w, shadow_h, color(0, 0, 0, 40), 0)
            end
        end

        -- Draw scrollbar if needed
        if needs_scroll then
            local sb_w = math.floor(4 * s)
            local sb_x = panel_x + panel_w - sb_w - math.floor(1 * s)
            local sb_h = panel_h - math.floor(10 * s)
            local thumb_h = math.max(math.floor(30 * s), sb_h * (content_area_h / total_content_h))
            local thumb_y = panel_y + math.floor(5 * s) + (sb_h - thumb_h) * (settings_state.scroll_offset / max_scroll)

            draw_rect(sb_x, panel_y + math.floor(5 * s), sb_w, sb_h, C.checkbox_off, math.floor(2 * s))
            draw_rect(sb_x, thumb_y, sb_w, thumb_h, C.accent, math.floor(2 * s))

            -- Scrollbar drag
            if is_mouse_in(sb_x - math.floor(5 * s), panel_y, sb_w + math.floor(10 * s), panel_h) and MOUSE.pressed then
                local rel_y = MOUSE.y - panel_y - math.floor(5 * s) - thumb_h / 2
                local scroll_pct = rel_y / (sb_h - thumb_h)
                settings_state.scroll_offset = math.max(0, math.min(max_scroll, scroll_pct * max_scroll))
            end
        end
    end

    -- =========================================================================
    -- MAIN UI DRAW
    -- =========================================================================

    local function draw_ui()
        if not UI.open then return end

        -- Disable conflicting controls while menu is open
        local player_ped = invoker.call(0x43A66C31C68491C0, invoker.call(0x4F8644AF03D0E0D6).int).int
        local in_veh = invoker.call(0x9A9112A0FE9A4713, player_ped, false)
        if in_veh and (in_veh.int or in_veh.ent or 0) ~= 0 then
            -- Disable radio wheel and music controls in vehicle
            invoker.call(0xFE99B66D079CF6BC, 0, 19, true) -- VehicleRadioWheel
            invoker.call(0xFE99B66D079CF6BC, 0, 85, true) -- VehicleNextRadio (scroll up)
            invoker.call(0xFE99B66D079CF6BC, 0, 84, true) -- VehiclePrevRadio (scroll down)
            invoker.call(0xFE99B66D079CF6BC, 0, 81, true) -- VehicleRadioWheelUD
            invoker.call(0xFE99B66D079CF6BC, 0, 82, true) -- VehicleRadioWheelLR
        end
        -- Disable weapon scroll/select for everyone
        invoker.call(0xFE99B66D079CF6BC, 0, 14, true) -- Mouse wheel down
        invoker.call(0xFE99B66D079CF6BC, 0, 15, true) -- Mouse wheel up
        invoker.call(0xFE99B66D079CF6BC, 0, 99, true) -- Next weapon
        invoker.call(0xFE99B66D079CF6BC, 0, 100, true) -- Prev weapon
        invoker.call(0xFE99B66D079CF6BC, 0, 27, true) -- Phone

        -- Note: update_input() is called in main loop, don't call it here again

        local s = UI.scale
        local x, y, w, h = UI.x, UI.y, UI.w, UI.h

        -- Window dragging
        if is_mouse_in(x, y, w, UI.header_h) then
            if MOUSE.just_pressed and not UI.dragging then
                UI.dragging = true
                UI.drag_ox = MOUSE.x - x
                UI.drag_oy = MOUSE.y - y
            end
        end

        if UI.dragging then
            if MOUSE.pressed then
                UI.x = MOUSE.x - UI.drag_ox
                UI.y = MOUSE.y - UI.drag_oy
                UI.x = math.max(0, math.min(screen_w - w, UI.x))
                UI.y = math.max(0, math.min(screen_h - h, UI.y))
            else
                UI.dragging = false
            end
        end

        -- Update local vars after drag
        x, y = UI.x, UI.y

        -- Window resizing (bottom-right corner drag)
        local resize_handle_size = math.floor(16 * s)
        local resize_x = x + w - resize_handle_size
        local resize_y = y + h - resize_handle_size

        if is_mouse_in(resize_x, resize_y, resize_handle_size, resize_handle_size) then
            if MOUSE.just_pressed and not UI.resizing then
                UI.resizing = true
                UI.resize_ox = MOUSE.x - w
                UI.resize_oy = MOUSE.y - h
            end
        end

        if UI.resizing then
            if MOUSE.pressed then
                local new_w = MOUSE.x - UI.resize_ox
                local new_h = MOUSE.y - UI.resize_oy
                UI.w = math.max(UI.min_w, math.min(UI.max_w, new_w))
                UI.h = math.max(UI.min_h, math.min(UI.max_h, new_h))

                -- Update scale factor dynamically based on new size
                local base_w = 760
                local base_h = 600
                local scale_x = UI.w / base_w
                local scale_y = UI.h / base_h
                UI.scale = math.min(scale_x, scale_y)
                s = UI.scale

                -- Update all scaled UI elements
                UI.header_h = math.floor(24 * s)
                UI.sidebar_w = math.floor(64 * s)
                UI.padding = math.floor(5 * s)
                UI.item_h = math.floor(40 * s)
                UI.font_header = math.floor(17 * s)
                UI.font_tab = math.floor(15 * s)
                UI.font_widget = math.floor(14 * s)
                UI.font_small = math.floor(13 * s)
                UI.font_tiny = math.floor(11 * s)
                UI.widget_rounding = math.floor(6 * s)
                UI.subtab_h = math.floor(30 * s)
            else
                UI.resizing = false
            end
        end

        -- Update local vars after resize
        w, h = UI.w, UI.h

        -- Background with rounded corners
        draw_rect(x, y, w, h, C.bg, math.floor(8 * s))

        -- Draw resize handle (visual indicator in bottom-right corner)
        if not UI.resizing then
            draw_rect(resize_x + math.floor(8 * s), resize_y + math.floor(8 * s), resize_handle_size - math.floor(8 * s), resize_handle_size - math.floor(8 * s), C.accent, 0)
        else
            draw_rect(resize_x + math.floor(6 * s), resize_y + math.floor(6 * s), resize_handle_size - math.floor(6 * s), resize_handle_size - math.floor(6 * s), C.text, 0)
        end

        -- Header
        draw_rect(x, y, w, UI.header_h, C.header, math.floor(8 * s))
        draw_text("CARPIE DIEM", x + math.floor(15 * s), y + math.floor(4 * s), UI.font_header, C.text)

        -- Sidebar
        local sidebar_y = y + UI.header_h
        local sidebar_h = h - UI.header_h
        draw_rect(x, sidebar_y, UI.sidebar_w, sidebar_h, C.sidebar)

        -- Tabs (with proper scaling)
        local tab_h = math.floor(40 * s)
        local btn_margin = math.floor(6 * s)
        local btn_rounding = math.floor(6 * s)

        for i, name in ipairs(TABS) do
            local ty = sidebar_y + btn_margin + (i - 1) * (tab_h + math.floor(4 * s))
            local tx = x + btn_margin
            local tw = UI.sidebar_w - btn_margin * 2
            local is_active = (UI.active_tab == i)
            local is_hover = is_mouse_in(tx, ty, tw, tab_h)

            if is_active then
                draw_rect(tx, ty, tw, tab_h, C.tab_active, btn_rounding)
            elseif is_hover then
                draw_rect(tx, ty, tw, tab_h, C.tab_hover, btn_rounding)
            else
                draw_rect(tx, ty, tw, tab_h, C.tab_inactive, btn_rounding)
            end

            -- Center text in button
            draw_text_centered(name, tx, ty, tw, tab_h, UI.font_tab, is_active and C.text or C.text_dim)

            if is_hover and MOUSE.just_pressed then
                -- Clean up preview clone when switching away from Self tab
                if UI.active_tab == 1 and i ~= 1 then
                    cleanup_preview_clone()
                end
                UI.active_tab = i
            end
        end

        -- Content area
        local cx = x + UI.sidebar_w
        local cy = y + UI.header_h
        local cw = w - UI.sidebar_w
        local ch = h - UI.header_h

        begin_content(cx, cy + math.floor(8 * s), cw)

        if UI.active_tab == 1 then
            draw_self_tab()
        elseif UI.active_tab == 2 then
            draw_visuals_tab()
        elseif UI.active_tab == 3 then
            draw_player_tab()
        elseif UI.active_tab == 4 then
            draw_online_tab()
        elseif UI.active_tab == 5 then
            draw_weapon_tab()
        elseif UI.active_tab == 6 then
            draw_spawn_tab()
        elseif UI.active_tab == 7 then
            draw_vehicle_tab()
        elseif UI.active_tab == 8 then
            draw_world_tab()
        elseif UI.active_tab == 9 then
            draw_model_tab()
        elseif UI.active_tab == 10 then
            draw_heist_tab()
        elseif UI.active_tab == 11 then
            draw_ui_tab()
        elseif UI.active_tab == 12 then
            draw_settings_tab()
        else
            draw_placeholder_tab(TABS[UI.active_tab])
        end

        -- Footer hint
        draw_text("Press T to close | F1 for Debug Console", x + math.floor(15 * s), y + h - math.floor(20 * s), UI.font_small, C.text_dim)
    end

    -- =========================================================================
    -- TOGGLE FUNCTION
    -- =========================================================================

    local function toggle_menu()
        UI.open = not UI.open
        if UI.open then
            safe_toast("CARPIE DIEM Opened")
            debug_info("UI", "Menu opened")
        else
            -- Clean up preview clone when closing menu
            cleanup_preview_clone()
            debug_info("UI", "Menu closed")
        end
    end

    -- =========================================================================
    -- MAIN LOOP
    -- =========================================================================

    local input_key = input.key
    local TOGGLE_KEY = 0xBB  -- = (legacy fallback)
    local TOGGLE_KEY_ALT = 0x77  -- F8 (legacy fallback)
    local DEBUG_CONSOLE_KEY = 0x70  -- F1

    -- Initialize natives
    util.yield(0)
    local natives_ok = init_natives()
    if natives_ok then
        safe_toast("CARPIE DIEM Loaded!\nWaiting for keybind setup...")
        debug_info("SYSTEM", "Natives initialized successfully")
    else
        safe_toast("CARPIE DIEM Loaded (limited)\nNatives not available")
        debug_warn("SYSTEM", "Natives failed to initialize")
    end

    debug_info("SYSTEM", "Starting main loop")

    while true do
        local ok, err = xpcall(function()
            -- Update frame time for FPS tracking
            debug_update_frame_time()

            -- Update input
            update_input()

            -- First-time keybind setup
            if keybind.show_setup then
                -- Draw setup window inline
                local res = game.resolution()
                local w, h = 450, 220
                local x, y = (res.x - w) / 2, (res.y - h) / 2
                draw_rect(x - 2, y - 2, w + 4, h + 4, color(114, 137, 218, 200), 8)
                draw_rect(x, y, w, h, color(25, 20, 35, 240), 6)
                draw_rect(x, y, w, 50, color(114, 137, 218, 255), 6)
                draw_text("SET MENU KEYBIND", x + w/2 - 110, y + 15, 18.0, color(255, 255, 255, 255))
                draw_text("Press any key to set menu open/close key", x + w/2 - 160, y + 80, 15.0, color(255, 255, 255, 255))
                draw_text("(Recommended: F9, F10, Insert, =, etc.)", x + w/2 - 150, y + 110, 12.0, color(200, 200, 200, 255))
                draw_text("[ Waiting for key press... ]", x + w/2 - 105, y + 145, 13.0, color(114, 137, 218, 255))

                -- Wait 30 frames before listening to keys
                keybind.startup_frames = keybind.startup_frames + 1

                if keybind.startup_frames >= 30 then
                    -- Listen for key press (exclude WASD and left shift)
                    for key_code = 0x08, 0xFF do
                        -- Skip movement keys: W=0x57, A=0x41, S=0x53, D=0x44, Left Shift=0x10
                        if key_code ~= 0x57 and key_code ~= 0x41 and key_code ~= 0x53 and key_code ~= 0x44 and key_code ~= 0x10 then
                            if input_key(key_code) and input_key(key_code).just_released then
                                local key_name = keybind.key_names[key_code] or string.format("Key 0x%X", key_code)
                                keybind.menu_key = key_code
                                keybind.configured = true
                                safe_toast("Menu keybind set to: " .. key_name)
                                safe_toast("Press " .. key_name .. " to open/close menu!")
                                keybind.show_setup = false
                                break
                            end
                        end
                    end
                end
            else
                -- Normal menu toggle (use custom keybind or fallback to = and F8)
                if keybind.configured and keybind.menu_key and input_key(keybind.menu_key).just_released then
                    toggle_menu()
                elseif input_key(TOGGLE_KEY).just_released or input_key(TOGGLE_KEY_ALT).just_released then
                    toggle_menu()
                end
            end

            -- Toggle debug console key (F1)
            if input_key(DEBUG_CONSOLE_KEY).just_released then
                DEBUG.show_console = not DEBUG.show_console
                debug_info("UI", DEBUG.show_console and "Debug console shown (F1)" or "Debug console hidden (F1)")
                safe_toast(DEBUG.show_console and "Debug Console: OFF" or "Debug Console: OFF")
            end

            -- No Hesi points now auto-reset on crash (see vehicle thread)

            -- Cursor (show when menu OR debug console is open)
            if input.show_cursor then
                input.show_cursor(UI.open or DEBUG.show_console)
            end

            -- Disable game controls when menu is open (ZODIAC method)
            -- Control list for disabling
            local controls_to_disable = {
                0, 1, 2, 3, 4, 5, 6, 25, 30, 31, 32, 33, 34, 35, 37,
                44, 45, 47, 58, 59, 60, 71, 72, 75, 140, 141, 142, 143,
                257, 258, 261, 262, 263, 264, 265, 266, 267, 268, 27
            }

            if UI.open then
                -- Disable for both control groups 0 and 1
                for group = 0, 1 do
                    for _, control in ipairs(controls_to_disable) do
                        pcall(function() invoker.call(0xFE99B66D079CF6BC, group, control, true) end)
                    end
                end
            end

            -- Draw UI (with performance tracking)
            if UI.open then
                debug_mark_start("draw_ui")
                draw_ui()
                debug_mark_end("draw_ui")
            end

            -- Draw debug console (independent of main menu)
            draw_debug_console()


            -- ============ ONLINE TAB FEATURES (in main loop like ZODIAC) ============

            -- Time Override (using natives table)
            if online_state and online_state.time_override then
                pcall(natives.NETWORK_OVERRIDE_CLOCK_TIME, online_state.time_hour or 12, online_state.time_minute or 0, online_state.time_second or 0)
            end

            -- Freeze Time (using natives table)
            if online_state and online_state.freeze_time then
                local hour = online_state.time_hour or 12
                pcall(natives.SET_CLOCK_TIME, hour, 0, 0)
            end

            -- Traffic Density (EXACTLY like ZODIAC - all 4 vehicle natives)
            if online_state and online_state.apply_traffic_density then
                local density = online_state.traffic_density or 1.0
                pcall(function()
                    invoker.call(0x245A6883D966D537, density) -- SET_VEHICLE_DENSITY_MULTIPLIER_THIS_FRAME
                    invoker.call(0xB3B3359379FE77D3, density) -- SET_RANDOM_VEHICLE_DENSITY_MULTIPLIER_THIS_FRAME
                    invoker.call(0xEAE6DCC7EEE3DB1D, density) -- SET_PARKED_VEHICLE_DENSITY_MULTIPLIER_THIS_FRAME
                    invoker.call(0x90B6DA738A9A25DA, density) -- SET_AMBIENT_VEHICLE_RANGE_MULTIPLIER_THIS_FRAME
                end)
            end

            -- Ped density feature removed per user request


        end, debug.traceback)

        if not ok then
            safe_toast("Error: " .. tostring(err))
            debug_error("SYSTEM", "Main loop error", tostring(err))
        end

        util.yield(0)
    end
end)
